#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The reversed permutation p' = [p_n, p_{n-1}, ..., p_1]
    // will have the same set of adjacent sums as p.
    // Specifically, the sums for p are [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n].
    // The sums for p' are [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1].
    // These are the same sums, just in reverse order.
    // Therefore, their sorted lists of sums (fingerprints) will be identical.
    // We just need to ensure p' is different from p.
    // The problem statement guarantees a solution exists, which implies
    // that p will never be a palindrome for n > 1.
    // For n=1, there's only one permutation [1], and it's a palindrome.
    // But n >= 2, so p and its reverse will always be different.
    // (A permutation p of length n >= 2 cannot be a palindrome because
    // if p_i = p_{n-i+1} for all i, then p_1 = p_n.
    // If p_1 = 1, then p_n = 1. If p_1 = 2, then p_n = 2, etc.
    // This means the permutation would have duplicate elements if n > 1,
    // unless n=1. But a permutation must have distinct elements.
    // For example, if n=2, p=[1,2]. p_rev=[2,1]. They are different.
    // If p=[1,1], it's not a permutation.
    // So, for any permutation p with n >= 2, p is never a palindrome.
    // Thus, reversing p always yields a different permutation p'.)

    for (int i = n - 1; i >= 0; --i) {
        std::cout << p[i] << (i == 0 ? "" : " ");
    }
    std::cout << "\n";
}

