int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        long long d;
        std::cin >> n >> d;
        std::vector<long long> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        long long current_a1 = a[0];

        for (int i = 1; i < n; ++i) {
            long long pile_idx = i; // 0-indexed pile_idx
            long long distance = pile_idx; // distance from pile 0 (pile 1 in problem statement)

            if (d == 0) { // No more days left
                break;
            }

            if (distance <= d) { // If we have enough days to move at least one haybale from this pile
                long long haybales_available = a[i];
                long long haybales_to_move = std::min(haybales_available, d / distance);

                current_a1 += haybales_to_move;
                d -= haybales_to_move * distance;
            }
        }
        std::cout << current_a1 << std::endl;
    }
    return 0;
}

