void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << std::endl;
    } else {
        // For n >= 2, we can construct a number.
        // The strategy is to use '2' as the first digit,
        // '3' as the last digit, and '7' for all intermediate digits.
        // This forms a number like 277...73.
        // Let's check divisibility:
        // 1. Divisibility by 2: The number ends in 3 (odd), so it's not divisible by 2.
        // 2. Divisibility by 3: The sum of digits is 2 + (n-2)*7 + 3 = 5 + 7n - 14 = 7n - 9.
        //    If 7n - 9 is divisible by 3, then 7n is divisible by 3. Since 7 is not divisible by 3,
        //    n must be divisible by 3.
        //    If n is divisible by 3, then 7n - 9 is divisible by 3.
        //    In this case, we need a different construction.
        //    A simpler construction that works for all n >= 2:
        //    Start with '2', then (n-1) '3's.
        //    Example: n=2 -> 23
        //    Example: n=3 -> 233
        //    Example: n=4 -> 2333
        //    Digits are 2 and 3.
        //    Divisibility by 2: Ends in 3 (odd), so not divisible by 2.
        //    Divisibility by 3: Sum of digits is 2 + (n-1)*3 = 2 + 3n - 3 = 3n - 1.
        //    For 3n - 1 to be divisible by 3, -1 must be divisible by 3, which is false.
        //    So, 3n - 1 is never divisible by 3.
        //    This construction 233...3 works for all n >= 2.

        std::cout << '2';
        for (int i = 0; i < n - 1; ++i) {
            std::cout << '3';
        }
        std::cout << std::endl;
    }
}

