#include <iostream>
#include <vector>
#include <numeric>
#include <map>

void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) {
            counts[s_val]++;
        }
    }

    long long current_sum = 0;
    for (auto const& [val, count] : counts) {
        // Add the total value contributed by this power of two
        // up to 2048.
        // For example, if we have three 512s, we can use two of them to make a 1024.
        // The remaining 512 is also available.
        // The total sum of values we can form is limited by 2048.
        // So, we add min(val * count, 2048 - current_sum) to current_sum.
        // This is equivalent to just adding val * count, and then checking if current_sum >= 2048.
        // The problem is not about sum, but about forming 2048.
        // We can think of it as having a "bucket" for each power of two up to 1024.
        // We want to fill the 2048 bucket.

        // A simpler approach:
        // Iterate through powers of two from smallest to largest.
        // For each power of two `p`, we have `counts[p]` instances.
        // We can combine `counts[p] / 2` pairs of `p` to form `counts[p] / 2` instances of `2*p`.
        // Add these to `counts[2*p]`.
        // This simulates the merging process.

        // Let's use a sum variable.
        // We want to see if the sum of all numbers less than or equal to 2048
        // can be combined to form 2048.
        // Since we can always combine two equal numbers, we can effectively
        // sum up all numbers less than or equal to 2048.
        // If this sum is >= 2048, then we can always form 2048.
        // Example: {1024, 512, 512, 4}
        // Sum = 1024 + 512 + 512 + 4 = 2052.
        // We can combine 512+512 -> 1024. Multiset becomes {1024, 1024, 4}.
        // Then 1024+1024 -> 2048. Multiset becomes {2048, 4}. Win.

        // Example: {64, 512, 2}
        // Sum = 64 + 512 + 2 = 578.
        // This is less than 2048. We cannot win.

        // This logic seems correct. If the sum of all numbers <= 2048 is X,
        // and X >= 2048, can we always form 2048?
        // Yes, because any power of two can be formed by combining smaller powers of two.
        // If we have a total sum of X, we can always combine numbers until we have
        // at most one of each power of two, plus some larger numbers.
        // For example, if we have {1,1,1,1,1,1,1,1}, sum is 8.
        // We can make {2,2,2,2} -> {4,4} -> {8}.
        // If we have {1,1,1,1,1,1,1,1, 2}, sum is 10.
        // We can make {8, 2}.
        // The total sum of values is conserved.
        // If the sum of all numbers <= 2048 is at least 2048,
        // we can always combine them to form 2048.
        // The only constraint is that we need *equal* numbers.
        // But since all numbers are powers of two, we can always combine them.
        // E.g., if we have {1, 1, 2, 4}, sum = 8.
        // We can combine 1,1 -> 2. Multiset {2,2,4}.
        // Then 2,2 -> 4. Multiset {4,4}.
        // Then 4,4 -> 8. Multiset {8}.
        // This is essentially a binary representation of the sum.
        // If the sum is S, we can always form S by combining powers of two.
        // If S >= 2048, we can form 2048.

        current_sum += (long long)val * count;
    }

    if (current_sum >= 2048) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

