int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    // The total area of the carrot is (1/2) * base * height = (1/2) * 1 * h = h/2.
    // Each of the n pieces should have an area of (h/2) / n = h / (2n).

    // Consider a cut at height x from the apex.
    // The triangle formed by this cut is similar to the original carrot.
    // If its height is x, its base will be x/h (by similarity: base/height = 1/h).
    // The area of this smaller triangle is (1/2) * (x/h) * x = x^2 / (2h).

    // We want to find x_i such that the area of the triangle from the apex to x_i
    // is i times the area of one piece.
    // Area_at_x_i = i * (h / (2n))
    // x_i^2 / (2h) = i * h / (2n)
    // x_i^2 = i * h^2 / n
    // x_i = sqrt(i * h^2 / n)
    // x_i = h * sqrt(i / n)

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
