    if (max_val_in_derived_p < n) { // This means n was replaced by n-1
        // Find the first occurrence of max_val_in_derived_p and increment it.
        // Since max_val_in_derived_p will be n-1, we are changing one of the n-1s to n.
        for (int i = 0; i < n; ++i) {
            if (p[i] == max_val_in_derived_p) {
                p[i] = n;
