    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1] at pos[1].
        // min_idx and max_idx are both pos[1]. Length is 1.
        // For m > 1, we consider the number m.
        // We need to expand the current segment [min_idx, max_idx]
        // to include m.
        // The new segment must cover all numbers from 1 to m.
        // This means its left boundary must be min(current_min_idx, pos[m])
        // and its right boundary must be max(current_max_idx, pos[m]).

        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number m is beautiful if there exists a subsegment [l, r]
        // such that p[l...r] is a permutation of 1...m.
        // This implies:
        // 1. The length of the subsegment (r - l + 1) must be m.
        // 2. The minimum value in p[l...r] must be 1.
        // 3. The maximum value in p[l...r] must be m.
        //
        // By maintaining current_min_idx and current_max_idx, we are tracking
        // the smallest contiguous segment that contains all numbers from 1 to m.
        // If this segment's length is exactly m, then it must contain
        // exactly the numbers 1 to m (since all numbers are distinct in a permutation).
        // Its minimum value will be 1 and maximum value will be m.
        // So, the condition simplifies to: (current_max_idx - current_min_idx + 1) == m.

        if ((current_max_idx - current_min_idx + 1) == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

