// Function to determine if Box 1 can be the special box
// Box 1: (-inf, -1]
bool can_be_box1(long long A, long long B, long long C, long long D) {
    // Final product must be negative and magnitude >= 1
    // For negative: odd number of negative toys (A+B)
    // For magnitude >= 1:
    //   - If B+C == 0, then all toys have magnitude >= 1. Product will be >= 1.
    //   - If B+C > 0, we need to ensure we can make the magnitude >= 1.
    //     This requires at least one toy with magnitude >= 1 (A or D) to "dominate"
    //     the products of toys with magnitude < 1 (B or C).
    //     If A+D == 0, all toys have magnitude < 1, so product will be < 1.
    //     If A+D > 0, we can potentially make magnitude >= 1.

    // Case 1: All toys have magnitude >= 1 (B=0, C=0)
    if (B == 0 && C == 0) {
        return (A % 2 == 1); // Product is negative if A is odd
    }

    // Case 2: There are toys with magnitude < 1 (B+C > 0)
    // To get magnitude >= 1, we need at least one toy from Box 1 or Box 4.
    if (A + D == 0) {
        return false; // All toys have magnitude < 1, product will be < 1.
    }

    // If A+D > 0, we can potentially make magnitude >= 1.
    // We need an odd number of negative toys (A+B) for the product to be negative.
    // If A+B is odd, it's possible.
    return ((A + B) % 2 == 1);
}

// Function to determine if Box 2 can be the special box
// Box 2: (-1, 0)
bool can_be_box2(long long A, long long B, long long C, long long D) {
    // Final product must be negative and magnitude < 1
    // For negative: odd number of negative toys (A+B)
    // For magnitude < 1:
    //   - If A+D == 0, all toys have magnitude < 1. Product will be < 1.
    //   - If A+D > 0, we need to ensure we can make the magnitude < 1.
    //     This requires at least one toy from Box 2 or Box 3 to "dominate"
    //     the products of toys with magnitude >= 1 (A or D).
    //     If B+C == 0, all toys have magnitude >= 1, so product will be >= 1.
    //     If B+C > 0, we can potentially make magnitude < 1.

    // Case 1: All toys have magnitude < 1 (A=0, D=0)
    if (A == 0 && D == 0) {
        return (B % 2 == 1); // Product is negative if B is odd
    }

    // Case 2: There are toys with magnitude >= 1 (A+D > 0)
    // To get magnitude < 1, we need at least one toy from Box 2 or Box 3.
    if (B + C == 0) {
        return false; // All toys have magnitude >= 1, product will be >= 1.
    }

    // If B+C > 0, we can potentially make magnitude < 1.
    // We need an odd number of negative toys (A+B) for the product to be negative.
    // If A+B is odd, it's possible.
    return ((A + B) % 2 == 1);
}

// Function to determine if Box 3 can be the special box
// Box 3: (0, 1)
bool can_be_box3(long long A, long long B, long long C, long long D) {
    // Final product must be positive and magnitude < 1
    // For positive: even number of negative toys (A+B)
    // For magnitude < 1:
    //   - If A+D == 0, all toys have magnitude < 1. Product will be < 1.
    //   - If A+D > 0, we need to ensure we can make the magnitude < 1.
    //     This requires at least one toy from Box 2 or Box 3.
    //     If B+C == 0, all toys have magnitude >= 1, so product will be >= 1.
    //     If B+C > 0, we can potentially make magnitude < 1.

    // Case 1: All toys have magnitude < 1 (A=0, D=0)
    if (A == 0 && D == 0) {
        return (B % 2 == 0); // Product is positive if B is even
    }

    // Case 2: There are toys with magnitude >= 1 (A+D > 0)
    // To get magnitude < 1, we need at least one toy from Box 2 or Box 3.
    if (B + C == 0) {
        return false; // All toys have magnitude >= 1, product will be >= 1.
    }

    // If B+C > 0, we can potentially make magnitude < 1.
    // We need an even number of negative toys (A+B) for the product to be positive.
    // If A+B is even, it's possible.
    return ((A + B) % 2 == 0);
}

// Function to determine if Box 4 can be the special box
// Box 4: [1, inf)
bool can_be_box4(long long A, long long B, long long C, long long D) {
    // Final product must be positive and magnitude >= 1
    // For positive: even number of negative toys (A+B)
    // For magnitude >= 1:
    //   - If B+C == 0, all toys have magnitude >= 1. Product will be >= 1.
    //   - If B+C > 0, we need to ensure we can make the magnitude >= 1.
    //     This requires at least one toy from Box 1 or Box 4.
    //     If A+D == 0, all toys have magnitude < 1, so product will be < 1.
    //     If A+D > 0, we can potentially make magnitude >= 1.

    // Case 1: All toys have magnitude >= 1 (B=0, C=0)
    if (B == 0 && C == 0) {
        return (A % 2 == 0); // Product is positive if A is even
    }

    // Case 2: There are toys with magnitude < 1 (B+C > 0)
    // To get magnitude >= 1, we need at least one toy from Box 1 or Box 4.
    if (A + D == 0) {
        return false; // All toys have magnitude < 1, product will be < 1.
    }

    // If A+D > 0, we can potentially make magnitude >= 1.
    // We need an even number of negative toys (A+B) for the product to be positive.
    // If A+B is even, it's possible.
    return ((A + B) % 2 == 0);
}

