struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<long long> b(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b[i];
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in descending order
    std::sort(b.rbegin(), b.rend());

    // Create pairs (A_i, B_i) such that A_i is sorted ascending and B_i is sorted descending.
    // This maximizes F(A_i, B_i) because F(n, k) = (n+1)/(k+1) is increasing in n and decreasing in k.
    // So, larger A values should be paired with smaller B values.
    // Since B is sorted descending, b[0] is the largest B value, b[m-1] is the smallest.
    // a_elements[0].value is the smallest A value, a_elements[m-1].value is the largest.
    // To maximize sum F(A_i, B_i), we want to pair largest A with smallest B,
    // second largest A with second smallest B, and so on.
    // This means if A is sorted ascending (a_0, a_1, ..., a_{m-1})
    // and B is sorted ascending (b'_0, b'_1, ..., b'_{m-1}),
    // we should pair (a_i, b'_{m-1-i}).
    // Since we sorted B descending, b_0 is b'_{m-1}, b_1 is b'_{m-2}, etc.
    // So we pair (a_elements[i].value, b[i]).
    // This means a_elements[0].value (smallest A) is paired with b[0] (largest B).
    // a_elements[m-1].value (largest A) is paired with b[m-1] (smallest B).
    // This is the correct pairing for maximizing the sum.

    std::vector<long long> result_a(m);
    for (int i = 0; i < m; ++i) {
        result_a[a_elements[i].original_index] = a_elements[i].value;
    }

    // The problem asks to rearrange A' such that sum F(A'_i, B_i) is maximized.
    // The values of B are fixed at their original indices.
    // Let's denote the original B array as B_orig.
    // We need to find a permutation A' of A such that sum_{i=0}^{m-1} F(A'_i, B_orig_i) is maximized.
    // The function F(n, k) = (n+1)/(k+1).
    // We want to maximize sum_{i=0}^{m-1} (A'_i + 1) / (B_orig_i + 1).
    // This is a rearrangement inequality problem.
    // To maximize sum x_i * y_i, if x is sorted ascending, y should be sorted ascending.
    // Here, we have (A'_i + 1) and 1/(B_orig_i + 1).
    // Let X_i = A'_i + 1 and Y_i = 1/(B_orig_i + 1).
    // We want to maximize sum X_i * Y_i.
    // So, if we sort X_i values (which means sorting A'_i values) in ascending order,
    // we should sort Y_i values (which means sorting 1/(B_orig_i + 1) values) in ascending order.
    // Sorting 1/(B_orig_i + 1) in ascending order is equivalent to sorting (B_orig_i + 1) in descending order,
    // which is equivalent to sorting B_orig_i in descending order.

    // So, we need to pair the smallest A value with the B_orig_i that has the largest B_orig_i + 1 (i.e., largest B_orig_i).
    // The second smallest A value with the B_orig_i that has the second largest B_orig_i.
    // And so on.
    // The largest A value with the B_orig_i that has the smallest B_orig_i.

    // Let's store B values along with their original indices.
    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        b_elements[i].value = b[i]; // b was already read into a vector<long long> b
        b_elements[i].original_index = i;
    }

    // Sort A values in ascending order.
    // a_elements is already sorted ascending.

    // Sort B elements by their values in descending order.
    std::sort(b_elements.begin(), b_elements.end(), [](const Element& x, const Element& y) {
        return x.value > y.value;
    });

    // Now, a_elements[i].value is the i-th smallest A value.
    // b_elements[i].original_index is the original index of the i-th largest B value.
    // We want to assign a_elements[i].value to the position corresponding to b_elements[i].original_index.
    // This means:
    // The smallest A value (a_elements[0].value) goes to the position where the largest B value was (b_elements[0].original_index).
    // The second smallest A value (a_elements[1].value) goes to the position where the second largest B value was (b_elements[1].original_index).
    // ...
    // The largest A value (a_elements[m-1].value) goes to the position where the smallest B value was (b_elements[m-1].original_index).

    std::vector<long long> final_a_prime(m);
    for (int i = 0; i < m; ++i) {
        final_a_prime[b_elements[i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << final_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

