// Function to check if a subarray is a permutation
// This version uses a boolean array for presence and checks max value
bool is_permutation(const std::vector<int>& arr, int start_idx, int end_idx, int expected_len) {
    if (expected_len == 0) return true; // An empty sequence can be considered a permutation of length 0, though problem constraints say non-zero lengths.
                                        // For this problem, l1, l2 >= 1.
    if (end_idx - start_idx + 1 != expected_len) return false;

    std::vector<bool> seen(expected_len + 1, false);
    int max_val = 0;
    for (int i = start_idx; i <= end_idx; ++i) {
        if (arr[i] < 1 || arr[i] > expected_len || seen[arr[i]]) {
            return false;
        }
        seen[arr[i]] = true;
        if (arr[i] > max_val) {
            max_val = arr[i];
        }
    }
    return max_val == expected_len;
}

