            possible_prefix = false;
        } else {
            seen_prefix[a[i]] = true;
            if (a[i] > current_max_prefix) {
                current_max_prefix = a[i];
            }
            if (current_max_prefix == i + 1) { // If max element seen so far is equal to current length
                prefix_is_perm[i + 1] = true;
            }
        }
    }

    // Precompute suffix permutation validity
    // suffix_is_perm[i] is true if a[i...n-1] is a permutation of length n-i
    std::vector<bool> suffix_is_perm(n + 1, false); // suffix_is_perm[i] means a[i...n-1]
    std::vector<bool> seen_suffix(n + 1, false);
    int current_max_suffix = 0;
    bool possible_suffix = true;
    for (int i = n - 1; i >= 0; --i) {
        if (!possible_suffix) {
            break;
        }
        int current_len = n - i;
        if (a[i] < 1 || a[i] > n || seen_suffix[a[i]]) {
            possible_suffix = false;
        } else {
            seen_suffix[a[i]] = true;
            if (a[i] > current_max_suffix) {
                current_max_suffix = a[i];
            }
            if (current_max_suffix == current_len) { // If max element seen so far is equal to current length
                suffix_is_perm[i] = true;
            }
        }
    }

    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (prefix_is_perm[l1] && suffix_is_perm[l1]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

