    for (int i = 0; i <= n; ++i) { // i is the number of items taken from the left
        int j = n - i; // j is the number of items taken from the right

        long long current_energy = 0;

        // Cost for items taken from the left
        current_energy += (prefix_sum[i] - prefix_sum[0]) * l;

        // Cost for items taken from the right
        // The sum of weights for items taken from the right is total_sum - prefix_sum[i]
        // which is (prefix_sum[n] - prefix_sum[i])
        current_energy += (prefix_sum[n] - prefix_sum[i]) * r;

        // Add penalty for consecutive same-side picks
        if (i > j) { // More items from left than right
            current_energy += (i - j - 1) * Ql;
        } else if (j > i) { // More items from right than left
            current_energy += (j - i - 1) * Qr;
        }
        // If i == j, no extra penalty from this rule

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

