// Function to convert a number to its parity pattern string
// The pattern string will have a fixed length (e.g., 18)
// '0' for even digit, '1' for odd digit
// Example: 241 -> "000...000101" (16 zeros, then 1, then 0, then 1)
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern += '0';
            } else {
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the left to a fixed length (e.g., 18)
    // The problem states pattern length no more than 18, and numbers up to 10^18 (19 digits).
    // Let's use a fixed length of 18 for consistency, as padding with 0s from left means even.
    // If a number has more than 18 digits, its most significant digits will be truncated
    // if we only store 18. However, the problem states "If the pattern is shorter than this integer,
    // it's supplemented with 0-s from the left. Similarly, if the integer is shorter than the pattern
    // its decimal notation is supplemented with the 0-s from the left."
    // This implies we should consider the maximum possible length. 10^18 has 19 digits.
    // A pattern of length 18 means we need to consider up to 18 digits.
    // Let's use a fixed length of 18 for the internal representation.
    // If a number is 10^18, its parity string would be "000...0001" (18 zeros, then 1).
    // The problem implies we only care about the digits up to the length of the pattern.
    // If the pattern is length L, we care about the rightmost L digits of the number.
    // If the number has more than L digits, the remaining digits are effectively matched against '0's.
    // So, we can just take the rightmost 18 digits' parities.
    // For example, 12345 and pattern "10".
    // 12345 -> ...000101 (right to left)
    // "10"  -> ...00010
    // They match.
    // So, we need to pad the number's parity string to 18 digits.
    while (pattern.length() < 18) {
        pattern += '0';
    }
    return pattern;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Use a map to store counts of each parity pattern string
    std::map<std::string, int> pattern_counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string p = get_parity_pattern(a);
            pattern_counts[p]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string p = get_parity_pattern(a);
            pattern_counts[p]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's to the fixed length (18)
            while (s.length() < 18) {
                s = '0' + s; // Pad from left
            }
            // The get_parity_pattern function generates patterns from right to left.
            // The query pattern 's' is given from left to right.
            // Example: s = "010" means 0 (leftmost), 1, 0 (rightmost).
            // The problem states "i-th from the right digit in decimal notation matches the i-th from the right digit of the pattern."
            // So, if s = "010", its rightmost digit is '0', second from right is '1', third from right is '0'.
            // Our get_parity_pattern generates "010" for 92 (2 is even, 9 is odd).
            // So, the pattern string generated by get_parity_pattern is already in the correct order (right-to-left).
            // The query pattern 's' needs to be reversed to match this format.
            std::reverse(s.begin(), s.end());
            // After reversing, pad with '0's to the fixed length (18)
            while (s.length() < 18) {
                s += '0'; // Pad from right (which corresponds to left in original number)
            }

            std::cout << pattern_counts[s] << "\n";
        }
    }

    return 0;
}

