// Function to get prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x | p such that x is not divisible by q.
        // This means x must be p / (some factor of q that makes p/factor not divisible by q)
        // Or, more generally, x = p / (r^k) where r is a prime factor of q, and r^k is the highest power of r that divides p,
        // such that p / (r^k) is not divisible by q.
        // We want to maximize x, so we want to minimize the divisor we remove from p.
        // The divisor we remove must be of the form r^k where r is a prime factor of q.

        std::vector<long long> prime_factors_of_q = get_prime_factors(q);
        long long max_x = 0;

        for (long long r : prime_factors_of_q) {
            long long current_p = p;
            // Divide current_p by r until it's no longer divisible by q
            // We want to find the smallest power of r, say r^k, such that p / r^k is not divisible by q.
            // To do this, we find the highest power of r that divides p, let it be r^a.
            // Then we try p / r, p / r^2, ..., p / r^a.
            // The largest x will be p / r^k for some k.
            // We need to find the smallest k such that (p / r^k) % q != 0.
            // This is equivalent to finding the largest x = p / r^k such that x % q != 0.

            long long temp_p = p;
            while (temp_p % q == 0) {
                temp_p /= r;
            }
            max_x = std::max(max_x, temp_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

