void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    for (int x = 0; x <= 9; ++x) {
        std::string coloring(n, ' ');
        char last1 = '0';
        char last2 = '0';
        bool possible = true;

        for (int i = 0; i < n; ++i) {
            char current_digit = s[i];
            if (current_digit < (x + '0')) {
                // Must be color 1
                if (current_digit < last1) {
                    possible = false;
                    break;
                }
                coloring[i] = '1';
                last1 = current_digit;
            } else if (current_digit > (x + '0')) {
                // Must be color 2
                if (current_digit < last2) {
                    possible = false;
                    break;
                }
                coloring[i] = '2';
                last2 = current_digit;
            } else { // current_digit == (x + '0')
                // Can be either 1 or 2
                // Try to put it in color 2 if possible, to keep color 1 digits small
                if (current_digit >= last2) {
                    coloring[i] = '2';
                    last2 = current_digit;
                } else if (current_digit >= last1) {
                    coloring[i] = '1';
                    last1 = current_digit;
                } else {
                    possible = false;
                    break;
                }
            }
        }

        if (possible) {
            // Final check: last digit of S1 <= first digit of S2
            // This is implicitly handled by the logic:
            // last1 is the max digit in S1.
            // last2 is the min digit in S2.
            // If a digit `d` is colored 1, it must be >= last1.
            // If a digit `d` is colored 2, it must be >= last2.
            // The split point `x` ensures that any digit `d1` colored 1 is <= `x`
            // and any digit `d2` colored 2 is >= `x`.
            // So, max(S1) <= x and min(S2) >= x.
            // Thus, max(S1) <= min(S2) is guaranteed if both are non-empty.
            // If one is empty, it's trivially sorted.
            std::cout << coloring << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

