#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    std::string s;
    std::cin >> s;

    std::vector<std::set<char>> adj(26);
    std::vector<int> degree(26, 0);
    std::vector<bool> present_in_s(26, false);

    for (size_t i = 0; i < s.length(); ++i) {
        present_in_s[s[i] - 'a'] = true;
        if (i > 0) {
            char c1 = s[i - 1];
            char c2 = s[i];
            if (adj[c1 - 'a'].find(c2) == adj[c1 - 'a'].end()) {
                adj[c1 - 'a'].insert(c2);
                adj[c2 - 'a'].insert(c1);
                degree[c1 - 'a']++;
                degree[c2 - 'a']++;
            }
        }
    }

    for (int i = 0; i < 26; ++i) {
        if (degree[i] > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::vector<bool> visited(26, false);

    for (int i = 0; i < 26; ++i) {
        if (present_in_s[i] && degree[i] <= 1 && !visited[i]) {
            // Start a path from a character with degree 0 or 1 that is in s
            // Degree 0 means it's an isolated character in s (s has length 1)
            // Degree 1 means it's an endpoint of a path

            char current_char = (char)('a' + i);

            // Traverse forward
            while (current_char != 0 && !visited[current_char - 'a']) {
                layout += current_char;
                visited[current_char - 'a'] = true;

                char next_char = 0;
                for (char neighbor : adj[current_char - 'a']) {
                    if (!visited[neighbor - 'a']) {
                        next_char = neighbor;
                        break;
                    }
                }
                current_char = next_char;
            }
        }
    }

    // Check if all characters present in s have been included in the layout
    for (int i = 0; i < 26; ++i) {
        if (present_in_s[i] && !visited[i]) {
            // This means there's a cycle or a path not starting with degree 1/0
            // (e.g., a path where all nodes have degree 2, forming a cycle or a long path)
            // This case should be covered by degree check or by starting from any unvisited node.
            // If a character is present in s and not visited, it means it's part of a component
            // that wasn't picked up by starting from a degree 0/1 node.
            // This implies all nodes in that component have degree 2, forming a cycle.
            // A cycle is not allowed in a linear keyboard layout.
            std::cout << "NO\n";
            return;
        }
    }

    // Add remaining characters not in s
    for (int i = 0; i < 26; ++i) {
        if (!visited[i]) {
            layout += (char)('a' + i);
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

