    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // This is sum_r = (b-1) * b * inv(2) mod MOD
    // If b-1 is 0 (i.e., b=1), sum_r is 0.
    // In this case, mod(x, 1) is always 0, so no nice integers.
    // The problem statement says mod(x, b) != 0.
    // If b=1, mod(x, 1) is always 0, so no nice integers.
    // The formula (b-1)*b/2 correctly gives 0 for b=1.

    long long sum_r_val;
    if (b == 1) {
        sum_r_val = 0;
    } else {
        long long b_minus_1 = b - 1;
        long long term1 = b_minus_1 % MOD;
        long long term2 = b % MOD;

        // Calculate (b-1) * b
        long long product_b_terms = (term1 * term2) % MOD;

        // Calculate inverse of 2 modulo MOD
        // MOD is 10^9 + 7, which is prime.
        // inv(2) = (MOD + 1) / 2
        long long inv2 = (MOD + 1) / 2;

        sum_r_val = (product_b_terms * inv2) % MOD;
    }

    // Sum of (k * b + 1) for k from 1 to a
    // This is sum_k = sum_{k=1 to a} (k*b + 1)
    // sum_k = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // sum_k = b * (a * (a+1) / 2) + a
    // sum_k = (b * a * (a+1) * inv(2) + a) mod MOD

    long long sum_k_val;
    long long a_plus_1 = a + 1;
    long long term_a1 = a % MOD;
    long long term_a2 = a_plus_1 % MOD;

    // Calculate a * (a+1)
    long long product_a_terms = (term_a1 * term_a2) % MOD;

    // Calculate inverse of 2 modulo MOD
    long long inv2 = (MOD + 1) / 2;

    long long sum_k_part1 = (product_a_terms * inv2) % MOD;
    sum_k_part1 = (sum_k_part1 * (b % MOD)) % MOD; // Multiply by b

    long long sum_k_part2 = a % MOD; // Add a

    sum_k_val = (sum_k_part1 + sum_k_part2) % MOD;

    // Total sum = (sum_r_val * sum_k_val) mod MOD
    long long total_sum = (sum_r_val * sum_k_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
