#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_actual = 0; k_actual < L; ++k_actual) {
        char first_char_t = s[k_actual];
        int char_code = first_char_t - 'a';

        const std::vector<int>& possible_k_values = char_indices[char_code];

        if (possible_k_values.size() == 1) {
            total_win_prob += 1.0; // k is uniquely determined
            continue;
        }

        // Vasya needs to choose an optimal position p (1 to L-1)
        // to maximize the probability of winning for this specific k_actual.
        // The probability for this k_actual is 1/L.
        // We need to find the best p that maximizes the number of unique k's.

        int max_unique_k_count = 0;

        for (int p = 1; p < L; ++p) {
            // For a fixed p, what is t[p]?
            // t[p] = s[(k_actual + p) % L]
            char second_char_t = s[(k_actual + p) % L];

            int current_unique_k_count = 0;
            for (int k_candidate : possible_k_values) {
                // Check if this k_candidate is consistent with t[0] and t[p]
                // t[0] is s[k_candidate] (already checked by being in possible_k_values)
                // t[p] is s[(k_candidate + p) % L]
                if (s[(k_candidate + p) % L] == second_char_t) {
                    current_unique_k_count++;
                }
            }
            // If only one k_candidate is consistent, Vasya wins for this k_actual and p.
            if (current_unique_k_count == 1) {
                max_unique_k_count = std::max(max_unique_k_count, 1);
                // If we found a p that guarantees a win for this k_actual, we don't need to check other p's.
                // This is because we only care if *there exists* a p that makes it unique.
                // If max_unique_k_count becomes 1, it means Vasya can win for this k_actual.
                break; 
            }
        }
        total_win_prob += static_cast<double>(max_unique_k_count);
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left half (jars 1 to n)
    // diff_L[k] = (count of 1s in a[0...k-1]) - (count of 2s in a[0...k-1])
    // for k from 0 to n
    std::vector<int> diff_L(n + 1, 0);
    int s1_L = 0;
    int s2_L = 0;
    for (int k = 0; k < n; ++k) {
        if (a[k] == 1) {
            s1_L++;
        } else {
            s2_L++;
        }
        diff_L[k + 1] = s1_L - s2_L;
    }

    // Calculate suffix sums for the right half (jars n+1 to 2n)
    // diff_R[k] = (count of 1s in a[2n-1...2n-k]) - (count of 2s in a[2n-1...2n-k])
    // for k from 0 to n
    std::vector<int> diff_R(n + 1, 0);
    int s1_R = 0;
    int s2_R = 0;
    for (int k = 0; k < n; ++k) {
        if (a[2 * n - 1 - k] == 1) {
            s1_R++;
        } else {
            s2_R++;
        }
        diff_R[k + 1] = s1_R - s2_R;
    }

    // Store the minimum number of jars eaten from the right to achieve a certain diff_R value
    // map: diff_val -> min_jars_eaten_from_right
    std::map<int, int> min_jars_right;
    for (int k = 0; k <= n; ++k) {
        int current_diff_R = diff_R[k];
        if (min_jars_right.find(current_diff_R) == min_jars_right.end()) {
            min_jars_right[current_diff_R] = k;
        } else {
            min_jars_right[current_diff_R] = std::min(min_jars_right[current_diff_R], k);
        }
    }

    int min_total_eaten = 2 * n; // Max possible jars eaten

    // Iterate through all possible jars eaten from the left (0 to n)
    for (int k_L = 0; k_L <= n; ++k_L) {
        int current_diff_L = diff_L[k_L];
        // We need diff_L[k_L] + diff_R[k_R] = 0, so diff_R[k_R] = -diff_L[k_L]
        int target_diff_R = -current_diff_L;

        if (min_jars_right.count(target_diff_R)) {
            int k_R = min_jars_right[target_diff_R];
            min_total_eaten = std::min(min_total_eaten, k_L + k_R);
        }
    }

    std::cout << min_total_eaten << std::endl;
}

