        long long abs_m = std::abs(m);

        // Ensure abs_n >= abs_m for simpler logic
        if (abs_n < abs_m) {
            std::swap(abs_n, abs_m);
        }

        // Minimum moves required is max(abs_n, abs_m)
        // If k < max(abs_n, abs_m), it's impossible.
        if (k < abs_n) {
            std::cout << -1 << "\n";
            continue;
        }

        long long diagonal_moves_to_reach = abs_m;
        long long straight_moves_to_reach = abs_n - abs_m;
        long long moves_to_reach = diagonal_moves_to_reach + straight_moves_to_reach;

        long long remaining_moves = k - moves_to_reach;

        // Case 1: abs_n and abs_m have the same parity
        // This means abs_n - abs_m is even.
        // (0,0) -> (abs_n, abs_m)
