        // 2. Right to left: `d = infinity`. If `a[j]==0`, `d=0`. Else `d++`. `dist_0[j] = min(dist_0[j], d)`.
        // Same for `dist_1[i]`.
        //
        // Then, `result_a[i] = 0` if `dist_0[i] <= dist_1[i]`.
        // `result_a[i] = 1` if `dist_1[i] < dist_0[i]`.
        //
        // This is the final stable state.
        // The number of steps `max_k` is the maximum `min(dist_0[i], dist_1[i]) - 1` over all `i`.
        // No, `max_k` is `max((len-1)/2)` for any block.
        //
        // Let's re-verify the `max_k` calculation.
        // A block of `len` identical values `X X ... X` will shrink from both ends.
        // After `k` steps, `2k` elements will have flipped.
        // The middle `len - 2k` elements will remain.
        // For the block to stabilize, `len - 2k` must be 0 or 1.
        // If `len` is odd, `len = 2m+1`. After `m` steps, `2m` elements flip, 1 remains. `k=m`.
        // If `len` is even, `len = 2m`. After `m-1` steps, `2m-2` elements flip, 2 remain.
        // After `m` steps, `2m` elements flip, 0 remain.
        // The number of steps for a block of length `len` to completely disappear (if surrounded by different values)
        // or shrink to a single element is `floor((len-1)/2)`.
        // This is `(len-1)/2` for odd `len`, and `(len-2)/2` for even `len`.
        // Example: 01110 -> 00100 (len=3, (3-1)/2=1 step)
        // Example: 011110 -> 001100 -> 000000 (len=4, (4-1)/2=1.5 -> floor(1.5)=1 step for 001100, then 1 more step for 000000)
        // The number of steps is `(len-1)/2` for odd `len`, and `(len-2)/2 + 1` for even `len`.
        // This is `floor((len-1)/2)` for odd `len`, and `floor((len-1)/2)` for even `len`.
        // So `max_k` is indeed `max((R[i]-1)/2)` for all `i` where `a[i] != a[i-1]`.

        // Now for the final sequence.
        // The final sequence will be `0...01...10...0` or `1...10...01...1`.
        // This means it will be a sequence of `0`s, then `1`s, then `0`s, etc.
        // The elements `a[i]` that are `max_k` steps away from a boundary will be the ones that define the final state.
        //
        // Let's compute `dist_0[i]` and `dist_1[i]`.
        std::vector<int> dist_0(n), dist_1(n);

        int current_dist = n + 1; // Effectively infinity
        for (int i = 0; i < n; ++i) {
            if (a[i] == 0) {
                current_dist = 0;
            } else {
                current_dist++;
            }
            dist_0[i] = current_dist;
        }
        current_dist = n + 1;
        for (int i = n - 1; i >= 0; --i) {
            if (a[i] == 0) {
                current_dist = 0;
            } else {
                current_dist++;
            }
            dist_0[i] = std::min(dist_0[i], current_dist);
        }

        current_dist = n + 1;
        for (int i = 0; i < n; ++i) {
            if (a[i] == 1) {
                current_dist = 0;
            } else {
                current_dist++;
            }
            dist_1[i] = current_dist;
        }
        current_dist = n + 1;
        for (int i = n - 1; i >= 0; --i) {
            if (a[i] == 1) {
                current_dist = 0;
            } else {
                current_dist++;
            }
            dist_1[i] = std::min(dist_1[i], current_dist);
        }

        for (int i = 0; i < n; ++i) {
            if (dist_0[i] <= dist_1[i]) {
                result_a[i] = 0;
            } else {
                result_a[i] = 1;
            }
        }

    for (int i = 0; i < n; ++i) {
        std::cout << result_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y to prevent overflow, as a_i can be up to 10^9 and n up to 2*10^5.
// In the worst case, y could be n * max(a_i) which is 2*10^5 * 10^9 = 2*10^14.
// x is an index, so it fits in int.

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n + 1); // a[0] is unused, a[1] will be set for each query
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    // dp_val[x][parity] stores the final y value if starting at x with given parity,
    // or -1 if it loops, or -2 if not computed yet.
    // parity 0: x increases (step A)
    // parity 1: x decreases (step B)
    std::vector<std::vector<long long>> dp_val(n + 1, std::vector<long long>(2, -2LL));

    // dp_next_x[x][parity] stores the next x value if starting at x with given parity.
    std::vector<std::vector<int>> dp_next_x(n + 1, std::vector<int>(2, 0));

    // Function to compute dp_val and dp_next_x for a given (x_start, parity_start)
    // Returns the final y value.
    long long solve(int x_start, int parity_start, const std::vector<long long>& current_a,
                    std::vector<std::vector<long long>>& memo_val,
                    std::vector<std::vector<int>>& memo_next_x) {

        if (x_start <= 0 || x_start > n) {
            return 0LL; // Base case: already out of bounds, contributes 0 to y
        }
        if (memo_val[x_start][parity_start] != -2LL) {
            return memo_val[x_start][parity_start]; // Already computed or detected loop
        }

        // Mark as currently computing to detect loops
        memo_val[x_start][parity_start] = -1LL; 

        long long val_at_x = current_a[x_start];
        long long current_y_contribution = val_at_x;
        int next_x;
        int next_parity;

        if (parity_start == 0) { // Step A: x increases
            next_x = x_start + val_at_x;
            next_parity = 1; // Next step will be B (x decreases)
        } else { // parity_start == 1: Step B: x decreases
            next_x = x_start - val_at_x;
            next_parity = 0; // Next step will be A (x increases)
        }

        memo_next_x[x_start][parity_start] = next_x;

        long long res = solve(next_x, next_parity, current_a, memo_val, memo_next_x);

        if (res == -1LL) { // Loop detected in subsequent calls
            memo_val[x_start][parity_start] = -1LL;
        } else {
            memo_val[x_start][parity_start] = current_y_contribution + res;
        }
        return memo_val[x_start][parity_start];
    }

    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a[1] for the current run

        // Reset DP tables for each run.
        // Only need to reset for states reachable from (1,0) with current a[1].
        // However, since a[1] changes, it's simpler to recompute everything or
        // use a fresh DP table for each i.
        // A more optimized approach would be to only compute for (x, parity) where x is odd/even
        // based on a[1]'s parity, but a full reset is fine given N constraints.
        for(int k=1; k<=n; ++k) {
            dp_val[k][0] = -2LL;
            dp_val[k][1] = -2LL;
            dp_next_x[k][0] = 0;
            dp_next_x[k][1] = 0;
        }

        // The program starts with x=1, y=0, and performs step A first.
        // So, the initial state is effectively (x=1, parity=0).
        // The initial y contribution is a[1].
        long long initial_val_at_x = a[1];
        int initial_next_x = 1 + initial_val_at_x;
        int initial_next_parity = 1; // After step A, next is step B

        long long result;
        if (initial_next_x <= 0 || initial_next_x > n) {
            result = initial_val_at_x; // Terminates immediately after first step A
        } else {
            // Mark (1,0) as computing to detect loops involving the very first step
            dp_val[1][0] = -1LL; 
            dp_next_x[1][0] = initial_next_x;

            long long subsequent_y = solve(initial_next_x, initial_next_parity, a, dp_val, dp_next_x);
            if (subsequent_y == -1LL) {
                result = -1LL; // Loop detected
            } else {
                result = initial_val_at_x + subsequent_y;
            }
            dp_val[1][0] = result; // Store the result for (1,0)
        }

        std::cout << result << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long m;
    std::cin >> n >> m;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        bool possible = true;
        long long prev_b = 0; // The value of b_{i-1}

        for (int i = 0; i < n; ++i) {
            long long current_a = a[i];
            long long current_b;

            // Case 1: current_b is current_a + x
            // This means current_b >= current_a.
            // We need current_b >= prev_b.
            // So, current_a + x >= prev_b.
            // If current_a >= prev_b, then we can set current_b = current_a.
            // This requires x = 0, which is <= mid.
            // So, current_b = current_a is a valid choice.
            // If current_a < prev_b, we must increment current_a.
            // The smallest possible current_b is prev_b.
            // This requires x = prev_b - current_a.
            // If prev_b - current_a <= mid, then current_b = prev_b is a valid choice.

            // Case 2: current_b is current_a + x - m
            // This means current_b < current_a.
            // We need current_b >= prev_b.
            // So, current_a + x - m >= prev_b.
            // This implies x >= prev_b - current_a + m.
            // This is only possible if prev_b - current_a + m <= mid.
            // If this condition holds, we can set current_b = prev_b.
            // This requires x = prev_b - current_a + m.

            // Let's analyze the conditions for current_b >= prev_b
            // We want to find the smallest possible current_b >= prev_b.
            // If current_a >= prev_b:
            //   We can choose current_b = current_a. This requires x = 0.
            //   Since 0 <= mid, this is always possible.
            //   So, if current_a >= prev_b, we can set current_b = current_a.
            //   The value of x needed is 0.
            //   However, we might need to increment current_a to current_a + x - m to satisfy prev_b.
            //   This happens if current_a + mid < prev_b.
            //   Example: a_i = 0, prev_b = 5, m = 10, mid = 2.
            //   current_a = 0. We need b_i >= 5.
            //   Option 1: b_i = a_i + x. Smallest b_i >= 5 is 5. Requires x = 5. But 5 > mid. Not possible.
            //   Option 2: b_i = a_i + x - m. Smallest b_i >= 5 is 5. Requires x = 5 + m. But x > mid. Not possible.
            //   So, if current_a + mid < prev_b, it's impossible.

            // Let's rephrase: we need to find x such that 0 <= x <= mid and (a_i + x) % m >= prev_b.
            // If a_i >= prev_b:
            //   We can choose x = 0. Then (a_i + 0) % m = a_i >= prev_b. This is valid.
            //   So, we can set current_b = a_i.
            //   However, we might be forced to use a larger x if a_i + mid < prev_b.
            //   This means we can't reach prev_b by just incrementing a_i.
            //   No, this is wrong. If a_i >= prev_b, we can always choose x=0, so b_i = a_i.
            //   This is the smallest possible b_i that is >= prev_b.
            //   So, if a_i >= prev_b, we set prev_b = a_i.
            //   The only exception is if a_i + mid < prev_b. This means a_i is too small.
            //   This condition is actually: if a_i + mid < prev_b, then we cannot make b_i >= prev_b.
            //   This is because if we increment a_i by x, where x <= mid, then (a_i + x) % m.
            //   If a_i + x < m, then b_i = a_i + x. If a_i + x < prev_b, then it's impossible.
            //   The maximum value we can achieve without wrapping around is a_i + mid.
            //   If a_i + mid < prev_b, then we can't make b_i >= prev_b without wrapping.
            //   If we wrap around, b_i = a_i + x - m.
            //   For this to be >= prev_b, we need a_i + x - m >= prev_b.
            //   This means x >= prev_b - a_i + m.
            //   If prev_b - a_i + m <= mid, then we can achieve b_i = prev_b.
            //   This is the only way to make b_i >= prev_b if a_i + mid < prev_b.

            // Correct logic:
            // We need to find a value `b_i` such that `b_i >= prev_b` and `b_i` can be formed from `a_i`
            // using at most `mid` operations.
            // This means `b_i = (a_i + x) % m` for some `0 <= x <= mid`.

            // Option 1: `b_i` is formed by `a_i + x` without wrapping around `m`.
            // So `b_i = a_i + x`.
            // We need `a_i + x >= prev_b`.
            // The smallest `x` that satisfies this is `max(0LL, prev_b - a_i)`.
            // If this `x` is `<= mid`, then we can potentially set `b_i = max(a_i, prev_b)`.
            // Specifically, if `a_i >= prev_b`, we can choose `x=0`, so `b_i = a_i`. This is valid.
            // If `a_i < prev_b`, we need `x = prev_b - a_i`. If `prev_b - a_i <= mid`, then we can set `b_i = prev_b`.

            // Option 2: `b_i` is formed by `a_i + x` wrapping around `m`.
            // So `b_i = a_i + x - m`.
            // We need `a_i + x - m >= prev_b`.
            // The smallest `x` that satisfies this is `max(0LL, prev_b - a_i + m)`.
            // If this `x` is `<= mid`, then we can potentially set `b_i = prev_b`.

            // Let's combine:
            // If `a_i >= prev_b`:
            //   We can always choose `x=0`, making `b_i = a_i`. This satisfies `b_i >= prev_b` and `x <= mid`.
            //   So, `prev_b` becomes `a_i`.
            //   However, there's a special case: if `a_i + mid` is less than `m` and `a_i + mid < prev_b` (this can't happen if `a_i >= prev_b`).
            //   The only way `a_i` could be too small is if `a_i` is close to `m` and `prev_b` is small.
            //   Example: `a_i = 6`, `prev_b = 0`, `m = 7`, `mid = 1`.
            //   `a_i >= prev_b` is true. We can set `b_i = a_i = 6`. `prev_b` becomes 6.
            //   Example: `a_i = 0`, `prev_b = 6`, `m = 7`, `mid = 1`.
            //   `a_i < prev_b`.
            //   Option 1: `b_i = a_i + x`. Need `x = prev_b - a_i = 6 - 0 = 6`. `6 > mid`. Not possible.
            //   Option 2: `b_i = a_i + x - m`. Need `x = prev_b - a_i + m = 6 - 0 + 7 = 13`. `13 > mid`. Not possible.
            //   So, this `mid` is not possible.

            // The condition for `b_i` to be achievable from `a_i` with `x <= mid` and `b_i >= prev_b`:
            // 1. If `a_i >= prev_b`:
            //    We can choose `b_i = a_i`. This requires `x=0`, which is `<= mid`. So this is always possible.
            //    The new `prev_b` becomes `a_i`.
            //    However, we might be able to choose a smaller `b_i` if `a_i` is large and `prev_b` is small.
            //    For example, `a_i = 5, prev_b = 0, m = 10, mid = 2`.
            //    If we set `b_i = 5`, `prev_b` becomes 5.
            //    But we could also set `b_i = (5 + 2) % 10 = 7`.
            //    Or `b_i = (5 + x) % 10`.
            //    The smallest `b_i` we can choose is `prev_b`.
            //    If `a_i >= prev_b`:
            //      We can set `b_i = a_i`. This requires `x=0`.
            //      We can also set `b_i = prev_b` if `(a_i + x) % m = prev_b` for some `x <= mid`.
            //      This means `a_i + x = prev_b` (if `a_i >= prev_b` this implies `x <= 0`, so `x=0` and `a_i = prev_b`)
            //      OR `a_i + x = prev_b + m`.
            //      So `x = prev_b + m - a_i`. If this `x <= mid`, then we can set `b_i = prev_b`.
            //      If `a_i >= prev_b` and `prev_b + m - a_i <= mid`, then we can choose `b_i = prev_b`.
            //      Otherwise, we must choose `b_i = a_i`.
            //      So, if `a_i >= prev_b`:
            //        If `prev_b + m - a_i <= mid`, then `prev_b` remains `prev_b`.
            //        Else, `prev_b` becomes `a_i`.
            // 2. If `a_i < prev_b`:
            //    We must increment `a_i`.
            //    We need `a_i + x >= prev_b`.
            //    The smallest `x` is `prev_b - a_i`.
            //    If `prev_b - a_i <= mid`, then we can set `b_i = prev_b`.
            //    If `prev_b - a_i > mid`, then it's impossible to reach `prev_b` without wrapping.
            //    In this case, we must wrap around.
            //    We need `a_i + x - m >= prev_b`.
            //    This means `x >= prev_b - a_i + m`.
            //    If `prev_b - a_i + m <= mid`, then we can set `b_i = prev_b`.
            //    Otherwise, it's impossible.

            // Simplified logic:
            // We need to find `b_i` such that `b_i >= prev_b` and `b_i = (a_i + x) % m` for some `0 <= x <= mid`.
            //
            // If `a_i >= prev_b`:
            //   We have two choices for `b_i`:
            //   a) `b_i = a_i`. This requires `x=0`, which is `<= mid`. This is always possible.
            //   b) `b_i = prev_b`. This requires `x = (prev_b - a_i + m) % m`.
            //      If `prev_b >= a_i`, then `x = prev_b - a_i`.
            //      If `prev_b < a_i`, then `x = prev_b - a_i + m`.
            //      In our current case `a_i >= prev_b`, so `x = prev_b - a_i + m`.
            //      If this `x <= mid`, then we can choose `b_i = prev_b`.
            //   To minimize `b_i`, we prefer `prev_b` over `a_i`.
            //   So, if `(prev_b - a_i + m) % m <= mid`, we set `prev_b` to `prev_b`.
            //   Otherwise, we must set `prev_b` to `a_i`.
            //   Note: `(prev_b - a_i + m) % m` is the number of increments needed to go from `a_i` to `prev_b` (modulo m).
            //   If `a_i >= prev_b`:
            //     If `a_i` can be decremented to `prev_b` by adding `x` and wrapping around, i.e., `(prev_b - a_i + m) <= mid`,
            //     then we can keep `prev_b` as `prev_b`.
            //     Otherwise, we must take `a_i` as the new `prev_b`.
            //
            // If `a_i < prev_b`:
            //   We must increment `a_i` to at least `prev_b`.
            //   The number of increments needed to reach `prev_b` from `a_i` is `prev_b - a_i`.
            //   If `prev_b - a_i <= mid`, then we can set `b_i = prev_b`.
            //   Otherwise, it's impossible to make `b_i >= prev_b` with `x <= mid`.
            //   So, `possible = false`.

            if (a[i] >= prev_b) {
                // Option 1: Set b_i = a_i. This requires x=0, which is <= mid. Always possible.
                // Option 2: Set b_i = prev_b. This requires x = (prev_b - a[i] + m) % m.
                // Since a[i] >= prev_b, this x is `prev_b - a[i] + m`.
                // If this x <= mid, we can choose b_i = prev_b.
                // Otherwise, we must choose b_i = a[i].
                if (a[i] + mid < m && a[i] + mid < prev_b) { // This condition is for a_i to be too small to reach prev_b even with wrap
                    // This means a_i is large, prev_b is small.
                    // E.g., a_i = 5, prev_b = 0, m = 10, mid = 2.
                    // a_i >= prev_b.
                    // (prev_b - a_i + m) % m = (0 - 5 + 10) % 10 = 5.
                    // 5 > mid. So we must take a_i. prev_b becomes 5.
                    // This is the correct logic.
                    // The condition `a[i] + mid < m && a[i] + mid < prev_b` is actually `a[i] + mid < prev_b`
                    // This means even if we increment a[i] by mid, it's still less than prev_b.
                    // This can only happen if a[i] is small and prev_b is large.
                    // But we are in the `a[i] >= prev_b` branch. So this condition is impossible.
                    // The only way `a[i] + mid < prev_b` could be true is if `prev_b` is very large and `a[i]` is very small.
                    // But we are in `a[i] >= prev_b`.
                    // So, if `a[i] >= prev_b`, we can always set `b_i = a[i]`.
                    // The question is if we can set `b_i = prev_b`.
                    // This requires `x = (prev_b - a[i] + m) % m`.
                    // Since `a[i] >= prev_b`, `prev_b - a[i]` is negative or zero.
                    // So `x = prev_b - a[i] + m`.
                    // If `x <= mid`, then we can set `b_i = prev_b`.
                    // Otherwise, we must set `b_i = a[i]`.
                    if (prev_b - a[i] + m <= mid) {
                        // prev_b remains prev_b
                    } else {
                        prev_b = a[i];
                    }
                } else { // a[i] < prev_b
                    // We need to increment a[i] to at least prev_b.
                    // The number of increments needed is `prev_b - a[i]`.
                    // If `prev_b - a[i] <= mid`, then we can set `b_i = prev_b`.
                    // Otherwise, it's impossible.
                    if (prev_b - a[i] > mid) {
                        possible = false;
                        break;
                    }
                    // If `prev_b - a[i] <= mid`, then `prev_b` remains `prev_b`.
                }
            } else { // a[i] < prev_b
                // We need to increment a[i] to at least prev_b.
                // The number of increments needed is `prev_b - a[i]`.
                // If `prev_b - a[i] <= mid`, then we can set `b_i = prev_b`.
                // Otherwise, it's impossible.
                if (prev_b - a[i] > mid) {
                    possible = false;
                    break;
                }
                // If `prev_b - a[i] <= mid`, then `prev_b` remains `prev_b`.
            }
        }

        if (possible) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n);
    std::vector<long long> min_initial_val(n, LLONG_MAX); // min_initial_val[j] = m_k - delta_k[j] for some query k

    // For each query operation (type 2), we know that for all j in [l, r],
    // a_0[j] + delta[j] <= m.
    // This implies a_0[j] <= m - delta[j].
    // We want to find the largest possible a_0[j] that satisfies all constraints.
    // So, a_0[j] = min(m_k - delta_k[j]) over all queries k where j is in [l_k, r_k].
    // Initialize delta_prefix_sum to track current sum of d_i for type 1 ops.
    std::vector<long long> current_delta(n, 0);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                min_initial_val[j] = std::min(min_initial_val[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // If a_0[j] was not constrained by any type 2 query, it can be anything.
    // To maximize chances of satisfying constraints, we can set it to 0.
    // Or, more generally, we can set it to a value that doesn't violate |a_i| <= 10^9.
    // The problem statement says "all numbers in his array didn't exceed 10^9 in their absolute value".
    // This refers to the initial array.
    // If min_initial_val[j] is still LLONG_MAX, it means a_0[j] was never constrained by an upper bound.
    // We can set it to 0, which is within the 10^9 limit.
    for (int j = 0; j < n; ++j) {
        if (min_initial_val[j] == LLONG_MAX) {
            initial_a[j] = 0;
        } else {
            initial_a[j] = min_initial_val[j];
        }
    }

    // Now, verify if this initial_a satisfies all type 2 queries.
    // Re-simulate all operations with the constructed initial_a.
    std::vector<long long> current_array_values(n);
    for (int j = 0; j < n; ++j) {
        current_array_values[j] = initial_a[j];
    }

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_array_values[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val_in_range = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val_in_range = std::max(max_val_in_range, current_array_values[j]);
            }
            if (max_val_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // If all checks pass, print YES and the array.
    std::cout << "YES\n";
    for (int j = 0; j < n; ++j) {
        std::cout << initial_a[j] << (j == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> treated_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        treated_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false;

        long long current_v_cry = children[i].v;
        long long total_d_cry_effect = 0; // Accumulates d_j cries from children leaving due to current_v_cry or previous d_j_cries

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated d_cry_effect from previous children leaving
            if (total_d_cry_effect > 0) {
                children[j].p -= total_d_cry_effect;
            }

            // Apply current_v_cry effect
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry = std::max(0LL, current_v_cry - 1);
            }

            // Check if child j leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_cry_effect += children[j].d;
            }
        }
    }

    std::cout << treated_children_indices.size() << "\n";
    for (size_t i = 0; i < treated_children_indices.size(); ++i) {
        std::cout << treated_children_indices[i] << (i == treated_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

