        best_partition[elements[0].original_index] = 1;
    }


    // Case 2: Partition where elements[0] is in S1 and elements[1] is in S2.
    // This implies that elements[0] and elements[1] are in different subsequences.
    // The smallest sum a_i + a_j is elements[0].value + elements[1].value.
    // Since they are in different subsequences, f(elements[0], elements[1]) = elements[0].value + elements[1].value + h.
    // This value will be the minimum f.
    // The maximum f will be elements[n-1].value + elements[n-2].value + h (if elements[n-1] and elements[n-2] are in different subsequences)
    // OR elements[n-1].value + elements[n-2].value (if they are in the same subsequence).
    //
    // Consider the partition: elements[0] in S1, elements[1]...elements[n-1] in S2.
    // min_f = elements[0].value + elements[1].value + h (from elements[0] in S1, elements[1] in S2)
    // max_f = elements[n-1].value + elements[n-2].value (from elements[n-1], elements[n-2] both in S2)
    // goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value + h)
    // This is only valid if elements[n-1] and elements[n-2] are both in S2.
    //
    // Let's consider a specific partition:
    // elements[0] is in S1.
    // elements[1], ..., elements[n-1] are in S2.
    //
    // min_f:
    //   - elements[0].value + elements[1].value + h (elements[0] in S1, elements[1] in S2)
    // max_f:
    //   - elements[n-1].value + elements[n-2].value (elements[n-1], elements[n-2] in S2)
    //   - elements[0].value + elements[n-1].value + h (elements[0] in S1, elements[n-1] in S2)
    //
    // The maximum f will be max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h).
    // The minimum f will be elements[0].value + elements[1].value + h.
    //
    // This partition is: elements[0] in S1, all others in S2.
    // min_val_f = elements[0].value + elements[1].value + h;
    // max_val_f = std::max((long long)elements[n-1].value + elements[n-2].value, (long long)elements[0].value + elements[n-1].value + h);
    // current_goodness = max_val_f - min_val_f;
    //
    // This is only if n >= 2.
    if (n >= 2) {
        long long min_f_val = (long long)elements[0].value + elements[1].value + h;
        long long max_f_val = std::max((long long)elements[n - 1].value + elements[n - 2].value, (long long)elements[0].value + elements[n - 1].value + h);
        long long current_goodness = max_f_val - min_f_val;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            best_partition[elements[0].original_index] = 1;
            for (int i = 1; i < n; ++i) {
                best_partition[elements[i].original_index] = 2;
            }
        }
    }

    // Case 3: Partition where elements[0] and elements[1] are in S1, and elements[2]...elements[n-1] are in S2.
    // This is only possible if n >= 3.
    //
    // min_f:
    //   - elements[0].value + elements[1].value (both in S1)
    //   - elements[0].value + elements[2].value + h (elements[0] in S1, elements[2] in S2)
    //
    // max_f:
    //   - elements[n-1].value + elements[n-2].value (both in S2)
    //   - elements[1].value + elements[n-1].value + h (elements[1] in S1, elements[n-1] in S2)
    //
    // The minimum f will be elements[0].value + elements[1].value.
    // The maximum f will be max(elements[n-1].value + elements[n-2].value, elements[1].value + elements[n-1].value + h).
    //
    // This partition is: elements[0], elements[1] in S1, all others in S2.
    // min_val_f = elements[0].value + elements[1].value;
    // max_val_f = std::max((long long)elements[n-1].value + elements[n-2].value, (long long)elements[1].value + elements[n-1].value + h);
    // current_goodness = max_val_f - min_val_f;
    //
    // This is only if n >= 3.
    if (n >= 3) {
        long long min_f_val = (long long)elements[0].value + elements[1].value;
        long long max_f_val = std::max((long long)elements[n - 1].value + elements[n - 2].value, (long long)elements[1].value + elements[n - 1].value + h);
        long long current_goodness = max_f_val - min_f_val;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            best_partition[elements[0].original_index] = 1;
            best_partition[elements[1].original_index] = 1;
            for (int i = 2; i < n; ++i) {
                best_partition[elements[i].original_index] = 2;
            }
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // max_r_for_l[i] stores the maximum r such that the substring s[i...r]
    // does NOT contain the pattern.
    // If max_r_for_l[i] is n, it means s[i...n-1] does not contain the pattern.
    // If max_r_for_l[i] is less than i, it means s[i...i] already contains the pattern,
    // which is impossible as min length is 3.
    // Initialize with n-1, meaning s[i...n-1] is initially considered "bad" (no pattern).
    std::vector<int> max_r_for_l(n);
    for (int i = 0; i < n; ++i) {
        max_r_for_l[i] = n - 1;
    }

    // Iterate through all possible starting positions x for the pattern s_x = s_{x+k} = s_{x+2k}
    // Note: string indices are 0-based, problem statement uses 1-based.
    // s_x = s_{x+k} = s_{x+2k} means indices x, x+k, x+2k.
    // The minimum length of such a pattern is 3 (when k=1).
    // The maximum k is such that x+2k < n. So 2k < n-x, k < (n-x)/2.
    // The maximum k is (n-1-x)/2.
    // The maximum x is n-3 (for k=1).
    for (int x = 0; x <= n - 3; ++x) {
        // For k=1, check s[x] == s[x+1] == s[x+2]
        if (s[x] == s[x+1] && s[x+1] == s[x+2]) {
            // This pattern occurs at indices x, x+1, x+2.
            // Any substring s[l...r] that contains this pattern is "good".
            // The smallest r that contains this pattern for a given l is x+2.
            // So, for any l <= x, and r >= x+2, the pair (l, r) is good.
            // We are interested in updating max_r_for_l.
            // For any l from 0 to x, the pattern starting at x makes any r >= x+2 a "good" r.
            // So, for these l, the maximum r that does NOT contain the pattern must be less than x+2.
            // We update max_r_for_l[l] to min(current max_r_for_l[l], x+1).
            // This means for l, any r from l to x+1 is still potentially "bad".
            // Any r >= x+2 is now "good".
            for (int l = 0; l <= x; ++l) {
                max_r_for_l[l] = std::min(max_r_for_l[l], x + 1);
            }
        }
    }

    // For k=2, check s[x] == s[x+2] == s[x+4]
    // Max x is n-5 (for k=2).
    for (int x = 0; x <= n - 5; ++x) {
        if (s[x] == s[x+2] && s[x+2] == s[x+4]) {
            // This pattern occurs at indices x, x+2, x+4.
            // Similar logic as above.
            // For any l from 0 to x, the pattern starting at x makes any r >= x+4 a "good" r.
            // We update max_r_for_l[l] to min(current max_r_for_l[l], x+3).
            for (int l = 0; l <= x; ++l) {
                max_r_for_l[l] = std::min(max_r_for_l[l], x + 3);
            }
        }
    }

    // For k=3, check s[x] == s[x+3] == s[x+6]
    // Max x is n-7 (for k=3).
    for (int x = 0; x <= n - 7; ++x) {
        if (s[x] == s[x+3] && s[x+3] == s[x+6]) {
            // This pattern occurs at indices x, x+3, x+6.
            // Similar logic as above.
            // For any l from 0 to x, the pattern starting at x makes any r >= x+6 a "good" r.
            // We update max_r_for_l[l] to min(current max_r_for_l[l], x+5).
            for (int l = 0; l <= x; ++l) {
                max_r_for_l[l] = std::min(max_r_for_l[l], x + 5);
            }
        }
    }

    // Calculate bad_pairs
    // For each l, the number of r's such that l <= r <= max_r_for_l[l]
    // is max_r_for_l[l] - l + 1.
    // If max_r_for_l[l] < l, it means there are no such r's, so 0 bad pairs.
    for (int l = 0; l < n; ++l) {
        if (max_r_for_l[l] >= l) {
            bad_pairs += (max_r_for_l[l] - l + 1);
        }
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

