    //
    // The number of ones in `b` must be less than or equal to the maximum number of ones we can generate in `a`
    // by appending '1's (if `ones_a` is odd) and then '0's.
    //
    // This seems correct and covers all cases.

    int effective_ones_a = ones_a + (ones_a % 2);

    if (ones_b <= effective_ones_a) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int head_idx = 0;
    int p_idx = 0;

    while (p_idx < m) {
        if (head_idx >= n) {
            return false; // Ran out of heads but still have tracks to cover
        }

        long long current_head_pos = h[head_idx];
        long long head_left_reach = current_head_pos - T;
        long long head_right_reach = current_head_pos + T;

        // If the current head cannot reach the current target track p[p_idx]
        // even by moving left as much as possible, then this head is useless for p[p_idx]
        // and any subsequent p_k (since p is sorted).
        // This implies we need to use the next head.
        if (head_right_reach < p[p_idx]) {
            head_idx++;
            continue;
        }

        // The current head can reach p[p_idx].
        // We want to use this head to cover as many subsequent p_k as possible.
        // The head should be positioned such that its rightmost reach covers the furthest possible p_k.
        // To do this, we effectively place the head at p[p_idx] + T.
        // This means the head's actual position would be p[p_idx] + T,
        // and its range would be [p[p_idx], p[p_idx] + 2*T].
        // However, the head is initially at current_head_pos.
        // The actual range it can cover is [current_head_pos - T, current_head_pos + T].
        // If p[p_idx] is within this range, we can cover it.
        // The most efficient way to cover p[p_idx] and subsequent tracks
        // is to move the head to the rightmost position possible while still covering p[p_idx].
        // This means the head's final position will be max(current_head_pos - T, p[p_idx]).
        // No, this is not correct. The head can be anywhere in [current_head_pos - T, current_head_pos + T].
        // We want to cover p[p_idx] and then as many p_k as possible to its right.
        // The head must cover p[p_idx]. So its final position `x` must satisfy `x - T <= p[p_idx] <= x + T`.
        // This means `p[p_idx] - T <= x <= p[p_idx] + T`.
        // Also, `current_head_pos - T <= x <= current_head_pos + T`.
        // So `x` must be in `[max(p[p_idx] - T, current_head_pos - T), min(p[p_idx] + T, current_head_pos + T)]`.
        // To cover the maximum number of tracks to the right, we should choose `x` to be as large as possible.
        // So, `x_final = min(p[p_idx] + T, current_head_pos + T)`.
        // The range covered by this head would be `[x_final - T, x_final + T]`.
        // The rightmost point covered by this head would be `x_final + T`.
        // This is `min(p[p_idx] + 2*T, current_head_pos + 2*T)`.
        // Let's simplify: if a head at `h_i` covers `p_j`, it can cover any track `k` such that
        // `|h_i - k| <= T` is not necessarily true. It can cover any track `k` such that
        // there exists a final position `x` for the head such that `|h_i - x| <= T` AND `|x - k| <= T`.
        // This means `k` must be in `[x - T, x + T]` and `x` must be in `[h_i - T, h_i + T]`.
        // So `k` must be in `[h_i - 2*T, h_i + 2*T]`. This is incorrect.
        // The problem states: "move the head exactly one track to the right or to the left, or leave it on the current track."
        // "A track is considered read if at least one head has visited this track."
        // This means if a head moves from `h_i` to `x` in `k` seconds, it visits all tracks on the path.
        // The total time is `T`. So `|h_i - x| <= T`.
        // The set of tracks visited by this head is `[min(h_i, x), max(h_i, x)]`.
        // The maximum range this head can cover is `[h_i - T, h_i + T]`.
        // If we want to cover `p[p_idx]`, the head must be able to reach `p[p_idx]`.
        // So `p[p_idx]` must be in `[h_i - T, h_i + T]`.
        // If it is, we can use this head. To maximize coverage to the right, we should move the head
        // to `h_i + T`. This covers the range `[h_i, h_i + T]` if `h_i` is to the left of `h_i + T`.
        // No, this is not right. The head can be moved to any `x` such that `|h_i - x| <= T`.
        // The tracks visited are `[min(h_i, x), max(h_i, x)]`.
        // If we want to cover `p[p_idx]`, we must choose `x` such that `p[p_idx]` is in `[min(h_i, x), max(h_i, x)]`.
        // And we want to maximize the rightmost point covered.
        // This means we want to maximize `max(h_i, x)`.
        // The maximum `x` can be is `h_i + T`.
        // So the rightmost point covered by this head is `h_i + T`.
        // This is the standard interpretation for "a head at `h_i` can cover `[h_i - T, h_i + T]`".

        long long current_coverage_right_limit = head_right_reach;

        // Advance p_idx as long as tracks are covered by the current head
        while (p_idx < m && p[p_idx] <= current_coverage_right_limit) {
            p_idx++;
        }
        head_idx++; // Move to the next head
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
