        // Use 5s
        presses += diff / 5;
        diff %= 5;

        // Remaining diff is 0, 1, 2, 3, 4
        if (diff == 0) {
            // No additional presses needed
        } else if (diff == 1) {
            // 1 can be achieved by +1 or -1.
