        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        int current_a1 = a[0]; // Initial haybales in pile 1

        // Iterate through piles from 2 to n (index 1 to n-1)
        for (int i = 1; i < n; ++i) {
            int pile_idx = i; // 0-indexed pile index
            int distance = pile_idx; // Distance from pile 1 (0-indexed)

            if (d == 0) { // No more days left
                break;
            }

            if (a[pile_idx] == 0) { // No haybales in this pile
                continue;
            }

            // Calculate how many haybales can be moved from this pile
            // Each haybale costs 'distance' days to move to pile 1
            int max_haybales_from_this_pile = a[pile_idx];
            int haybales_movable_by_days = d / distance; // Integer division

            int haybales_to_move = std::min(max_haybales_from_this_pile, haybales_movable_by_days);

            current_a1 += haybales_to_move;
            d -= haybales_to_move * distance;
        }
        std::cout << current_a1 << std::endl;
    }
