void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) {
            counts[s_val]++;
        }
    }

    long long current_sum = 0;
    for (auto const& [val, count] : counts) {
        // Add all numbers less than or equal to 2048 to the current sum.
        // This is because any number X can be thought of as contributing X to the total sum.
        // When two X's combine to 2X, the total sum remains the same.
        // The goal is to see if the total sum can be rearranged to include 2048.
        // If the total sum of numbers <= 2048 is >= 2048, then it's possible.
        // This is because any power of two can be formed by combining smaller powers of two
        // as long as their sum is sufficient.
        // For example, if we have {1, 1, 1, 1}, sum is 4. We can make {2, 2} then {4}.
        // If we have {1, 2, 1}, sum is 4. We can make {2, 2} then {4}.
        // The key insight is that we can always combine smaller powers of two into larger ones
        // without loss of "value" towards the target 2048, as long as the value is <= 2048.
        // Numbers > 2048 are useless.
        current_sum += (long long)val * count;
    }

    if (current_sum >= 2048) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

