            //    Is s divisible by 3? The sum of digits is 2 + (n-1)*3.
            //    If n=2, s=23. Sum of digits = 2+3=5. Not divisible by 3.
            //    If n > 2, s = 23...3. Sum of digits = 2 + (n-1)*3.
            //    This sum is 2 + 3n - 3 = 3n - 1.
            //    For s to be divisible by 3, 3n - 1 must be divisible by 3.
            //    However, 3n is always divisible by 3, so 3n - 1 will never be divisible by 3.
            //    Thus, s is never divisible by 3.
            // This construction works for all n >= 2.

            std::cout << '2';
            for (int i = 0; i < n - 1; ++i) {
                std::cout << '3';
            }
            std::cout << "\n";
        }
    }
    return 0;
}

