int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_for_i = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            max_val_for_i = std::max(max_val_for_i, a[i][j]);
        }
        p[i] = max_val_for_i;
    }

    // Check if any p[i] is n-1 and no p[i] is n.
    // This happens if the original permutation contained n, and it was p[k] for some k.
    // In that case, for any j != k, min(p[k], p[j]) = p[j].
    // So, max_val_for_k = max(p[j] for j != k) = n-1 (since p is a permutation of 1..n).
    // If this is the case, we need to change p[k] from n-1 to n.
    bool n_found_in_p = false;
    for (int val : p) {
        if (val == n) {
            n_found_in_p = true;
            break;
        }
    }

    if (!n_found_in_p) {
        // If n is not present in the reconstructed p, it means the original permutation
        // had n at some position, say p_k = n.
        // For this p_k, max(min(p_k, p_j) for j!=k) would be max(p_j for j!=k) = n-1.
        // So, p_k would have been reconstructed as n-1.
        // We need to find one such p_k (which is currently n-1) and change it to n.
        // Since the input guarantees a solution, there must be exactly one such position.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break; 
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

