void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    int min_suffix_price = a[n - 1]; // Initialize with the last price

    // Iterate from right to left, starting from the second to last element
    // For a[i] to be bad, there must be a price a[j] < a[i] where j > i.
    // This is equivalent to a[i] > min(a[i+1], ..., a[n-1]).
    // min_suffix_price stores min(a[i+1], ..., a[n-1]) when we are at index i.
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix_price) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_suffix_price, it means a[i] is
            // either equal to or less than min_suffix_price.
            // In this case, a[i] itself becomes the new minimum for elements
            // to its left.
            min_suffix_price = a[i];
        }
    }
    std::cout << bad_prices_count << "\n";
}

