int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_dist = 0;
        int last_R_pos = -1; // Represents the last 'R' cell visited, or -1 for cell 0.
                             // The distance from last_R_pos to the current cell is `current_cell - last_R_pos`.
                             // We need to be able to jump from last_R_pos to current_cell.
                             // So, `d` must be at least `current_cell - last_R_pos`.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // If we encounter an 'R', it means we can jump right from cell (i+1).
                // The current segment of 'L's (or the initial segment before the first 'R')
                // ends at cell (i+1).
                // The distance from the last 'R' (or cell 0) to this cell (i+1) is (i+1) - (last_R_pos + 1) + 1
                // which simplifies to (i+1) - last_R_pos.
                // Example: last_R_pos = -1 (start at 0). First 'R' at s[0]. Cell is 1.
                // Distance is 1 - (-1) = 2.
                // Example: last_R_pos = 2 (s[1] was 'R'). Next 'R' at s[4]. Cell is 5.
                // Distance is 5 - 2 = 3.
                max_dist = std::max(max_dist, (i + 1) - (last_R_pos + 1) + 1);
                last_R_pos = i; // Update last_R_pos to the current 'R' cell (i+1) - 1
            }
        }

        // After iterating through the string, we need to consider the segment
        // from the last 'R' (or cell 0 if no 'R's) to the target cell n+1.
        // The distance from the last 'R' (or cell 0) to n+1 is (n+1) - (last_R_pos + 1) + 1.
        // This simplifies to (n+1) - last_R_pos.
        max_dist = std::max(max_dist, (n + 1) - (last_R_pos + 1) + 1);

        std::cout << max_dist << "\n";
    }
    return 0;
}

