int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int k = 1; k < n; ++k) {
        // The area of the triangle from the apex to the k-th cut (inclusive of k-th piece)
        // should be k times the area of a single piece.
        // Total area = h/2. Each piece area = (h/2)/n.
        // Area up to k-th cut = k * (h/2)/n = k*h / (2n).
        // Let x_k be the height of this triangle.
        // Area_k = (1/2) * (base_k) * x_k.
        // By similar triangles, base_k / 1 = x_k / h, so base_k = x_k / h.
        // Area_k = (1/2) * (x_k / h) * x_k = x_k^2 / (2h).
        // Equating the two expressions for Area_k:
        // x_k^2 / (2h) = k*h / (2n)
        // x_k^2 = k*h^2 / n
        // x_k = sqrt(k*h^2 / n) = h * sqrt(k / n)
        double x_k = h * std::sqrt(static_cast<double>(k) / n);
        std::cout << x_k << (k == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

