        long long k_max = n / m;

        // Calculate the sum of last digits for one full cycle of 10 multiples
        // i.e., (m % 10) + (2m % 10) + ... + (10m % 10)
        long long cycle_sum = 0;
        for (int i = 1; i <= 10; ++i) {
            cycle_sum += (static_cast<long long>(i) * m) % 10;
        }

        // Number of full cycles of 10 multiples
        long long num_full_cycles = k_max / 10;
        long long total_sum = num_full_cycles * cycle_sum;

        // Remaining multiples after full cycles
        long long remaining_multiples = k_max % 10;
        for (long long i = 1; i <= remaining_multiples; ++i) {
            total_sum += (i * m) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

