void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // current_min_idx and current_max_idx are already initialized to pos[1].
        // The length is 1, min is 1, max is 1. So m=1 is always beautiful.

        // For m > 1, we need to expand the segment to include 'm'.
        // The segment must contain all numbers from 1 to m.
        // This means the segment must span from min(pos[1...m]) to max(pos[1...m]).
        // We maintain current_min_idx and current_max_idx as the minimum and maximum
        // indices encountered so far for numbers 1 to (m-1).
        // When considering 'm', we update these bounds to include pos[m].

        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number 'm' is beautiful if there exists a subsegment [l, r]
        // such that it contains exactly numbers 1 to m.
        // This implies:
        // 1. The minimum value in p[l...r] is 1.
        // 2. The maximum value in p[l...r] is m.
        // 3. The length of the subsegment (r - l + 1) is equal to m.

        // The smallest segment that contains all numbers from 1 to m
        // is p[current_min_idx ... current_max_idx].
        // For this segment, min value is 1 (because it contains pos[1])
        // and max value is m (because it contains pos[m] and all numbers up to m-1).
        // If this segment has length exactly 'm', then it is a permutation of 1 to m.
        // Its length is (current_max_idx - current_min_idx + 1).

        if ((current_max_idx - current_min_idx + 1) == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

