void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Check increasing part from left
    // We need a_i >= i-1 for the increasing part to be 0 < 1 < ... < i-1
    // If a_i < i-1, we cannot make it strictly increasing up to a_i.
    // The first element a_0 must be at least 0.
    // The second element a_1 must be at least 1.
    // The i-th element a_{i-1} must be at least i-1.
    // So, a_i must be at least i.
    // Let's find the maximum index `l` such that a_0, ..., a_l can form the start of a sharpened array.
    // This means a_i >= i for all i from 0 to l.
    // If a_i < i, then we cannot make a_0 < a_1 < ... < a_i.
    // So, we find the first index `l` where a_l < l.
    // All elements before `l` (i.e., a_0, ..., a_{l-1}) satisfy a_i >= i.
    int l = 0;
    while (l < n && a[l] >= l) {
        l++;
    }
    // l is now the first index where a[l] < l, or l == n if all elements satisfy a[i] >= i.
    // The valid indices for the increasing part are 0 to l-1.

    // Check decreasing part from right
    // We need a_i >= n-1-i for the decreasing part to be ... > 1 > 0.
    // If a_i < n-1-i, we cannot make it strictly decreasing from a_i to a_{n-1}.
    // The last element a_{n-1} must be at least 0.
    // The second to last a_{n-2} must be at least 1.
    // The i-th element from the end a_{n-1-i} must be at least i.
    // So, a_i must be at least n-1-i.
    // Let's find the minimum index `r` such that a_r, ..., a_{n-1} can form the end of a sharpened array.
    // This means a_i >= n-1-i for all i from r to n-1.
    // If a_i < n-1-i, then we cannot make a_i > ... > a_{n-1}.
    // So, we find the first index `r` from the right where a_r < n-1-r.
    // All elements after `r` (i.e., a_{r+1}, ..., a_{n-1}) satisfy a_i >= n-1-i.
    int r = n - 1;
    while (r >= 0 && a[r] >= (n - 1 - r)) {
        r--;
    }
    // r is now the first index from the right where a[r] < n-1-r, or r == -1 if all elements satisfy a[i] >= n-1-i.
    // The valid indices for the decreasing part are r+1 to n-1.

    // If there is an overlap between the valid increasing prefix and valid decreasing suffix,
    // it means there's at least one element `a_k` that can serve as the peak.
    // The increasing part goes up to index `l-1`.
    // The decreasing part starts from index `r+1`.
    // If `l-1 >= r+1`, it means there's at least one index `k` such that `k <= l-1` and `k >= r+1`.
    // This `k` can be the peak.
    // For such a `k`, `a_k >= k` (from left check) and `a_k >= n-1-k` (from right check).
    // This ensures that `a_k` can be made large enough to be the peak.
    // Specifically, we need `l > r`.
    // `l` is the first index that fails the left condition.
    // `r` is the first index that fails the right condition (from right to left).
    // If `l > r`, it means the "good" prefix (0 to l-1) and "good" suffix (r+1 to n-1) overlap.
    // The overlap region is `[r+1, l-1]`. Any `k` in this region can be the peak.
    // For example, if `l=3` and `r=1`:
    // Left good: `a_0, a_1, a_2` (indices 0, 1, 2)
    // Right good: `a_2, ..., a_{n-1}` (indices 2 to n-1)
    // Overlap at index 2. `l-1 = 2`, `r+1 = 2`. `l > r` (3 > 1).
    if (l > r) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

