#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <map>

char get_winning_move(char bot_move) {
    if (bot_move == 'R') return 'P';
    if (bot_move == 'S') return 'R';
    if (bot_move == 'P') return 'S';
    return ' '; // Should not happen
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        std::map<char, int> counts;
        for (char c : s) {
            counts[c]++;
        }

        char most_frequent_bot_move = ' ';
        int max_count = -1;

        // Check 'R'
        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_bot_move = 'R';
        }
        // Check 'S'
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_bot_move = 'S';
        }
        // Check 'P'
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_bot_move = 'P';
        }
        // If counts are equal, any choice is fine. The order of if statements handles this.

        char our_optimal_move = get_winning_move(most_frequent_bot_move);

        for (int i = 0; i < n; ++i) {
            std::cout << our_optimal_move;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s, t;
    std::cin >> s >> t;

    std::vector<bool> s_chars(26, false);
    for (char c : s) {
        s_chars[c - 'a'] = true;
    }

    std::vector<bool> t_chars(26, false);
    for (char c : t) {
        t_chars[c - 'a'] = true;
    }

    bool common_char_found = false;
    for (int i = 0; i < 26; ++i) {
        if (s_chars[i] && t_chars[i]) {
            common_char_found = true;
            break;
        }
    }

    if (common_char_found) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        solve();
    }
    return 0;
}

