#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
    } else {
        // We need to append at most 3 elements.
        // A strategy that always works is to append two elements.
        // Let the current sum be S and current XOR sum be X.
        // We want to find b1, b2 such that S + b1 + b2 = 2 * (X ^ b1 ^ b2).
        // Let b1 = X.
        // Then the new XOR sum becomes X ^ X ^ b2 = b2.
        // The equation becomes S + X + b2 = 2 * b2.
        // S + X = b2.
        // So, we can choose b1 = X and b2 = S + X.
        // The appended elements are X and S + X.
        // The new sum will be S + X + (S + X) = 2S + 2X.
        // The new XOR sum will be X ^ X ^ (S + X) = S + X.
        // We need 2S + 2X = 2 * (S + X), which is true.
        // This strategy always works and uses 2 elements.

        // The problem statement says "at most 3 elements".
        // The strategy above uses 2 elements.
        // The values can be large, up to 10^18.
        // current_sum can be up to 10^5 * 10^9 = 10^14.
        // current_xor_sum can be up to 2^60 approx.
        // So S + X can be up to 10^14 + 2^60, which fits in long long.

        long long b1 = current_xor_sum;
        long long b2 = current_sum + current_xor_sum;

        std::cout << 2 << std::endl;
        std::cout << b1 << " " << b2 << std::endl;
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

