int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::map<int, long long> x_counts;
    std::map<int, long long> y_counts;
    std::map<std::pair<int, int>, long long> xy_counts;

    for (int i = 0; i < n; ++i) {
        int x, y;
        std::cin >> x >> y;
        x_counts[x]++;
        y_counts[y]++;
        xy_counts[{x, y}]++;
    }

    long long total_pairs = 0;

    // Pairs with same x-coordinate
    for (auto const& [x_coord, count] : x_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Pairs with same y-coordinate
    for (auto const& [y_coord, count] : y_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Subtract pairs with same (x,y) coordinates, as they were counted twice
    // (once for same x, once for same y)
    for (auto const& [coords, count] : xy_counts) {
        if (count >= 2) {
            total_pairs -= count * (count - 1) / 2;
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w assuming all '1's

    // Step 1: Determine necessary '0's in w based on '0's in s
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // If s[i] is '0', then both w[i-x] and w[i+x] (if they exist) must be '0'.
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Step 2: Verify if the constructed w can produce s
    // For each s[i], check if it can be formed by w
    for (int i = 0; i < n; ++i) {
        bool can_be_one = false;
        // Check w[i-x]
        if (i - x >= 0 && w[i - x] == '1') {
            can_be_one = true;
        }
        // Check w[i+x]
        if (i + x < n && w[i + x] == '1') {
            can_be_one = true;
        }

        // If s[i] is '1' but our w cannot produce a '1' at s[i], then no solution exists.
        if (s[i] == '1' && !can_be_one) {
            std::cout << -1 << std::endl;
            return;
        }
        // If s[i] is '0' and our w produces a '1' at s[i], then no solution exists.
        // This case is implicitly handled by the initialization and step 1.
        // If s[i] was '0', we forced w[i-x] and w[i+x] to '0'.
        // So can_be_one would be false, matching s[i] == '0'.
    }

    std::cout << w << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

