// Function to convert a number to its parity pattern string
std::string to_parity_pattern(long long n) {
    std::string pattern_str;
    if (n == 0) {
        return "0"; // Special case for 0
    }
    while (n > 0) {
        if ((n % 10) % 2 == 0) {
            pattern_str += '0';
        } else {
            pattern_str += '1';
        }
        n /= 10;
    }
    std::reverse(pattern_str.begin(), pattern_str.end()); // Digits were extracted right-to-left, reverse to get left-to-right
    return pattern_str;
}

// Function to normalize a pattern string to a fixed length (18)
// by padding with '0's from the left.
// This is crucial because numbers up to 10^18 can have up to 19 digits,
// but the problem states pattern length is at most 18.
// A number like 10^18 (1 followed by 18 zeros) would be '100...0' (19 digits).
// The problem implies comparison up to 18 digits.
// For example, 92 (092) vs 010.
// The effective pattern for comparison should be 18 characters long.
// For a number, we extract its parity pattern.
// For a query pattern, we pad it.
// Example: 92 -> "010" (0 is even, 9 is odd, 2 is even)
// Example: 241 -> "001" (2 is even, 4 is even, 1 is odd)
// Example: 1 -> "1"
// Example: 0 -> "0"
// All these patterns need to be normalized to a fixed length for map keys.
// Since numbers are up to 10^18, they can have up to 19 digits.
// The pattern length is at most 18.
// Let's use a fixed length of 18 for the normalized pattern.
// If a number is 10^18, its parity pattern is '1' followed by 18 '0's.
// If we only consider up to 18 digits, then 10^18 would be treated as 0.
// The problem states "integer x matches the pattern s, if the parity of the i-th from the right digit in decimal notation matches the i-th from the right digit of the pattern."
// "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
// "Similarly, if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
// This means we should compare up to the maximum length of the number or pattern.
// Max number of digits for 10^18 is 19. Max pattern length is 18.
// So, we need to consider up to 19 digits.
// Let's normalize to 19 digits.
// A number like 92 (092) and pattern 010.
// Number 92: ...0000000000000000092 -> parity ...0000000000000000010
// Pattern 010: ...0000000000000000010
// They match.
// So, we need to convert the number to its 19-digit parity string.
// And the query pattern to its 19-digit parity string.

std::string get_normalized_parity_pattern(long long n) {
    std::string s_parity(19, '0'); // Max 19 digits for 10^18
    int i = 18; // Start from the rightmost position
    if (n == 0) {
        return s_parity; // All '0's for 0
    }
    while (n > 0 && i >= 0) {
        if ((n % 10) % 2 != 0) { // Odd digit
            s_parity[i] = '1';
        }
        n /= 10;
        i--;
    }
    return s_parity;
}

std::string get_normalized_query_pattern(const std::string& s) {
    std::string s_normalized(19, '0'); // Max 19 digits
    int s_len = s.length();
    for (int i = 0; i < s_len; ++i) {
        s_normalized[19 - s_len + i] = s[i];
    }
    return s_normalized;
}


int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int k = 0; k < t; ++k) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_normalized_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_normalized_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            std::cout << counts[get_normalized_query_pattern(s)] << "\n";
        }
    }

    return 0;
}

