int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int balance = 0;

    for (char c : s) {
        if (result.length() == k) {
            break;
        }

        if (c == '(') {
            if (open_count < k / 2) {
                result += '(';
                open_count++;
                balance++;
            }
        } else { // c == ')'
            if (close_count < k / 2 && balance > 0) {
                result += ')';
                close_count++;
                balance--;
            }
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = n;

    // We need k distinct differences.
    // The strategy is to generate k-1 large differences first,
    // then fill the rest of the permutation in an increasing or decreasing order
    // to generate only one new difference (or reuse an existing one).

    // Generate k-1 distinct differences using the alternating pattern
    // 1, n, 2, n-1, 3, n-2, ...
    // This generates differences: n-1, n-2, n-3, ...
    // We need k-1 such differences.
    // So we will print k-1 pairs (or k-1 elements if k is odd)
    // from this alternating pattern.

    // The first k-1 elements will be printed using the alternating pattern.
    // This will generate k-1 distinct differences: n-1, n-2, ..., n-(k-1).
    for (int i = 0; i < k; ++i) { // Loop k times to print k elements
        if (i % 2 == 0) {
            std::cout << left++ << " ";
        } else {
            std::cout << right-- << " ";
        }
    }

    // After printing k elements, we have used 'left' and 'right' pointers.
    // The remaining elements are from 'left' to 'right'.
    // To ensure no new distinct differences are introduced (other than possibly 1),
    // we print the remaining elements in increasing order.
    // This will generate only difference '1' for the remaining part.
    // If k=1, this loop is skipped, and the next loop prints 1 2 3 ... n.
    // If k > 1, the last difference generated by the alternating pattern
    // was either |(left-1) - right| or |left - (right+1)|.
    // The next element will be 'left'. The difference will be |(last_printed) - left|.
    // If last_printed was right, then diff is |right - left|.
    // If last_printed was left-1, then diff is |(left-1) - left| = 1.
    // By printing the rest in increasing order (left, left+1, ..., right),
    // all subsequent differences will be 1.
    // The only new distinct difference introduced will be 1 (if it wasn't already present).
    // The differences generated by the alternating pattern are n-1, n-2, ..., n-(k-1).
    // If k-1 < n-1, then 1 is not among these.
    // If k-1 = n-1, then all differences from 1 to n-1 are generated.
    // In either case, printing the rest in increasing order works.

    for (int i = left; i <= right; ++i) {
        std::cout << i << (i == right ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

