int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    std::vector<std::vector<int>> prefix_counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < 3; ++j) {
            prefix_counts[j][i + 1] = prefix_counts[j][i];
        }
        if (s[i] == 'x') {
            prefix_counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            prefix_counts[1][i + 1]++;
        } else { // s[i] == 'z'
            prefix_counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        if (r - l + 1 < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = prefix_counts[0][r] - prefix_counts[0][l - 1];
        int count_y = prefix_counts[1][r] - prefix_counts[1][l - 1];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l - 1];

        if (std::abs(count_x - count_y) <= 1 &&
            std::abs(count_x - count_z) <= 1 &&
            std::abs(count_y - count_z) <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    for (int p = 0; p <= 9; ++p) {
        std::string coloring(n, ' ');
        char last1 = '0' - 1; // Represents a digit smaller than any possible digit '0'
        char last2 = '0' - 1;

        bool possible_p = true;
        for (int i = 0; i < n; ++i) {
            char current_digit = s[i];
            if (current_digit < p + '0') {
                // Must be colored 1
                if (current_digit < last1) {
                    possible_p = false;
                    break;
                }
                coloring[i] = '1';
                last1 = current_digit;
            } else if (current_digit > p + '0') {
                // Must be colored 2
                if (current_digit < last2) {
                    possible_p = false;
                    break;
                }
                coloring[i] = '2';
                last2 = current_digit;
            } else { // current_digit == p + '0'
                // Can be colored 1 or 2
                // Prefer coloring 2 if it maintains sorted order for S2
                if (current_digit >= last2) {
                    coloring[i] = '2';
                    last2 = current_digit;
                } else if (current_digit >= last1) {
                    // If cannot be 2, try coloring 1
                    coloring[i] = '1';
                    last1 = current_digit;
                } else {
                    // Cannot be 1 or 2
                    possible_p = false;
                    break;
                }
            }
        }

        if (possible_p) {
            std::cout << coloring << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

