// Function to get prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that p % x == 0 and x % q != 0.
        // This means x must not be a multiple of q.
        // If x is a multiple of q, then x = k * q for some integer k.
        // We want to remove some prime factors from p such that the resulting number x is no longer divisible by q.
        // To maximize x, we should remove as few factors as possible, or rather, remove factors that result in the largest possible x.

        // Let q = f1^a1 * f2^a2 * ... * fk^ak be the prime factorization of q.
        // For x to be divisible by q, x must have at least a_i factors of f_i for all i.
        // If x is NOT divisible by q, then for at least one prime factor f_j of q,
        // x must have fewer than a_j factors of f_j.

        // We iterate through each distinct prime factor f_i of q.
        // For each f_i, we try to construct a candidate x by dividing p by f_i repeatedly
        // until p is no longer divisible by q.
        // Specifically, we find the largest power of f_i that divides p, say f_i^b_i.
        // We then divide p by f_i until p is no longer divisible by q.
        // This means we divide p by f_i until the exponent of f_i in p becomes less than its exponent in q.
        // The resulting value will be p / (f_i^k) for some k.
        // To maximize x, we want to divide p by the smallest possible power of f_i such that x is no longer divisible by q.
        // This means we divide p by f_i until the count of f_i in p is just enough to make p not divisible by q.
        // More precisely, if p = P * f_i^A and q = Q * f_i^B where P, Q are not divisible by f_i,
        // and A >= B (since p % q == 0), we want to find x = p / f_i^k such that (A-k) < B.
        // The smallest k that satisfies this is k = A - B + 1.
        // So, we divide p by f_i^(A - B + 1).

        std::vector<long long> q_prime_factors = get_prime_factors(q);
        long long max_x = 0;

        for (long long factor : q_prime_factors) {
            long long current_p = p;
            // Divide current_p by 'factor' until current_p is no longer divisible by q.
            // This means we divide current_p by 'factor' until the count of 'factor' in current_p
            // is less than its count in q.
            while (current_p % q == 0) {
                current_p /= factor;
            }
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1 = 0 means cannot move left (x-1). So target X must be >= current x.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }
            // f3 = 0 means cannot move right (x+1). So target X must be <= current x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }
            // f4 = 0 means cannot move down (y-1). So target Y must be >= current y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
            // f2 = 0 means cannot move up (y+1). So target Y must be <= current y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;
    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1}^{b-1} r
    // sum_r = (b-1) * b / 2
    // Since b can be up to 10^7, (b-1)*b can be up to 10^14, so use long long.
    // We need to perform division by 2. Since MOD is odd, 2 has a modular inverse.
    // Modular inverse of 2 modulo 10^9+7 is (10^9+7 + 1) / 2 = 500000004.
    long long sum_r_val;
    if (b == 1) { // If b=1, then r must be 0, but r must be >=1. So no valid r.
        sum_r_val = 0;
    } else {
        long long b_minus_1 = (b - 1) % MOD;
        long long b_mod = b % MOD;
        long long inv2 = 500000004; // Modular inverse of 2 mod 10^9+7
        sum_r_val = (b_minus_1 * b_mod) % MOD;
        sum_r_val = (sum_r_val * inv2) % MOD;
    }

    // Calculate sum_k_term = sum_{k=1}^{a} (k * b + 1)
    // sum_k_term = sum_{k=1}^{a} (k * b) + sum_{k=1}^{a} 1
    // sum_k_term = b * sum_{k=1}^{a} k + a
    // sum_{k=1}^{a} k = a * (a + 1) / 2
    long long sum_k_val;
    long long a_mod = a % MOD;
    long long a_plus_1_mod = (a + 1) % MOD;
    long long b_mod = b % MOD;
    long long inv2 = 500000004; // Modular inverse of 2 mod 10^9+7

    long long sum_k_arith = (a_mod * a_plus_1_mod) % MOD;
    sum_k_arith = (sum_k_arith * inv2) % MOD;

    long long term1 = (b_mod * sum_k_arith) % MOD;
    long long term2 = a_mod;

    sum_k_val = (term1 + term2) % MOD;

    // Total sum = sum_k_term * sum_r
    long long total_sum = (sum_k_val * sum_r_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <map>
#include <algorithm>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    for (size_t i = 0; i < s.length() - 1; ++i) {
        adj[s[i]].insert(s[i+1]);
        adj[s[i+1]].insert(s[i]);
    }

    bool possible = true;
    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    std::string layout = "";
    std::set<char> visited_in_layout;
    char start_char = '\0';

    // Find a starting character for a chain (degree 1 in the graph of password adjacencies)
    // Or any character if all have degree 0 or 2.
    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj.count(c) && adj[c].size() == 1) {
            start_char = c;
            break;
        }
    }

    // If no char with degree 1 found, pick any char that appears in the password
    // (this implies all chars in password have degree 2, forming cycles, or degree 0 if isolated)
    // If all chars have degree 2, it means there are multiple disjoint cycles or one large cycle.
    // We need to handle this by picking an arbitrary one.
    if (start_char == '\0') {
        for (char c = 'a'; c <= 'z'; ++c) {
            if (adj.count(c)) { // If it appeared in the password
                start_char = c;
                break;
            }
        }
    }

    // If start_char is still '\0', it means the password was empty or contained only one character.
    // The problem statement says |s| >= 1. If |s|=1, adj will be empty.
    // If |s|=1, any layout is fine.
    if (start_char == '\0') {
        std::cout << "YES\n";
        for (char c = 'a'; c <= 'z'; ++c) {
            std::cout << c;
        }
        std::cout << "\n";
        return;
    }

    // Build the layout string from start_char
    char current_char = start_char;
    char prev_char = '\0'; // To keep track of the direction in the chain

    while (current_char != '\0' && visited_in_layout.find(current_char) == visited_in_layout.end()) {
        layout += current_char;
        visited_in_layout.insert(current_char);

        char next_char = '\0';
        if (adj.count(current_char)) {
            for (char neighbor : adj[current_char]) {
                if (neighbor != prev_char) {
                    next_char = neighbor;
                    break;
                }
            }
        }
        prev_char = current_char;
        current_char = next_char;
    }

    // Check if all characters that appeared in the password are included in the layout
    // This handles cases where there might be multiple disjoint chains/cycles.
    // If current_char is not '\0' and visited_in_layout.find(current_char) != visited_in_layout.end(),
    // it means we formed a cycle. This is only valid if all characters in the password
    // are part of this single cycle.
    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj.count(c) && visited_in_layout.find(c) == visited_in_layout.end()) {
            possible = false; // Found a character from password not in the current chain/cycle
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    // Add remaining characters (those not in the password)
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

