    }

    int k = static_cast<int>(std::ceil(std::sqrt(n)));

    std::vector<int> p(n);
    int current_val = n;
    for (int i = 0; i < n; ++i) {
        int block_start = std::max(1, current_val - k + 1);
        for (int j = 0; j < k && current_val >= 1; ++j) {
            p[i + j] = current_val;
            current_val--;
        }
        i += (k - 1); // Advance i by k-1 positions as k elements were filled
    }

