#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < n; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_actual = 0; k_actual < n; ++k_actual) {
        char first_char = s[k_actual];

        std::vector<int> possible_k_values;
        for (int idx : char_indices[first_char - 'a']) {
            possible_k_values.push_back(idx);
        }

        if (possible_k_values.size() == 1) {
            total_win_prob += 1.0;
            continue;
        }

        double max_win_prob_for_this_first_char = 0.0;

        // Vasya chooses p to maximize win probability
        // p can be from 1 to n-1
        for (int p = 1; p < n; ++p) {
            std::vector<std::vector<int>> groups_by_second_char(26);
            for (int k_cand : possible_k_values) {
                char second_char = s[(p + k_cand) % n];
                groups_by_second_char[second_char - 'a'].push_back(k_cand);
            }

            double current_p_win_prob = 0.0;
            for (int i = 0; i < 26; ++i) {
                if (groups_by_second_char[i].size() == 1) {
                    current_p_win_prob += 1.0;
                }
            }
            max_win_prob_for_this_first_char = std::max(max_win_prob_for_this_first_char, current_p_win_prob);
        }
        total_win_prob += max_win_prob_for_this_first_char / possible_k_values.size();
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / n << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize current values for an input of 0 and an input of 1023
    // 1023 is (1<<10) - 1, so all bits 0-9 are 1.
    // We only care about bits 0-9.
    int current_val_if_input_is_0 = 0;
    int current_val_if_input_is_1023 = 1023;

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_val_if_input_is_0 &= x;
            current_val_if_input_is_1023 &= x;
        } else if (op_char == '|') {
            current_val_if_input_is_0 |= x;
            current_val_if_input_is_1023 |= x;
        } else if (op_char == '^') {
            current_val_if_input_is_0 ^= x;
            current_val_if_is_1023 ^= x;
        }
    }

    // Now, for each bit position j (0 to 9):
    // Let x_j be the j-th bit of the original input.
    // Let v0_j be the j-th bit of current_val_if_input_is_0.
    // Let v1_j be the j-th bit of current_val_if_input_is_1023.
    //
    // If x_j = 0, the final j-th bit is v0_j.
    // If x_j = 1, the final j-th bit is v1_j.
    //
    // We need to find a sequence of operations (AND, OR, XOR) with constants
    // that transforms x_j to v0_j when x_j=0, and to v1_j when x_j=1.
    //
    // Let's determine the combined effect for each bit:
    //
    // Case 1: v0_j = 0, v1_j = 0
    //   - If x_j = 0, result is 0.
    //   - If x_j = 1, result is 0.
    //   This means the j-th bit is always 0, regardless of x_j.
    //   This can be achieved by `& 0` for this bit.
    //
    // Case 2: v0_j = 0, v1_j = 1
    //   - If x_j = 0, result is 0.
    //   - If x_j = 1, result is 1.
    //   This means the j-th bit is unchanged (x_j).
    //   This can be achieved by `& 1` or `| 0` or `^ 0` for this bit.
    //
    // Case 3: v0_j = 1, v1_j = 0
    //   - If x_j = 0, result is 1.
    //   - If x_j = 1, result is 0.
    //   This means the j-th bit is flipped (NOT x_j).
    //   This can be achieved by `^ 1` for this bit.
    //
    // Case 4: v0_j = 1, v1_j = 1
    //   - If x_j = 0, result is 1.
    //   - If x_j = 1, result is 1.
    //   This means the j-th bit is always 1, regardless of x_j.
    //   This can be achieved by `| 1` for this bit.

    int final_and_const = 1023; // All bits 1 initially
    int final_or_const = 0;     // All bits 0 initially
    int final_xor_const = 0;    // All bits 0 initially

    for (int j = 0; j < 10; ++j) {
        int v0_j = (current_val_if_input_is_0 >> j) & 1;
        int v1_j = (current_val_if_input_is_1023 >> j) & 1;

        if (v0_j == 0 && v1_j == 0) { // Case 1: always 0
            final_and_const &= ~(1 << j); // Set j-th bit of AND constant to 0
        } else if (v0_j == 0 && v1_j == 1) { // Case 2: unchanged (x_j)
            // No change needed for AND, OR, XOR constants for this bit
            // (final_and_const has 1, final_or_const has 0, final_xor_const has 0)
        } else if (v0_j == 1 && v1_j == 0) { // Case 3: flipped (NOT x_j)
            final_xor_const |= (1 << j); // Set j-th bit of XOR constant to 1
        } else { // v0_j == 1 && v1_j == 1 (Case 4: always 1)
            final_or_const |= (1 << j); // Set j-th bit of OR constant to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_const != 1023) { // If any bit needs to be forced to 0
        result_ops.push_back({'&', final_and_const});
    }
    if (final_or_const != 0) { // If any bit needs to be forced to 1
        result_ops.push_back({'|', final_or_const});
    }
    if (final_xor_const != 0) { // If any bit needs to be flipped
        result_ops.push_back({'^', final_xor_const});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;
        long long abs_n = std::abs(n);
        long long abs_m = std::abs(m);

        long long min_coord = std::min(abs_n, abs_m);
        long long max_coord = std::max(abs_n, abs_m);

        if (k < max_coord) {
            std::cout << -1 << "\n";
            continue;
        }

        long long ans = min_coord; // Initial diagonal moves to cover min_coord in both dimensions
        long long remaining_k = k - min_coord;
        long long remaining_max_coord = max_coord - min_coord;

        // After min_coord diagonal moves, we are at (min_coord, min_coord) or equivalent,
        // and need to reach (max_coord, min_coord) or (min_coord, max_coord) in remaining_max_coord moves
        // and then (max_coord, max_coord) in remaining_k moves.
        // Effectively, we need to cover remaining_max_coord distance in one dimension.
        // This takes remaining_max_coord straight moves.
        // After these moves, we are at (max_coord, min_coord) or (min_coord, max_coord)
        // and have remaining_k - remaining_max_coord moves left.
        // The current position is (max_coord, max_coord) relative to (0,0) if we consider the path.
        // The total distance covered is max_coord.
        // The number of moves used is max_coord.
        // The remaining moves are k - max_coord.

        // Now we are at (max_coord, max_coord) (conceptually, after max_coord moves)
        // and have k - max_coord moves left.
        // Each pair of moves (e.g., (1,0) then (-1,0) or (1,1) then (-1,-1)) can be used to
        // consume 2 moves without changing the final position.
        // We want to maximize diagonal moves.
        // A pair of moves like (1,0) and (0,1) can be replaced by (1,1) and (0,0) (not allowed)
        // or (1,0) and (0,1) can be replaced by (1,1) and (0,0) (not allowed)
        // A pair of moves (1,0) and (1,0) can be replaced by (1,1) and (1,-1) (2 diagonal moves)
        // A pair of moves (1,0) and (0,1) can be replaced by (1,1) and (0,0) (not allowed)
        // A pair of moves (1,0) and (0,1) can be replaced by (1,1) and (0,0) (not allowed)

        // The parity of (N+M) and K must be the same.
        // Each move changes (x+y) by -2, -1, 0, 1, or 2.
        // So, (x_new + y_new) - (x_old + y_old) has the same parity as (x_new - x_old) + (y_new - y_old).
        // This means (x_new + y_new) and (x_old + y_old) have the same parity if the move is diagonal (dx, dy both non-zero, so dx+dy is even).
        // And different parity if the move is non-diagonal (one of dx, dy is zero, so dx+dy is odd).
        // This is incorrect.
        // (x_new + y_new) - (x_old + y_old) = dx + dy.
        // If dx, dy are both non-zero (diagonal), then dx, dy are 1 or -1. So dx+dy is 0 or 2 or -2 (even).
        // If one of dx, dy is zero (non-diagonal), then dx+dy is 1 or -1 (odd).
        // So, a diagonal move preserves the parity of (x+y).
        // A non-diagonal move flips the parity of (x+y).
        // To reach (N, M) from (0,0) in K moves:
        // (N+M) must have the same parity as (0+0) + (number of non-diagonal moves) * 1 (mod 2).
        // (N+M) % 2 == (K - num_diagonal_moves) % 2.
        // (N+M) % 2 == (K % 2 - num_diagonal_moves % 2 + 2) % 2.
        // This means (N+M) and K must have the same parity if num_diagonal_moves is even.
        // And different parity if num_diagonal_moves is odd.
        // This is not useful for maximizing diagonal moves.

        // A simpler parity argument:
        // The sum of coordinates (x+y) changes by an even amount for a diagonal move (e.g., (1,1) -> +2, (1,-1) -> 0).
        // The sum of coordinates (x+y) changes by an odd amount for a non-diagonal move (e.g., (1,0) -> +1, (0,-1) -> -1).
        // Let D be the number of diagonal moves and S be the number of straight (non-diagonal) moves.
        // K = D + S.
        // The final (N+M) must have the same parity as S.
        // So, (N+M) % 2 == S % 2.
        // (N+M) % 2 == (K - D) % 2.
        // If (N+M) % 2 != K % 2, then D must be odd.
        // If (N+M) % 2 == K % 2, then D must be even.

        // We have used max_coord moves to reach (max_coord, max_coord) (conceptually).
        // The remaining moves are k - max_coord.
        // Each of these remaining moves must be "cancelled out" to stay at (max_coord, max_coord).
        // For example, move (1,0) then (-1,0). This uses 2 moves, changes position by (0,0).
        // Or move (1,1) then (-1,-1). This uses 2 moves, changes position by (0,0).
        // We want to maximize diagonal moves among these remaining k - max_coord moves.
        // Each pair of moves can be made diagonal: (1,0) and (-1,0) are 0 diagonal.
        // (1,1) and (-1,-1) are 2 diagonal.
        // So, we can add 2 diagonal moves for every 2 remaining moves.
        // The maximum number of diagonal moves we can add is 2 * floor((k - max_coord) / 2).
        // So, ans = max_coord + 2 * floor((k - max_coord) / 2).

        // Let's check the parity condition.
        // The target (abs_n, abs_m) has sum abs_n + abs_m.
        // The total moves is k.
        // If (abs_n + abs_m) % 2 != k % 2, it means we need an odd number of straight moves.
        // Or, equivalently, an odd number of moves that flip the parity of (x+y).
        // If (abs_n + abs_m) % 2 == k % 2, we need an even number of such moves.

        // Consider the state after max_coord moves.
        // We are at (max_coord, max_coord) (conceptually).
        // The sum of coordinates is 2 * max_coord.
        // The number of moves used is max_coord.
        // The parity of (2*max_coord) is 0.
        // The parity of max_coord is max_coord % 2.
        // If (max_coord % 2) != 0, then we used an odd number of straight moves.
        // If (max_coord % 2) == 0, then we used an even number of straight moves.

        // The final (abs_n + abs_m) must have the same parity as (k - D).
        // (abs_n + abs_m) % 2 == (k - D) % 2.
        // This means D % 2 == (k - (abs_n + abs_m)) % 2.

        // The maximum possible diagonal moves is k.
        // If k is the number of moves, and we want to reach (N,M).
        // We need at least max(N,M) moves.
        // If k < max(N,M), impossible.
        // Otherwise, we can reach (N,M) in max(N,M) moves.
        // The remaining k - max(N,M) moves must be "wasted".
        // Each wasted move must be paired with another move to cancel out its effect on the final position.
        // E.g., (1,0) then (-1,0). This uses 2 moves, 0 diagonal.
        // E.g., (1,1) then (-1,-1). This uses 2 moves, 2 diagonal.
        // So, for every 2 wasted moves, we can add 2 diagonal moves.
        // The number of diagonal moves is max(N,M) + 2 * floor((k - max(N,M)) / 2).
        // This is the maximum possible number of diagonal moves if parity allows.

        long long current_diag_moves = max_coord;
        long long current_k = max_coord;

        // Now we have k - current_k moves remaining.
        // We are at (max_coord, max_coord) (conceptually).
        // We need to end at (max_coord, max_coord).
        // Each pair of remaining moves can be (1,1) and (-1,-1) to add 2 diagonal moves.
        // Or (1,0) and (-1,0) to add 0 diagonal moves.
        // Or (1,0) and (0,1) to add 0 diagonal moves.
        // The maximum number of diagonal moves we can add is 2 * ((k - current_k) / 2).
        current_diag_moves += 2 * ((k - current_k) / 2);
        current_k += 2 * ((k - current_k) / 2);

        // Now, if k > current_k, it means k - current_k is 1.
        // We have one move left.
        // If we are at (max_coord, max_coord) and need to end at (max_coord, max_coord),
        // and we have 1 move left, it's impossible.
        // This means if (k - max_coord) is odd, we have an issue.
        // If (k - max_coord) is odd, we have one move left after pairing up (k - max_coord - 1) moves.
        // This one move must be cancelled out.
        // E.g., if we are at (X,Y) and need to end at (X,Y) in 1 move, impossible.
        // So, if (k - max_coord) is odd, we must adjust.
        // This means we cannot use the strategy of adding 2 diagonal moves for every 2 remaining moves.
        // We need to change one of the previous pairs of moves.
        // Instead of (1,1) and (-1,-1) (2 diag), we could do (1,0) and (-1,0) (0 diag).
        // This reduces diagonal moves by 2.
        // So, if (k - max_coord) is odd, we must reduce the total diagonal moves by 2.
        // This is equivalent to saying:
        // If (k - max_coord) % 2 == 1:
        //   ans = max_coord + 2 * ((k - max_coord - 1) / 2) - 2
        //   ans = max_coord + (k - max_coord - 1) - 2
        //   ans = k - 3
        // If (k - max_coord) % 2 == 0:
        //   ans = max_coord + 2 * ((k - max_coord) / 2)
        //   ans = max_coord + (k - max_coord)
        //   ans = k

        // Let's re-evaluate the parity condition.
        // The final position (abs_n, abs_m) has sum abs_n + abs_m.
        // The starting position (0,0) has sum 0.
        // Each diagonal move changes (x+y) by an even amount (0, 2, -2).
        // Each non-diagonal move changes (x+y) by an odd amount (1, -1).
        // Let D be the number of diagonal moves and S be the number of non-diagonal moves.
        // K = D + S.
        // The parity of (abs_n + abs_m) must be equal to the parity of S.
        // (abs_n + abs_m) % 2 == S % 2
        // (abs_n + abs_m) % 2 == (K - D) % 2

        // We want to maximize D.
        // The maximum possible D is K.
        // If D = K, then S = 0.
        // This requires (abs_n + abs_m) % 2 == 0.
        // If (abs_n + abs_m) % 2 == 0, then we can potentially achieve D = K.
        // If (abs_n + abs_m) % 2 != 0, then we cannot achieve D = K (since S must be odd).
        // In this case, D must be K-1 (if K-1 is odd) or K-2 (if K-1 is even).
        // So, if (abs_n + abs_m) % 2 != K % 2, then D must be odd.
        // If (abs_n + abs_m) % 2 == K % 2, then D must be even.

        // Let's calculate the maximum possible diagonal moves without parity constraints:
        // It's max_coord + 2 * ((k - max_coord) / 2).
        // This simplifies to k if (k - max_coord) is even.
        // This simplifies to k - 1 if (k - max_coord) is odd.
        // Let's call this `potential_D`.

        long long potential_D;
        if ((k - max_coord) % 2 == 0) {
            potential_D = k;
        } else {
            potential_D = k - 1;
        }

        // Now check if `potential_D` satisfies the parity condition:
        // (abs_n + abs_m) % 2 == (k - potential_D) % 2.
        // If it does, then `potential_D` is the answer.
        // If it doesn't, we need to adjust `potential_D` to satisfy the parity.
        // This means we need to change the parity of `potential_D`.
        // To change the parity of `potential_D`, we must change it by an odd number.
        // The smallest change is 1. But we can only change D by 2 (e.g., replace (1,1) and (-1,-1) with (1,0) and (-1,0)).
        // So, if `potential_D` doesn't satisfy the parity, we must reduce it by 2.

        // Let's check the parity of (k - potential_D).
        // If (k - max_coord) is even: potential_D = k. Then (k - potential_D) = 0 (even).
        // If (k - max_coord) is odd: potential_D = k - 1. Then (k - potential_D) = 1 (odd).
        // So, (k - potential_D) % 2 == (k - max_coord) % 2.
        // The condition becomes: (abs_n + abs_m) % 2 == (k - max_coord) % 2.

        if ((abs_n + abs_m) % 2 == (k - max_coord) % 2) {
            std::cout << potential_D << "\n";
        } else {
            // If parities don't match, we need to reduce potential_D by 2.
            // This is because we need to change the parity of (k - D).
            // If (k - D) is currently X, and we need it to be Y, where X % 2 != Y % 2.
            // We need to change D by an odd amount. The smallest change is 1.
            // But we can only change D by 2 (e.g., replace two diagonal moves with two straight moves).
            // So, we reduce D by 2.
            std::cout << potential_D - 2 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <numeric>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long count = 0;

    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // For substrings starting with '0', the value f(s_l...s_r) is at most r-l.
            // The length is r-l+1.
            // So, f(s_l...s_r) <= r-l < r-l+1.
            // This means f(s_l...s_r) can never be equal to r-l+1 if s_l = '0'
            // UNLESS the value is 0.
            // If f(s_l...s_r) = 0, then all characters must be '0'.
            // In this case, length = r-l+1.
            // So, r-l+1 = 0, which is impossible for a non-empty string.
            // Therefore, no good substring can start with '0' and have a non-zero length.
            // The only exception is if the problem implies f(0) = 0, length 1.
            // Example: f(000) = 0. If s_l...s_r = "0", length 1, f("0") = 0. 1 != 0.
            // So, a substring "0" is not good.
            // This means we only need to consider substrings starting with '1' for the main logic.
            // However, the problem statement example f(000) = 0.
            // If s_l...s_r = "0", length is 1. f("0") = 0. 1 != 0.
            // If s_l...s_r = "00", length is 2. f("00") = 0. 2 != 0.
            // If s_l...s_r = "000", length is 3. f("000") = 0. 3 != 0.
            // So, substrings consisting only of '0's are never good.
            // This simplifies things: we only need to consider substrings that contain at least one '1'.
            // And if they contain a '1', the value will be positive.
            // If s[i] == '0', it can be a leading zero for a value that starts with '1' later.
            // Example: s = "0110", s[0...2] = "011". length = 3. f("011") = 3. This is good.
            // So, we must iterate through all possible starting positions.
            // The logic for `val` and `len` below handles leading zeros correctly.
        }

        long long current_val = 0;
        // Max length for current_val to be within reasonable bounds (e.g., 2^60)
        // If length is 60, 2^60 is huge.
        // Max length of string is 2e5.
        // If current_val is 20, then 2^20 is ~1e6.
        // If current_val is 60, then 2^60 is ~1e18.
        // If current_val is 18, then 2^18 is ~2.6e5.
        // So, we can iterate up to about 18-20 characters to the right of 'i'
        // before current_val exceeds the maximum possible length of the string (2e5).
        // If current_val exceeds 2e5, it can never be equal to r-l+1, because r-l+1 <= 2e5.
        // So, we can limit the inner loop.
        // The maximum length of a substring is N.
        // If f(sub) > N, it cannot be good.
        // N_max = 2e5. log2(2e5) approx 17.6.
        // So, if a substring has length > 18, its value can exceed N.
        // We can iterate up to about 18-20 characters to the right of 'i'.
        // Let's say we check up to 20 characters.
        // For each i, we check j from i to min(n-1, i+19).
        // This is O(N * 20).
        // What about longer substrings?
        // If s[i] is '1', and we have a long string of '0's after it, e.g., "10000000000000000000".
        // The value is 2^k. The length is k+1.
        // We need k+1 = 2^k. This only holds for k=0 (1=1) and k=1 (2=2).
        // For k=0, "1", length 1, value 1. Good.
        // For k=1, "10", length 2, value 2. Good.
        // For k=2, "100", length 3, value 4. Not good.
        // For k > 1, 2^k grows much faster than k+1. So 2^k > k+1.
        // So, for substrings starting with '1' followed by many '0's, only "1" and "10" are good.

        // Let's refine the loop limit.
        // The maximum possible length of a substring is N.
        // If current_val > N, it cannot be equal to r-l+1.
        // So, we can stop extending the substring if current_val exceeds N.
        // Also, if current_val becomes very large, it will quickly exceed N.
        // The maximum value of N is 2e5.
        // 2^17 = 131072
        // 2^18 = 262144
        // So, if a substring has length 18, its value can be up to 2^18-1.
        // If it has length 19, its value can be up to 2^19-1.
        // This means we only need to check substrings of length up to about 18-20 characters.
        // Let's use a constant `MAX_CHECK_LEN` for the inner loop.
        // If `current_val` exceeds `n`, we can break.
        // The maximum length of a substring is `n`.
        // If `current_val` exceeds `n`, it can't be equal to `r-l+1` (which is at most `n`).
        // So, we can limit the inner loop to `j` such that `j-i+1` is not too large.
        // `j-i+1` is the length.
        // If `j-i+1` is around 20, `current_val` can be up to `2^20 - 1` which is ~10^6.
        // This is larger than `n` (2e5).
        // So, we can iterate `j` from `i` up to `min(n-1, i + MAX_BITS - 1)`.
        // `MAX_BITS` should be around `log2(N_max) + C`. Let's say 20.
        const int MAX_BITS = 20; // log2(2e5) is approx 17.6. So 18-20 bits are enough.

        for (int j = i; j < n; ++j) {
            int len = j - i + 1;
            if (len > MAX_BITS && s[i] == '0') {
                // If s[i] is '0', and len > MAX_BITS, then current_val will be 0
                // if all subsequent chars are '0' up to j.
                // If there's a '1' later, say at k, then current_val will be at least 2^(j-k).
                // If j-k is large, current_val will be large.
                // If s[i] is '0', and len > MAX_BITS, and current_val is still 0,
                // then len (which is > MAX_BITS) cannot be equal to 0.
                // If s[i] is '0', and len > MAX_BITS, and current_val is non-zero,
                // then current_val must be at least 2^(len - (first_one_pos - i) - 1).
                // This is getting complicated. Let's simplify.
                // The value `current_val` can grow very quickly.
                // If `current_val` exceeds `n`, it can never be equal to `len` (which is at most `n`).
                // So, we can break early if `current_val > n`.
                // This is the most robust check.
            }

            current_val = (current_val << 1) | (s[j] - '0');

            if (current_val > n) { // Optimization: if value exceeds max possible length, it can't be good.
                // This check is crucial.
                // If s[i] is '0', current_val might stay 0 for a long time.
                // If current_val is 0, and len > 0, then len != current_val.
                // So, if current_val is 0, we can continue.
                // If current_val is non-zero and > n, we can break.
                if (current_val > 0) break; // Only break if it's a positive value that's too large.
            }

            if (current_val == len) {
                count++;
            }
        }
    }
    std::cout << count << std::endl;
}

