#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial balance for the right half (jars n+1 to 2n)
    // Balance = (count of 1s) - (count of 2s)
    // We are interested in the balance of the remaining jars.
    // Let's define balance_val = (count of 1s) - (count of 2s)
    // If we remove `k` jars, and the remaining jars have balance `B_rem`,
    // then `S_rem - B_rem = B_rem`. We want `B_rem = 0`.
    // This means `S_rem = B_rem`.

    // Calculate prefix sums for balance.
    // For a[i] = 1, add 1. For a[i] = 2, subtract 1.
    // The balance of a segment [i, j] is prefix_balance[j] - prefix_balance[i-1].

    // Calculate total balance of all 2n jars
    int total_balance = 0;
    for (int x : a) {
        if (x == 1) total_balance++;
        else total_balance--;
    }

    // Map to store the first occurrence of a balance value for the left half (jars 1 to n)
    // key: balance value, value: number of jars removed from left (n - index)
    // The balance is calculated from right to left for the left half.
    // `left_balance_map[b]` stores the minimum `k_L` such that removing `k_L` jars from the left
    // (i.e., keeping jars from `k_L+1` to `n`) results in a balance `b` for the remaining left jars.
    // The balance `b` here is `(count of 1s) - (count of 2s)` for jars `k_L+1` to `n`.
    std::map<int, int> left_balance_map;
    left_balance_map[0] = 0; // If 0 jars are removed from left, balance is 0.

    int current_balance_left = 0;
    for (int i = n - 1; i >= 0; --i) { // Iterate from jar n down to jar 1
        if (a[i] == 1) current_balance_left++;
        else current_balance_left--;
        if (left_balance_map.find(current_balance_left) == left_balance_map.end()) {
            left_balance_map[current_balance_left] = n - i; // n - i jars removed from left
        }
    }

    // Initialize minimum jars to remove.
    // If total_balance is already 0, 0 jars need to be removed.
    int min_removed_jars = 2 * n; // Max possible value

    // Check the case where only jars from the left are removed, or no jars from right.
    // If we remove `k_L` jars from the left, the remaining jars are `a[k_L]` to `a[2n-1]`.
    // The balance of these remaining jars is `total_balance - current_balance_left_removed`.
    // We want this to be 0. So `total_balance = current_balance_left_removed`.
    // `current_balance_left_removed` is the balance of jars `a[0]` to `a[k_L-1]`.
    // This is equivalent to `current_balance_left` in our map, but with opposite sign.
    // The balance `current_balance_left` in `left_balance_map` is for jars `a[i]` to `a[n-1]`.
    // So, if we remove `k_L` jars from the left, the balance of these `k_L` jars is `current_balance_left`
    // where `k_L = n - i`.
    // The total balance of remaining jars `a[k_L]` to `a[2n-1]` should be 0.
    // This means `(total_balance of all 2n jars) - (balance of first k_L jars) = 0`.
    // `balance of first k_L jars` is `current_balance_left` from the map, but for `a[0]` to `a[k_L-1]`.
    // The `left_balance_map` stores `current_balance_left` for `a[i]` to `a[n-1]`.
    // So, if we remove `k_L` jars from the left, the remaining jars are `a[k_L]` to `a[2n-1]`.
    // The balance of these remaining jars is `total_balance - (balance of first k_L jars)`.
    // We want `total_balance - (balance of first k_L jars) = 0`.
    // This means `balance of first k_L jars = total_balance`.
    // The `left_balance_map` stores `balance of jars a[i]...a[n-1]` and `n-i` jars removed.
    // This is not directly useful for `balance of first k_L jars`.

    // Let's re-evaluate.
    // We want the final remaining segment `a[k_L]` to `a[2n-1-k_R]` to have balance 0.
    // `k_L` jars removed from left, `k_R` jars removed from right.
    // Total jars removed = `k_L + k_R`.
    // The balance of the segment `a[k_L]` to `a[2n-1-k_R]` is `0`.
    // This means `(balance of all 2n jars) - (balance of first k_L jars) - (balance of last k_R jars) = 0`.
    // `balance of first k_L jars` is `prefix_balance[k_L-1]`.
    // `balance of last k_R jars` is `(total_balance) - (prefix_balance[2n-1-k_R])`.
    // This is getting complicated.

    // Let's use the definition:
    // `current_balance_left` is the balance of jars `a[i]` to `a[n-1]`.
    // `k_L = n - i` is the number of jars removed from the left.
    // `left_balance_map[b]` stores `k_L` such that `balance(a[n-k_L]...a[n-1]) = b`.
    // This is the balance of the *kept* jars in the left half.
    // No, this is the balance of the *removed* jars from the left.
    // `current_balance_left` is the balance of `a[n-1]` down to `a[i]`.
    // `n-i` is the count of jars `a[i], ..., a[n-1]`.
    // So `left_balance_map[b]` stores `k_L` such that `balance(a[n-k_L]...a[n-1]) = b`.
    // This means `k_L` jars are removed from the left, and their balance is `b`.
    // The remaining jars are `a[k_L]` to `a[2n-1]`.
    // The balance of the remaining jars is `total_balance - b`.
    // We want this to be 0. So `b = total_balance`.
    // If `left_balance_map` contains `total_balance`, then `min_removed_jars = std::min(min_removed_jars, left_balance_map[total_balance])`.

    // Let's define `balance_prefix[i]` as the balance of `a[0]` to `a[i-1]`. `balance_prefix[0]=0`.
    // `balance_suffix[i]` as the balance of `a[i]` to `a[2n-1]`. `balance_suffix[2n]=0`.

    // `left_balances[k]` stores the balance of the first `k` jars (a[0]...a[k-1]).
    // `left_balances[0] = 0`.
    // `left_balances[k]` for `k=1...n`.
    std::vector<int> left_balances(n + 1);
    left_balances[0] = 0;
    for (int i = 0; i < n; ++i) {
        left_balances[i+1] = left_balances[i] + (a[i] == 1 ? 1 : -1);
    }

    // `right_balances[k]` stores the balance of the last `k` jars (a[2n-k]...a[2n-1]).
    // `right_balances[0] = 0`.
    // `right_balances[k]` for `k=1...n`.
    std::vector<int> right_balances(n + 1);
    right_balances[0] = 0;
    for (int i = 0; i < n; ++i) {
        right_balances[i+1] = right_balances[i] + (a[2*n - 1 - i] == 1 ? 1 : -1);
    }

    // We want to find `k_L` jars removed from left and `k_R` jars removed from right
    // such that the remaining jars `a[k_L]` to `a[2n-1-k_R]` have a balance of 0.
    // The balance of these remaining jars is:
    // `total_balance - (balance of first k_L jars) - (balance of last k_R jars)`
    // `total_balance - left_balances[k_L] - right_balances[k_R] = 0`
    // `left_balances[k_L] + right_balances[k_R] = total_balance`

    // Iterate over all possible `k_L` (number of jars removed from left, 0 to n)
    // For each `k_L`, we know `left_balances[k_L]`.
    // We need to find `k_R` such that `right_balances[k_R] = total_balance - left_balances[k_L]`.
    // We want to minimize `k_L + k_R`.

    // Store `right_balances` values and their minimum `k_R` in a map for quick lookup.
    std::map<int, int> right_balance_to_kR;
    for (int k_R = 0; k_R <= n; ++k_R) {
        if (right_balance_to_kR.find(right_balances[k_R]) == right_balance_to_kR.end()) {
            right_balance_to_kR[right_balances[k_R]] = k_R;
        }
    }

    min_removed_jars = 2 * n; // Initialize with maximum possible

    for (int k_L = 0; k_L <= n; ++k_L) {
        int target_right_balance = total_balance - left_balances[k_L];
        if (right_balance_to_kR.count(target_right_balance)) {
            int k_R = right_balance_to_kR[target_right_balance];
            min_removed_jars = std::min(min_removed_jars, k_L + k_R);
        }
    }

    std::cout << min_removed_jars << std::endl;
}

