        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y to prevent overflow
using ll = long long;

// Memoization table for results:
// dp[x][parity] stores the pair {final_x, final_y} if starting from x with given parity
// parity 0: after step 2 (x = x + a[x], y = y + a[x])
// parity 1: after step 3 (x = x - a[x], y = y + a[x])
// We only need to store the result for the state *before* the next step 2.
// So, dp[x] stores {final_x, final_y} if starting from x and performing step 2, then step 3, then recursively.
// The final_y stored is the *additional* y accumulated from this point onwards.
// The final_x stored is the x value *after* the sequence of operations.
// A special value (e.g., -2 for x) can indicate an infinite loop.
std::vector<std::pair<ll, ll>> dp;
std::vector<bool> visited; // To detect cycles

int N;
std::vector<ll> A_orig; // Stores a_2, ..., a_n

// Function to solve for a given starting x and a[1]
// Returns {final_x, final_y} relative to the start of this call
std::pair<ll, ll> solve(ll current_x, ll a1_val) {
    // Base cases for termination
    if (current_x <= 0 || current_x > N) {
        return {current_x, 0}; // Terminated, no additional y
    }

    // Check memoization table
    // The dp table is indexed by current_x - 1
    if (dp[current_x - 1].first != 0) { // 0 means not computed yet, -2 means cycle
        return dp[current_x - 1];
    }
    if (visited[current_x - 1]) { // Cycle detected
        return {-2, -2}; // Special value for infinite loop
    }

    visited[current_x - 1] = true; // Mark as currently visiting

    ll val;
    if (current_x == 1) {
        val = a1_val;
    } else {
        val = A_orig[current_x - 2]; // A_orig stores a_2 at index 0, a_3 at index 1, etc.
    }

    // Step 2: x = x + val, y = y + val
    ll next_x_after_step2 = current_x + val;
    ll y_accumulated = val;

    // Check termination after step 2
    if (next_x_after_step2 <= 0 || next_x_after_step2 > N) {
        visited[current_x - 1] = false; // Unmark
        return dp[current_x - 1] = {next_x_after_step2, y_accumulated};
    }

    // Step 3: x = x - val, y = y + val
    ll next_x_after_step3 = next_x_after_step2 - val;
    y_accumulated += val;

    // Check termination after step 3
    if (next_x_after_step3 <= 0 || next_x_after_step3 > N) {
        visited[current_x - 1] = false; // Unmark
        return dp[current_x - 1] = {next_x_after_step3, y_accumulated};
    }

    // Recursive call for the next state
    std::pair<ll, ll> res = solve(next_x_after_step3, a1_val);

    // If infinite loop detected in recursive call
    if (res.first == -2) {
        visited[current_x - 1] = false; // Unmark
        return dp[current_x - 1] = {-2, -2};
    }

    // Combine results
    visited[current_x - 1] = false; // Unmark
    return dp[current_x - 1] = {res.first, y_accumulated + res.second};
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;

    A_orig.resize(N - 1);
    for (int i = 0; i < N - 1; ++i) {
        std::cin >> A_orig[i];
    }

    // For each i from 1 to N-1, set a[1] = i
    for (ll i = 1; i < N; ++i) {
        // Reset DP table and visited array for each new a[1]
        dp.assign(N, {0, 0}); // {0,0} indicates not computed
        visited.assign(N, false);

        // Initial state: x = 1, y = 0
        // The solve function calculates the *additional* y from x=1 onwards.
        // The initial y is 0.
        std::pair<ll, ll> result = solve(1, i);

        if (result.first == -2) { // Infinite loop
            std::cout << -1 << "\n";
        } else {
            std::cout << result.second << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
