int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());

    int count = 0;
    int j = 0; // Pointer for the elements we are trying to place (the 'b' array elements)
    for (int i = 0; i < n; ++i) { // Pointer for the original positions (the 'a' array elements)
        // We are trying to find an element a[j] from the sorted array
        // to place at position i (which originally held a[i])
        // such that a[j] > a[i].
        // Since both a[i] and a[j] are from the sorted array,
        // we want to find the smallest a[j] that is greater than a[i]
        // to maximize our chances for subsequent elements.
        // This is equivalent to finding an a[j] such that a[j] > a[i]
        // and using it.
        // We can use two pointers.
        // 'i' iterates through the sorted 'a' array, representing the original values.
        // 'j' iterates through the sorted 'a' array, representing the values we can pick for permutation.
        // We try to match a[j] with a[i].
        // If a[j] > a[i], we found a valid pair. Increment count and advance both pointers.
        // If a[j] <= a[i], a[j] is too small for a[i]. We need a larger element for a[i],
        // so we advance 'j' to look for a larger element. 'i' stays put.

        if (a[j] > a[i]) {
            count++;
            j++; // Move to the next element to be placed
        } else {
            // a[j] <= a[i], so a[j] cannot be placed at position i to satisfy the condition.
            // We need a larger element for position i.
            // So, we advance j to consider the next available element from the sorted array.
            // The element a[i] is still waiting for a suitable larger element.
            // However, the logic should be:
            // We are trying to match a[i] (from the original positions) with a[j] (from the elements available for permutation).
            // If a[j] > a[i], we can make a match. We increment count and use both a[i] and a[j].
            // If a[j] <= a[i], a[j] is not large enough for a[i]. We must try a larger element for a[i].
            // So we advance j, but i stays.
            // This means j will always be >= i.
            // The correct two-pointer approach is:
            // i points to the current element in the sorted array that we want to "beat".
            // j points to the current element in the sorted array that we are trying to use to "beat" a[i].
            // Both i and j start at 0.
            // If a[j] > a[i], we found a pair (a[i], a[j]) where a[j] can be placed at a position that originally held a[i].
            // We increment count, and advance both i and j, as both elements are "used".
            // If a[j] <= a[i], a[j] is not large enough to beat a[i]. We need a larger element.
            // So we advance j, hoping to find a larger element. i stays put, waiting for a suitable match.
