                    return false; // Cannot make a[i] >= prev_val
                }
                // Else, current_a + x >= prev_val. We can make a[i] become prev_val.
                // prev_val remains prev_val.
            } else { // current_a + x >= m, wrap-around happens
                // The values available are [current_a, m-1] and [0, (current_a+x)%m].
                // We need to find a value >= prev_val.
                // If (current_a+x)%m < prev_val, it means all values after wrap-around are too small.
                // And values from current_a to m-1 are also too small (since current_a < prev_val).
                // So it's impossible.
                if ((current_a + x) % m < prev_val) {
                    return false; // Cannot make a[i] >= prev_val
                }
                // Else, (current_a+x)%m >= prev_val. We can make a[i] become prev_val.
                // prev_val remains prev_val.
            }
        }
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> b(n, LLONG_MAX); // b[i] stores max_val - current_delta[i]
                                          // which is an upper bound for initial_a[i]

    // Simulate operations in reverse to find upper bounds for initial_a[i]
    // For type 2 operations, m_i is the maximum of a_j.
    // So, a_j <= m_i for all j in [l_i, r_i].
    // This means initial_a[j] + current_delta[j] <= m_i.
    // So, initial_a[j] <= m_i - current_delta[j].
    // We want to find the tightest upper bound for initial_a[j], so we take the minimum of these.
    // For type 1 operations, they don't directly impose upper bounds on initial_a[i],
    // but they change current_delta, which affects subsequent type 2 operations.
    // We need to apply deltas in reverse.

    std::vector<long long> current_delta(n, 0); // current_delta[i] stores sum of d's applied to a[i]
                                                // from operations *after* the current one in reverse pass.

    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // This is an add operation. When going in reverse, it means this delta
            // was applied *before* the current state. So, to get to the state before this op,
            // we subtract this delta.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] -= ops[i].val;
            }
        } else { // type == 2
            // This is a max query. It implies initial_a[j] + current_delta[j] <= ops[i].val
            // for all j in [ops[i].l, ops[i].r].
            // So, initial_a[j] <= ops[i].val - current_delta[j].
            // We update b[j] with the minimum of its current value and this new upper bound.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] = std::min(b[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // Initialize initial_a based on the derived upper bounds.
    // To satisfy initial_a[i] <= 10^9, we can just use b[i] if it's not LLONG_MAX.
    // If b[i] is LLONG_MAX, it means no type 2 operation constrained this element.
    // In this case, we can set initial_a[i] to 0 (or any value within [-10^9, 10^9]).
    // The problem states |a_i| <= 10^9.
    // If b[i] is LLONG_MAX, we can set initial_a[i] = 0.
    // If b[i] is not LLONG_MAX, we must use a value <= b[i].
    // To maximize chances of satisfying max constraints, we should pick initial_a[i] = b[i].
    // However, we also need to ensure |initial_a[i]| <= 10^9.
    // If b[i] > 10^9, we can cap it at 10^9.
    // If b[i] < -10^9, then it's impossible to satisfy |initial_a[i]| <= 10^9 and initial_a[i] <= b[i].
    // But this check is done later. For now, let's just use b[i] as the candidate initial_a[i].
    // If b[i] is LLONG_MAX, we can set it to 10^9 to satisfy the |a_i| <= 10^9 constraint.
    // Or simply 0, as it's a valid value. Let's use 0 for unconstrained elements.

    std::vector<long long> initial_a(n);
    for (int i = 0; i < n; ++i) {
        if (b[i] == LLONG_MAX) {
            initial_a[i] = 0; // Unconstrained, pick 0
        } else {
            initial_a[i] = b[i]; // Use the tightest upper bound
        }
        // Ensure |initial_a[i]| <= 10^9
        if (initial_a[i] > 1000000000LL) initial_a[i] = 1000000000LL;
        if (initial_a[i] < -1000000000LL) initial_a[i] = -1000000000LL;
    }

    // Now, simulate operations forward with the constructed initial_a
    // and verify all type 2 constraints.

    std::vector<long long> current_a = initial_a;
    std::vector<long long> current_prefix_sum_delta(n + 1, 0); // For efficient range updates

    for (const auto& op : ops) {
        if (op.type == 1) {
            current_prefix_sum_delta[op.l] += op.val;
            if (op.r + 1 < n) {
                current_prefix_sum_delta[op.r + 1] -= op.val;
            }
        } else { // type == 2
            long long max_val_in_range = LLONG_MIN;
            long long current_delta_val = 0;
            for (int j = 0; j < n; ++j) {
                current_delta_val += current_prefix_sum_delta[j];
                if (j >= op.l && j <= op.r) {
                    max_val_in_range = std::max(max_val_in_range, initial_a[j] + current_delta_val);
                }
            }
            if (max_val_in_range != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false;

        long long current_v_effect = children[i].v;
        long long total_d_effect_from_leaving = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply effect from child i crying in office
            if (current_v_effect > 0) {
                children[j].p -= current_v_effect;
                current_v_effect = std::max(0LL, current_v_effect - 1);
            }

            // Apply cumulative effect from children who left earlier
            children[j].p -= total_d_effect_from_leaving;

            // Check if child j cries and leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_effect_from_leaving += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

