// Function to calculate parity of a 01-string
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    // Calculate initial parity of a
    int current_parity_a = calculate_parity(a);

    // Store all possible strings that can be generated from 'a' by appending parities
    // and their corresponding parities.
    // We only need to store the parity count for the current string.
    // The maximum length of a string is 1000.
    // If we start with a string of length L, we can append up to 1000-L parities.
    // The maximum length of a string we care about is max(|a|, |b|).
    // Since |a|, |b| <= 1000, we can generate strings up to length 1000.
    // We can represent the state by (current_string_length, current_ones_count).
    // However, we only need to check if 'b' is a suffix of any generated string.

    // Let's precompute the parities for all possible extensions of 'a'.
    // We can generate a sequence of parities.
    // The string 'a' can become 'a', 'a' + parity(a), 'a' + parity(a) + parity(a + parity(a)), etc.
    // We are interested in suffixes of these generated strings.

    // The core idea is that if 'b' can be formed, it must be a suffix of some string 'a_prime'
    // where 'a_prime' is formed by taking a suffix of the original 'a' and then
    // appending zero or more parities.

    // Let's iterate through all possible starting suffixes of 'a'.
    // For each suffix, we generate all possible extensions by appending parities.
    // Then we check if 'b' is a suffix of any of these extended strings.

    for (int i = 0; i < a.length(); ++i) {
        std::string current_a_suffix = a.substr(i);
        int current_ones_count = calculate_parity(current_a_suffix) == 1 ? 1 : 0; // This is the parity of current_a_suffix
                                                                                // No, this is not the count of ones.
                                                                                // It's the parity value.
        int ones_in_current_suffix = 0;
        for(char c : current_a_suffix) {
            if (c == '1') {
                ones_in_current_suffix++;
            }
        }

        // Check if current_a_suffix itself is 'b'
        if (current_a_suffix == b) {
            std::cout << "YES\n";
            return 0;
        }

        // Now, extend current_a_suffix by appending parities
        // We need to keep track of the actual string to check for suffix match.
        // But we can optimize by only keeping track of the last character and the parity.
        // The length of the extended string can go up to 1000.
        // The length of current_a_suffix is current_a_suffix.length().
        // We can append up to 1000 - current_a_suffix.length() characters.

        std::string extended_s = current_a_suffix;
        while (extended_s.length() < b.length() || extended_s.length() <= 1000) {
            int parity_val = (ones_in_current_suffix % 2);
            extended_s.push_back(parity_val == 1 ? '1' : '0');
            if (parity_val == 1) {
                ones_in_current_suffix++;
            }

            // If extended_s becomes longer than b, we can check if b is a suffix of extended_s
            if (extended_s.length() >= b.length()) {
                if (extended_s.substr(extended_s.length() - b.length()) == b) {
                    std::cout << "YES\n";
                    return 0;
                }
            }
            if (extended_s.length() == 1000) break; // Max length constraint
        }
    }

    std::cout << "NO\n";

    return 0;
}

