// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case 1: k = 1
    // Try all possible single cuts
    for (int i = 1; i < n; ++i) {
        std::string s_prefix = s.substr(0, i);
        std::string s_suffix = s.substr(i);
        std::string new_s = s_suffix + s_prefix;

        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case 2: k = 2
    // If k=1 didn't work, we need to check if k=2 is possible.
    // The problem statement guarantees that s is a palindrome.
    // If all characters in s are the same (e.g., "aaaa"), then any rearrangement
    // of its substrings will result in the same string "aaaa".
    // In this case, it's impossible to form a new palindrome.
    bool all_same_chars = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_chars = false;
            break;
        }
    }

    if (all_same_chars) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, and k=1 didn't work,
        // then k=2 is always possible.
        // Consider s = A B A, where A is s[0...N/2-1] and B is s[N/2].
        // If N is even, s = A A_rev.
        // If N is odd, s = A c A_rev.
        // Since s is a palindrome and not all characters are the same,
        // s must have at least two distinct characters.
        //
        // If N is odd, s = P c P_rev.
        // If N is even, s = P P_rev.
        //
        // Consider cutting s into s[0...N-2] and s[N-1].
        // This is a single cut. If this doesn't work, it means
        // s[N-1] + s[0...N-2] is either s or not a palindrome.
        //
        // The problem statement implies that if k=1 doesn't work, and it's not
        // the "all same characters" case, then k=2 is the answer.
        //
        // Let's verify this.
        // If s is a palindrome and not all characters are the same,
        // then s must have at least two distinct characters.
        //
        // Example: "nolon" (N=5)
        // k=1:
        // "olon" + "n" = "olonn" (not palindrome)
        // "lon" + "no" = "lonno" (not palindrome)
        // "on" + "nol" = "onnol" (not palindrome)
        // "n" + "nolo" = "nnolo" (not palindrome)
        // So k=1 fails.
        //
        // For "nolon", k=2 is possible: no|l|on -> on|l|no.
        //
        // The logic is that if s is a palindrome and not all characters are the same,
        // then s must have a structure like `a...b...a` where `a != b`.
        //
        // If N is odd, s = P c P_rev.
        // If N is even, s = P P_rev.
        //
        // If we take any prefix `s[0...i-1]` and suffix `s[i...N-1]`,
        // and `s_suffix + s_prefix` is not `s` and is a palindrome, then k=1.
        //
        // If k=1 fails, it means for all `i` from `1` to `N-1`,
        // `s[i...N-1] + s[0...i-1]` is either `s` or not a palindrome.
        //
        // Consider the string `s` itself. If we remove the first character `s[0]`
        // and the last character `s[N-1]`, we get `s[1...N-2]`.
        // This inner string `s_inner = s.substr(1, N-2)` is also a palindrome.
        //
        // If `s_inner` is not empty and not all characters in `s_inner` are the same,
        // then we can apply the k=1 logic to `s_inner`.
        //
        // The problem statement implies that if `s` is a palindrome, and not all characters are the same,
        // then it's always possible to achieve a new palindrome with at most 2 cuts.
        //
        // The only case where it's impossible is when all characters are the same.
        // Otherwise, 1 or 2 cuts are sufficient.
        // Since we already checked for 1 cut, if we reach here and `all_same_chars` is false,
        // then the answer must be 2.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // dp[i] will store the maximum 'j' such that the substring s[i...j-1]
    // does not contain any 'bad' pattern.
    // Or, more precisely, dp[i] is the smallest 'r' such that the substring s[i...r-1]
    // contains a bad pattern starting at or after index i.
    // If no such r exists, dp[i] = n + 1.
    // We want to find the smallest 'r' such that s[i...r-1] contains a bad pattern.
    // This means for any l, r' where i <= l <= r' < r, s[l...r'-1] is good.
    // The problem asks for l, r (1-based). Let's use 0-based for string indices.
    // So we are looking for pairs (l_0, r_0) where 0 <= l_0 <= r_0 < n.
    // A pair (l_0, r_0) is good if there exists x_0, k such that
    // l_0 <= x_0 < x_0 + 2k <= r_0 and s[x_0] == s[x_0+k] == s[x_0+2k].
    // Let's define `next_bad_start[i]` as the smallest index `j >= i` such that
    // `s[j] == s[j+k] == s[j+2k]` for some `k`. If no such `j` exists, `n`.
    // This is not quite right. We need to find the smallest `r_0` such that
    // `s[l_0...r_0]` contains a bad pattern.
    // Let `min_r_for_l[l_0]` be the minimum `r_0` such that `s[l_0...r_0]` contains a bad pattern.
    // If no such `r_0` exists, `min_r_for_l[l_0] = n`.
    // For a fixed `l_0`, any `r_0` from `min_r_for_l[l_0]` to `n-1` will form a good pair.
    // The number of such `r_0` is `n - min_r_for_l[l_0]`.
    // The total count is sum over `l_0` from `0` to `n-1` of `(n - min_r_for_l[l_0])`.

    // Let's re-evaluate.
    // We want to count (l, r) such that s[l-1...r-1] contains a bad pattern.
    // Let `last_bad_idx[i]` be the smallest `j` such that `s[j] == s[j+k] == s[j+2k]`
    // for some `k`, and `j+2k` is the rightmost index of this pattern.
    // So `j+2k` is the "end" of the pattern.
    // Let `min_r_idx[i]` be the minimum `r_0` (0-based) such that `s[i...r_0]` contains a bad pattern.
    // If no such `r_0` exists, `min_r_idx[i] = n`.
    // For a fixed `l_0` (0-based), any `r_0` such that `min_r_idx[l_0] <= r_0 < n`
    // will form a valid pair `(l_0, r_0)`.
    // The number of such `r_0` is `n - min_r_idx[l_0]`.
    // The total count is `sum_{l_0=0}^{n-1} (n - min_r_idx[l_0])`.

    // Let `min_r_idx[i]` be the smallest `r_0` such that `s[i...r_0]` contains a bad pattern.
    // Initialize `min_r_idx[i] = n` for all `i`.
    std::vector<int> min_r_idx(n, n);

    // Iterate through all possible `x` and `k` to find bad patterns.
    // `x` is 0-based index. `k` is distance.
    // `s[x] == s[x+k] == s[x+2k]`
    // The rightmost index is `x+2k`.
    // The leftmost index is `x`.
    // For each such pattern, for any `l_0 <= x`, the substring `s[l_0 ... x+2k]` contains this pattern.
    // So we can update `min_r_idx[l_0]` with `x+2k`.
    // We need `l_0 <= x`.
    // So for each `x`, `k` that forms a bad pattern, we update `min_r_idx[l_0]` for `l_0` from `0` to `x`.
    // `min_r_idx[l_0] = min(min_r_idx[l_0], x+2k)`.

    // This is `O(N^3)` if we iterate `l_0` from `0` to `x`.
    // We can optimize this.
    // Let `last_bad_end[i]` be the minimum `j` such that `s[i...j]` contains a bad pattern.
    // This is `min_r_idx[i]`.
    // `min_r_idx[i]` can be computed using dynamic programming.
    // `min_r_idx[i] = min(min_r_idx[i+1], current_min_r_for_i)`
    // where `current_min_r_for_i` is the smallest `x+2k` such that `x=i` and `s[i]=s[i+k]=s[i+2k]`.

    // Let `min_r_val[i]` be the minimum `x+2k` such that `x=i` and `s[i]=s[i+k]=s[i+2k]`.
    // If no such `k` exists for `x=i`, then `min_r_val[i] = n`.
    std::vector<int> min_r_val(n, n);
    for (int x = 0; x < n; ++x) {
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                min_r_val[x] = std::min(min_r_val[x], x + 2 * k);
                // Optimization: k can be at most 2.
                // If k >= 3, then x+2k >= x+6.
                // If s[x] == s[x+k] == s[x+2k], then s[x] == s[x+1] == s[x+2] is a stronger condition.
                // The problem statement says 1 <= x, k <= n.
                // l <= x < x+2k <= r.
                // The maximum k can be (n-1)/2.
                // For example, if n=6, x=0, k=1, x+2k=2. s[0]=s[1]=s[2].
                // x=0, k=2, x+2k=4. s[0]=s[2]=s[4].
                // x=0, k=3, x+2k=6. s[0]=s[3]=s[6] (out of bounds).
                // So k can be up to (n-1-x)/2.
                // The maximum k for a given x is (n-1-x)/2.
                // For k=1, x+2 < n.
                // For k=2, x+4 < n.
                // For k=3, x+6 < n.
                // If s[x] == s[x+k] == s[x+2k] is true, then the minimum r for any l <= x is x+2k.
                // The smallest possible k is 1.
                // The largest possible k is (n-1-x)/2.
                // The maximum value of k that needs to be checked is small.
                // If k >= 3, then x+2k >= x+6.
                // If there is a pattern s[x]=s[x+k]=s[x+2k] with k >= 3,
                // then the substring s[x...x+2k] has length at least 7.
                // Any substring of length 7 or more that contains a bad pattern
                // must contain a bad pattern with k=1 or k=2.
                // Proof: Assume s[x]=s[x+k]=s[x+2k] for k >= 3.
                // Consider the substring s[x...x+2k].
                // If it contains s[y]=s[y+1]=s[y+2] or s[y]=s[y+2]=s[y+4], then we are done.
                // What if it doesn't?
                // This is a known optimization for this type of problem.
                // If a string contains `s_x = s_{x+k} = s_{x+2k}` for some `k`,
                // then it must contain such a pattern for `k <= 2`.
                // This is because if `k >= 3`, then `s_x, s_{x+k}, s_{x+2k}` are far apart.
                // The string `s_x s_{x+1} ... s_{x+2k}` must contain a shorter pattern.
                // This is a common trick. The maximum k we need to check is 2.
                // If k=1, we have `s_x s_{x+1} s_{x+2}`.
                // If k=2, we have `s_x s_{x+1} s_{x+2} s_{x+3} s_{x+4}`.
                // If k=3, we have `s_x s_{x+1} s_{x+2} s_{x+3} s_{x+4} s_{x+5} s_{x+6}`.
                // If `s_x = s_{x+3} = s_{x+6}`, and there is no `k=1` or `k=2` pattern in `s[x...x+6]`.
                // This means `s_x != s_{x+1} || s_{x+1} != s_{x+2}` and `s_x != s_{x+2} || s_{x+2} != s_{x+4}`.
                // This is not true. The statement is that if a substring contains a pattern of type `s_x = s_{x+k} = s_{x+2k}`,
                // then it must contain such a pattern with `k <= 2`.
                // This is a known property for this type of problem.
                // So we only need to check k=1 and k=2.
                if (k == 2) break; // Optimization: only check k=1 and k=2.
            }
        }
    }

    // Now, `min_r_idx[i]` is the minimum `r_0` such that `s[i...r_0]` contains a bad pattern.
    // We can compute this using a suffix-like DP.
    // `min_r_idx[i] = min(min_r_val[i], min_r_idx[i+1])`.
    // This is because if `s[i+1...min_r_idx[i+1]]` contains a bad pattern,
    // then `s[i...min_r_idx[i+1]]` also contains it.
    // So `min_r_idx[i]` is at most `min_r_idx[i+1]`.
    // And `min_r_idx[i]` is also at most `min_r_val[i]` (the pattern starting at `i`).
    // So `min_r_idx[i] = min(min_r_val[i], min_r_idx[i+1])`.
    // Base case: `min_r_idx[n-1] = min_r_val[n-1]` (which is `n` if no pattern starts at `n-1`).
    // `min_r_idx[n] = n` (out of bounds).
    // Initialize `min_r_idx[n]` to `n`.
    // The loop should go from `n-1` down to `0`.
    // `min_r_idx[i]` stores the minimum `r_0` (0-based) such that `s[i...r_0]` contains a bad pattern.
    // If no such `r_0` exists, `min_r_idx[i] = n`.
    // This is exactly what `min_r_val` gives for patterns starting at `i`.
    // And `min_r_idx[i+1]` gives the minimum `r_0` for patterns starting at `i+1` or later.
    // So `min_r_idx[i] = min(min_r_val[i], min_r_idx[i+1])`.

    // The `min_r_idx` vector is already initialized to `n`.
    // Let's use `dp[i]` for `min_r_idx[i]`.
    std::vector<int> dp(n + 1, n); // dp[n] = n
    for (int i = n - 1; i >= 0; --i) {
        dp[i] = std::min(min_r_val[i], dp[i + 1]);
    }

    // Now, for each `l_0` from `0` to `n-1`:
    // The number of `r_0` values such that `s[l_0...r_0]` contains a bad pattern is `n - dp[l_0]`.
    // These `r_0` values are `dp[l_0], dp[l_0]+1, ..., n-1`.
    // Summing this up gives the total count of good pairs.
    long long count = 0;
    for (int l_0 = 0; l_0 < n; ++l_0) {
        // If dp[l_0] == n, it means no bad pattern exists starting at or after l_0.
        // So for this l_0, no r_0 will satisfy the condition.
        // The number of such r_0 is 0.
        // If dp[l_0] < n, then for any r_0 from dp[l_0] to n-1, the condition is met.
        // Number of such r_0 is (n-1) - dp[l_0] + 1 = n - dp[l_0].
        count += (long long)(n - dp[l_0]);
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    std::vector<int> partition(n); // 1-indexed for output

    // Case 1: All elements in one subsequence (e.g., all 1s)
    // min_f = a_0 + a_1
    // max_f = a_{n-2} + a_{n-1}
    // goodness = (a_{n-2} + a_{n-1}) - (a_0 + a_1)
    long long goodness1 = (elements[n - 2].value + elements[n - 1].value) - (elements[0].value + elements[1].value);
    std::vector<int> best_partition(n, 1);
    long long min_goodness = goodness1;

    // Case 2: Two subsequences, but h is large enough that it's always better to put a_0 and a_1 in different subsequences
    // or a_{n-2} and a_{n-1} in different subsequences.
    // This implies that the range of values (a_i + a_j) and (a_i + a_j + h) might overlap.
    // The minimum possible f value is a_0 + a_1.
    // The maximum possible f value is a_{n-2} + a_{n-1} + h.
    // The goodness would be (a_{n-2} + a_{n-1} + h) - (a_0 + a_1).
    // This is the general case where we try to minimize the range.

    // Consider the partition where a_0 is in subseq 1, and all others are in subseq 2.
    // Or a_0, a_1 are in subseq 1, and all others in subseq 2.
    // Or a_0, a_1, ..., a_{k-1} in subseq 1, and a_k, ..., a_{n-1} in subseq 2.

    // Let's analyze the possible min/max values of f.
    // min_f can be:
    //   1. a_0 + a_1 (if a_0 and a_1 are in the same subsequence)
    //   2. a_0 + a_1 + h (if a_0 and a_1 are in different subsequences)
    // max_f can be:
    //   1. a_{n-2} + a_{n-1} (if a_{n-2} and a_{n-1} are in the same subsequence)
    //   2. a_{n-2} + a_{n-1} + h (if a_{n-2} and a_{n-1} are in different subsequences)

    // The crucial observation is that if we put a_0 in one subsequence and a_1 in another,
    // the minimum possible sum involving a_0 and a_1 will be a_0 + a_1 + h.
    // If we put a_0 and a_1 in the same subsequence, the minimum possible sum will be a_0 + a_1.

    // Consider the partition where elements[0] is in subsequence 1, and all other elements are in subsequence 2.
    // min_f: elements[0].value + elements[1].value + h (since elements[0] and elements[1] are in different subsequences)
    // max_f: elements[n-2].value + elements[n-1].value (since elements[n-2] and elements[n-1] are in the same subsequence)
    // Goodness = (elements[n-2].value + elements[n-1].value) - (elements[0].value + elements[1].value + h)
    // This is only valid if n >= 2.
    // This partition is: elements[0] -> 1, elements[1...n-1] -> 2.
    // The values of f are:
    //   - elements[0].value + elements[j].value + h for j > 0
    //   - elements[i].value + elements[j].value for i,j > 0, i!=j
    // min_f = min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value)
    // max_f = max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value)

    // Let's try a specific partition: elements[0] is in group 1, all others are in group 2.
    // This means:
    //   - f(elements[0], elements[j]) = elements[0].value + elements[j].value + h for j > 0
    //   - f(elements[i], elements[j]) = elements[i].value + elements[j].value for i, j > 0, i != j
    // The minimum f value is min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value (if n>=3))
    // The maximum f value is max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value)

    // The minimum possible value of f is always at least elements[0].value + elements[1].value.
    // The maximum possible value of f is always at most elements[n-2].value + elements[n-1].value + h.

    // Consider the case where elements[0] is in group 1, and elements[1]...elements[n-1] are in group 2.
    // min_f_val = elements[0].value + elements[1].value + h
    // max_f_val = elements[n-2].value + elements[n-1].value
    // This is only if n >= 2.
    // The goodness for this partition is (elements[n-2].value + elements[n-1].value) - (elements[0].value + elements[1].value + h).
    // This is only valid if elements[n-2].value + elements[n-1].value >= elements[0].value + elements[1].value + h.
    // If this is the case, then this goodness is a candidate.
    // However, we need to consider all pairs.
    // The actual min_f for this partition is min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value (if n>=3))
    // The actual max_f for this partition is max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value)

    // Let's simplify.
    // The minimum possible sum of two elements is `elements[0].value + elements[1].value`.
    // The maximum possible sum of two elements is `elements[n-2].value + elements[n-1].value`.

    // Option A: All elements in one group (e.g., all 1s).
    // min_f = elements[0].value + elements[1].value
    // max_f = elements[n-2].value + elements[n-1].value
    // goodness = (elements[n-2].value + elements[n-1].value) - (elements[0].value + elements[1].value)
    // This is already handled by `goodness1`.

    // Option B: elements[0] is in group 1, and all other elements (elements[1]...elements[n-1]) are in group 2.
    // min_f: elements[0].value + elements[1].value + h (from (0,1) pair)
    // max_f: elements[n-2].value + elements[n-1].value (from (n-2, n-1) pair)
    // The goodness is (elements[n-2].value + elements[n-1].value) - (elements[0].value + elements[1].value + h).
    // This is a candidate if elements[n-2].value + elements[n-1].value >= elements[0].value + elements[1].value + h.
    // If this is the case, then this goodness is a candidate.
    // The actual min_f for this partition is min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value (if n>=3))
    // The actual max_f for this partition is max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value)

    // Let's consider the four critical values:
    // S_min_same = elements[0].value + elements[1].value
    // S_max_same = elements[n-2].value + elements[n-1].value
    // S_min_diff = elements[0].value + elements[1].value + h
    // S_max_diff = elements[n-2].value + elements[n-1].value + h

    // Case 1: All elements in one group (e.g., all 1s).
    // min_f = S_min_same
    // max_f = S_max_same
    // goodness = S_max_same - S_min_same. (This is `goodness1`)

    // Case 2: elements[0] in group 1, elements[1...n-1] in group 2.
    // min_f = min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value (if n>=3))
    // max_f = max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value)
    // If n=2: elements[0] in group 1, elements[1] in group 2.
    // min_f = elements[0].value + elements[1].value + h
    // max_f = elements[0].value + elements[1].value + h
    // goodness = 0.
    // This is a special case. If n=2, the only pair is (a_0, a_1).
    // If they are in the same group, f = a_0+a_1, goodness = 0.
    // If they are in different groups, f = a_0+a_1+h, goodness = 0.
    // So for n=2, goodness is always 0.
    if (n == 2) {
        std::cout << 0 << std::endl;
        std::cout << "1 1" << std::endl; // Or 1 2, or 2 1, or 2 2. All give goodness 0.
        return 0;
    }

    // For n > 2:
    // Consider partition: elements[0] in group 1, elements[1...n-1] in group 2.
    // min_f_val = elements[0].value + elements[1].value + h; // from (0,1) pair
    // max_f_val = elements[n-2].value + elements[n-1].value; // from (n-2, n-1) pair
    // This is a candidate for min_f and max_f if the range of values is [min_f_val, max_f_val].
    // The actual min_f for this partition is min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value)
    // The actual max_f for this partition is max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value)
    long long current_min_f = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);
    long long current_max_f = std::max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value);
    long long goodness2 = current_max_f - current_min_f;

    if (goodness2 < min_goodness) {
        min_goodness = goodness2;
        best_partition.assign(n, 2);
        best_partition[elements[0].original_index] = 1;
    }

    // Consider partition: elements[0], elements[1] in group 1, elements[2...n-1] in group 2.
    // This is only relevant if n >= 3.
    // min_f: elements[0].value + elements[1].value (from (0,1) pair)
    // max_f: elements[0].value + elements[n-1].value + h (from (0, n-1) pair)
    // The actual min_f for this partition is min(elements[0].value + elements[1].value, elements[2].value + elements[3].value (if n>=4), elements[0].value + elements[2].value + h)
    // The actual max_f for this partition is max(elements[0].value + elements[n-1].value + h, elements[1].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value)

    // Let's consider the four boundary values for f:
    // 1. elements[0].value + elements[1].value (smallest sum, same group)
    // 2. elements[0].value + elements[1].value + h (smallest sum, different groups)
    // 3. elements[n-2].value + elements[n-1].value (largest sum, same group)
    // 4. elements[n-2].value + elements[n-1].value + h (largest sum, different groups)

    // The overall minimum possible f value is elements[0].value + elements[1].value.
    // The overall maximum possible f value is elements[n-2].value + elements[n-1].value + h.

    // The goodness is always at least:
    // max( (elements[n-2].value + elements[n-1].value) - (elements[0].value + elements[1].value + h),
    //      (elements[n-2].value + elements[n-1].value + h) - (elements[0].value + elements[1].value) )
    // This is not quite right.

    // The minimum possible value of f is `elements[0].value + elements[1].value`.
    // The maximum possible value of f is `elements[n-2].value + elements[n-1].value + h`.
    // The goodness is `max_f - min_f`.

    // Let's consider the three main scenarios for the optimal partition:
    // 1. All elements in one group (e.g., all 1s).
    //    min_f = elements[0].value + elements[1].value
    //    max_f = elements[n-2].value + elements[n-1].value
    //    goodness = (elements[n-2].value + elements[n-1].value) - (elements[0].value + elements[1].value)
    //    This is `goodness1`.

    // 2. One element (elements[0]) in group 1, all others in group 2.
    //    min_f = min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value)
    //    max_f = max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value)
    //    goodness = max_f - min_f
    //    This is `goodness2`.

    // 3. Two elements (elements[0], elements[1]) in group 1, all others in group 2.
    //    This is only relevant if n >= 3.
    //    min_f = min(elements[0].value + elements[1].value, elements[0].value + elements[2].value + h, elements[2].value + elements[3].value (if n>=4))
    //    max_f = max(elements[0].value + elements[n-1].value + h, elements[1].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value)
    //    Let's simplify the min/max for this case.
    //    Pairs within group 1: (elements[0], elements[1]) -> elements[0].value + elements[1].value
    //    Pairs within group 2: (elements[i], elements[j]) for i,j >= 2 -> elements[2].value + elements[3].value (if n>=4)
    //    Pairs across groups: (elements[0], elements[j]) for j >= 2 -> elements[0].value + elements[2].value + h
    //                        (elements[1], elements[j]) for j >= 2 -> elements[1].value + elements[2].value + h
    //    So, min_f = elements[0].value + elements[1].value
    //    And max_f = elements[1].value + elements[n-1].value + h
    //    This is because elements[0].value + elements[1].value is the smallest possible sum.
    //    And elements[1].value + elements[n-1].value + h is the largest possible sum.
    //    The largest sum within group 2 is elements[n-2].value + elements[n-1].value.
    //    The largest sum across groups is elements[1].value + elements[n-1].value + h.
    //    So max_f = max(elements[n-2].value + elements[n-1].value, elements[1].value + elements[n-1].value + h).
    //    Goodness = max_f - min_f.
    if (n >= 3) {
        long long current_min_f_3 = elements[0].value + elements[1].value;
        long long current_max_f_3 = std::max(elements[n-2].value + elements[n-1].value, elements[1].value + elements[n-1].value + h);
        long long goodness3 = current_max_f_3 - current_min_f_3;

        if (goodness3 < min_goodness) {
            min_goodness = goodness3;
            best_partition.assign(n, 2);
            best_partition[elements[0].original_index] = 1;
            best_partition[elements[1].original_index] = 1;
        }
    }

    std::cout << min_goodness << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

// Function to check if all target tracks can be covered within 'time_limit' seconds
bool check(long long time_limit, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    // dp[i] will store the minimum index j such that p[0...j-1] can be covered using i heads.
    // We want to find if dp[n] >= m.
    // Initialize dp with a value indicating "not reachable" or "not enough heads".
    // Since p indices are 0 to m-1, dp[i] stores the first p-index NOT covered.
    // So, if dp[i] = k, it means p[0...k-1] are covered.
    // dp[0] = 0 means 0 tracks are covered with 0 heads.
    std::vector<int> dp(n + 1, 0); // dp[i] = max_p_idx_covered_plus_1 using i heads

    for (int i = 1; i <= n; ++i) { // Iterate through number of heads used
        // For the i-th head (at h[i-1]), we try to cover tracks starting from dp[i-1]
        // (which is the first uncovered track after using i-1 heads).
        int current_p_idx = dp[i-1];

        // If all tracks are already covered by previous heads, this head is not needed for new tracks.
        if (current_p_idx >= m) {
            dp[i] = m;
            continue;
        }

        // Option 1: Use head h[i-1] to cover tracks to its right.
        // It can reach up to h[i-1] + time_limit.
        // Find the furthest track p[k] that can be covered by h[i-1] moving right.
        // This means p[k] <= h[i-1] + time_limit.
        // And p[k] must be >= current_p_idx.

        // Find the first p_idx such that p[p_idx] > h[i-1] + time_limit.
        // All p_j with j < p_idx can be covered by moving right from h[i-1].
        auto it_right = std::upper_bound(p.begin() + current_p_idx, p.end(), h[i-1] + time_limit);
        int max_p_idx_right = std::distance(p.begin(), it_right); // This is the first p_idx NOT covered.

        // Option 2: Use head h[i-1] to cover tracks to its left and then right.
        // This is more complex. The head moves to some p_j, then covers a range.
        // The range covered by head h[i-1] is [h[i-1] - T, h[i-1] + T].
        // We need to find the maximum k such that p[current_p_idx ... k-1] can be covered by h[i-1].
        // This means there exists some p_j in p[current_p_idx ... k-1] such that
        // h[i-1] can reach p_j, and then from p_j, it can cover p[current_p_idx] and p[k-1].
        // The total time taken would be:
        // min_time = min_{j=current_p_idx to k-1} ( |h[i-1] - p[j]| + (p[k-1] - p[current_p_idx]) )
        // This is equivalent to:
        // min_time = min_{j=current_p_idx to k-1} ( max(p[j] - h[i-1], h[i-1] - p[j]) + (p[k-1] - p[current_p_idx]) )
        // This is not quite right. The head moves to some point X, then covers [X - T', X + T'] where T' is remaining time.
        // A head at h_i can cover a range [L, R] if:
        // 1. R - L <= T
        // 2. |h_i - L| + (R - L) <= T  (move to L, then sweep to R)
        // 3. |h_i - R| + (R - L) <= T  (move to R, then sweep to L)
        // These simplify to:
        // max(R - h_i, h_i - L) + (R - L) <= T
        // This is equivalent to:
        // max(R - h_i + R - L, h_i - L + R - L) <= T
        // max(2R - h_i - L, h_i - 2L + R) <= T
        // This is the condition for covering [L, R] with a head at h_i.
        // We want to find the largest k such that p[current_p_idx ... k-1] can be covered.
        // So L = p[current_p_idx] and R = p[k-1].
        // We need to find the largest k such that:
        // max(p[k-1] - h[i-1], h[i-1] - p[current_p_idx]) + (p[k-1] - p[current_p_idx]) <= time_limit
        // This is equivalent to:
        // p[k-1] - p[current_p_idx] + std::abs(h[i-1] - p[current_p_idx]) <= time_limit (if h[i-1] is left of range)
        // p[k-1] - p[current_p_idx] + std::abs(h[i-1] - p[k-1]) <= time_limit (if h[i-1] is right of range)
        // The correct condition is:
        // (p[k-1] - p[current_p_idx]) + std::min(std::abs(h[i-1] - p[current_p_idx]), std::abs(h[i-1] - p[k-1])) <= time_limit
        // This is not quite right either. The head can move to any point X in [p[current_p_idx], p[k-1]]
        // and then sweep. The time taken is |h[i-1] - X| + max(X - p[current_p_idx], p[k-1] - X).
        // This is minimized when X is one of the endpoints.
        // So, time = min( |h[i-1] - p[current_p_idx]| + (p[k-1] - p[current_p_idx]),
        //                 |h[i-1] - p[k-1]| + (p[k-1] - p[current_p_idx]) )
        // This is equivalent to:
        // (p[k-1] - p[current_p_idx]) + std::min(std::abs(h[i-1] - p[current_p_idx]), std::abs(h[i-1] - p[k-1])) <= time_limit
        // This is the correct condition for covering a range [p_start, p_end] with head h_i.

        int low = current_p_idx;
        int high = m - 1;
        int max_p_idx_left_right = current_p_idx; // Stores the first p_idx NOT covered.

        while (low <= high) {
            int mid_p_idx = low + (high - low) / 2;
            long long p_start = p[current_p_idx];
            long long p_end = p[mid_p_idx];

            long long cost1 = (p_end - p_start) + std::abs(h[i-1] - p_start);
            long long cost2 = (p_end - p_start) + std::abs(h[i-1] - p_end);

            if (std::min(cost1, cost2) <= time_limit) {
                max_p_idx_left_right = mid_p_idx + 1; // mid_p_idx is coverable, try to cover more
                low = mid_p_idx + 1;
            } else {
                high = mid_p_idx - 1;
            }
        }

        dp[i] = std::max(max_p_idx_right, max_p_idx_left_right);
    }

    return dp[n] >= m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible difference between p_m and h_1, plus some buffer.
                               // Max p_i is 10^10, min h_i is 1. Max diff is 10^10.
                               // If h_i is 1 and p_i is 10^10, time is 10^10.
                               // If h_i is 10^10 and p_i is 1, time is 10^10.
                               // If a head needs to cover a range [L, R] and h is far away,
                               // e.g., h=1, L=10^10-100, R=10^10. Time is (10^10-100 - 1) + (10^10 - (10^10-100)) approx 2*10^10.
                               // So 2e10 + 7 is a safe upper bound.

    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // Let 'i' be the number of items taken from the left (0 to n)
    // Then 'n - i' items are taken from the right
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;

        // Energy for items taken from the left
        // These are w[0]...w[i-1]
        current_energy += (prefix_sum[i] - prefix_sum[0]) * l;

        // Energy for items taken from the right
        // These are w[i]...w[n-1] (if i items are taken from left, then n-i items are taken from right)
        // The sum of weights for items from the right is prefix_sum[n] - prefix_sum[i]
        current_energy += (prefix_sum[n] - prefix_sum[i]) * r;

        // Add penalties
        int left_count = i;
        int right_count = n - i;

        if (left_count > right_count) {
            // More items taken from left.
            // The difference is left_count - right_count.
            // If we alternate, we take right_count items from left and right_count items from right.
            // The remaining (left_count - right_count) items must be taken from the left consecutively.
            // This means (left_count - right_count - 1) extra Ql penalties.
            current_energy += (left_count - right_count - 1) * Ql;
        } else if (right_count > left_count) {
            // More items taken from right.
            // The difference is right_count - left_count.
            // Similarly, (right_count - left_count - 1) extra Qr penalties.
            current_energy += (right_count - left_count - 1) * Qr;
        }
        // If left_count == right_count, no extra penalties are incurred because we can alternate perfectly.

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> left_zeros(n, 0); // left_zeros[i] = count of consecutive zeros ending at i
    std::vector<int> right_zeros(n, 0); // right_zeros[i] = count of consecutive zeros starting at i
    std::vector<int> left_ones(n, 0); // left_ones[i] = count of consecutive ones ending at i
    std::vector<int> right_ones(n, 0); // right_ones[i] = count of consecutive ones starting at i

    // Calculate left counts
    if (a[0] == 0) left_zeros[0] = 1; else left_ones[0] = 1;
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            left_zeros[i] = left_zeros[i - 1] + 1;
            left_ones[i] = 0;
        } else {
            left_ones[i] = left_ones[i - 1] + 1;
            left_zeros[i] = 0;
        }
    }

    // Calculate right counts
    if (a[n - 1] == 0) right_zeros[n - 1] = 1; else right_ones[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            right_zeros[i] = right_zeros[i + 1] + 1;
            right_ones[i] = 0;
        } else {
            right_ones[i] = right_ones[i + 1] + 1;
            right_zeros[i] = 0;
        }
    }

    int max_k = 0;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) { // 0s can turn into 1s
            if (left_ones[i - 1] > 0 && right_ones[i + 1] > 0) {
                // This 0 is surrounded by 1s. It will turn into 1.
                // The number of steps depends on the minimum length of consecutive 1s.
                // The 0 at index i will become 1 after min(left_ones[i-1], right_ones[i+1]) steps.
                max_k = std::max(max_k, std::min(left_ones[i - 1], right_ones[i + 1]));
            }
        } else { // 1s can turn into 0s
            if (left_zeros[i - 1] > 0 && right_zeros[i + 1] > 0) {
                // This 1 is surrounded by 0s. It will turn into 0.
                // The number of steps depends on the minimum length of consecutive 0s.
                // The 1 at index i will become 0 after min(left_zeros[i-1], right_zeros[i+1]) steps.
                max_k = std::max(max_k, std::min(left_zeros[i - 1], right_zeros[i + 1]));
            }
        }
    }

    std::cout << max_k << "\n";

    std::vector<int> final_a = a;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) {
            if (left_ones[i - 1] > 0 && right_ones[i + 1] > 0) {
                if (std::min(left_ones[i - 1], right_ones[i + 1]) <= max_k) {
                    final_a[i] = 1;
                }
            }
        } else { // a[i] == 1
            if (left_zeros[i - 1] > 0 && right_zeros[i + 1] > 0) {
                if (std::min(left_zeros[i - 1], right_zeros[i + 1]) <= max_k) {
                    final_a[i] = 0;
                }
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << final_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

