#include <algorithm>
#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    if (n == 2) {
        std::cout << p[1] << " " << p[0] << std::endl;
        return;
    }

    // For n > 2, reversing the permutation always works.
    // Let p = [p_1, p_2, ..., p_n].
    // The sums are [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n].
    // Let p' = [p_n, p_{n-1}, ..., p_1].
    // The sums for p' are [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1].
    // These are exactly the same set of sums, just in reverse order.
    // Sorting them will yield the same fingerprint.
    // Since n > 2, p' will always be different from p.
    // If p is [1, 2, ..., n], then p' is [n, n-1, ..., 1]. These are different.
    // If p is [n, n-1, ..., 1], then p' is [1, 2, ..., n]. These are different.
    // If p is a palindrome (e.g., [1, 2, 1] for n=3, but permutations can't be palindromes for n>1),
    // then p_i = p_{n-i+1}.
    // For a permutation, p_i must be distinct.
    // If p = p', then p_i = p_{n-i+1} for all i.
    // For n > 2, this is impossible for a permutation.
    // E.g., for n=3, p_1=p_3, p_2=p_2. But p_1, p_2, p_3 must be distinct.
    // So p_1=p_3 is impossible.
    // Thus, for n > 2, reversing a permutation always yields a different permutation.

    std::reverse(p.begin(), p.end());
    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

