#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long current_a1 = a[0];
    long long remaining_days = d;

    for (int i = 1; i < n; ++i) {
        long long pile_idx = i + 1; // 1-indexed pile number
        long long haybales_in_pile = a[i];
        long long cost_per_haybale = pile_idx - 1;

        if (cost_per_haybale == 0) { // Should not happen for i >= 1
            current_a1 += haybales_in_pile;
            continue;
        }

        if (remaining_days >= cost_per_haybale) {
            long long max_can_move = remaining_days / cost_per_haybale;
            long long actual_moved = std::min(haybales_in_pile, max_can_move);

            current_a1 += actual_moved;
            remaining_days -= actual_moved * cost_per_haybale;
        } else {
            // Not enough days to move even one haybale from this pile
            break; 
        }
    }

    std::cout << current_a1 << std::endl;
}

