void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << "\n";
    } else {
        // For n >= 2, we can construct a number.
        // The strategy is to use '2' as the first digit,
        // and '3' for all subsequent digits except the last one,
        // and '9' for the last digit.
        // This forms a number like 233...39.
        //
        // Let's check divisibility:
        // 1. Not divisible by 2: The number ends in 9 (odd).
        // 2. Not divisible by 3: The sum of digits is 2 + (n-2)*3 + 9 = 2 + 3n - 6 + 9 = 3n + 5.
        //    Since 3n is divisible by 3, 3n+5 is not divisible by 3.
        // 3. Not divisible by 9: The sum of digits is 3n + 5.
        //    Since 3n is divisible by 3, if 3n+5 were divisible by 9, it would also be divisible by 3.
        //    For 3n+5 to be divisible by 9, 3n+5 must be a multiple of 9.
        //    3n+5 = 9k
        //    3n = 9k - 5
        //    This implies 9k-5 must be divisible by 3.
        //    9k is divisible by 3, but 5 is not. So 9k-5 is not divisible by 3.
        //    Therefore, 3n+5 is never divisible by 3, and thus never divisible by 9.
        //
        // This construction works for all n >= 2.

        std::cout << '2';
        for (int i = 0; i < n - 2; ++i) {
            std::cout << '3';
        }
        std::cout << '9' << "\n";
    }
}

