#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) {
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_neg_one) {
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation is needed for this specific element.
        // The presence of +1 or -1 before index i is still relevant for future elements.
    }

    std::cout << "YES\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        long long diff = std::abs(a - b);
        long long presses = 0;

        // Greedy approach for denominations 5, 2, 1
        // This works because 5 > 2*2 and 2 > 1*1.
        // For example, if we have 4, we can do 2+2 (2 presses) or 5-1 (2 presses).
        // If we have 3, we can do 2+1 (2 presses) or 5-2 (2 presses).
        // The greedy choice of taking as many 5s as possible, then 2s, then 1s
        // will always yield the minimum number of presses.

        presses += diff / 5;
        diff %= 5;

        // Now diff can be 0, 1, 2, 3, 4
        if (diff == 4) {
            // 4 can be 2+2 (2 presses) or 5-1 (2 presses). Both are 2 presses.
            // Greedy: 2+2.
            presses += 2;
        } else if (diff == 3) {
            // 3 can be 2+1 (2 presses) or 5-2 (2 presses). Both are 2 presses.
            // Greedy: 2+1.
            presses += 2;
        } else if (diff == 2) {
            // 2 is 1 press.
            presses += 1;
        } else if (diff == 1) {
            // 1 is 1 press.
            presses += 1;
        }
        // If diff is 0, no more presses needed.

        std::cout << presses << "\n";
    }
    return 0;
}

