#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Item {
    int value;
    int original_index;
};

bool compareItems(const Item& a, const Item& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<Item> a(n);
        std::vector<Item> b(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i].value;
            a[i].original_index = i;
        }
        for (int i = 0; i < n; ++i) {
            std::cin >> b[i].value;
            b[i].original_index = i;
        }

        std::sort(a.begin(), a.end(), compareItems);
        std::sort(b.begin(), b.end(), compareItems);

        std::vector<int> result_x(n);
        std::vector<int> result_y(n);

        for (int i = 0; i < n; ++i) {
            result_x[a[i].original_index] = a[i].value;
            result_y[a[i].original_index] = b[n - 1 - i].value;
        }

        for (int i = 0; i < n; ++i) {
            std::cout << result_x[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << result_y[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue; // Skip diagonal element a[i][i] = 0
            max_val_in_row = std::max(max_val_in_row, a[i][j]);
        }
        // If max_val_in_row is n-1, then p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        // This is because if p[i] is not n, then p[i] is one of the values 1 to n-1.
        // In this case, there must be some p[j] such that p[j] > p[i].
        // Then min(p[i], p[j]) = p[i].
        // So max_val_in_row would be p[i].
        // If p[i] is n, then for any p[j] (j != i), p[j] <= n-1.
        // So min(p[i], p[j]) = min(n, p[j]) = p[j].
        // The maximum of these p[j] values would be n-1 (since n is taken by p[i]).
        // So max_val_in_row would be n-1.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

