int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        // The maximum number of teams 'k' must satisfy:
        // 1. k <= c (enough coders)
        // 2. k <= m (enough mathematicians)
        // 3. 3 * k <= c + m + x (enough total students)
        // From 1 and 2, k <= min(c, m).
        // From 3, k <= (c + m + x) / 3.
        // So, k <= min(c, m, (c + m + x) / 3).
        // This condition is also sufficient.
        // If we can form k teams, we need k coders, k mathematicians.
        // The remaining k students for each team can be filled by:
        // - additional coders (c - k)
        // - additional mathematicians (m - k)
        // - students with no specialization (x)
        // The total number of "other" students available is (c - k) + (m - k) + x.
        // Each team needs 1 coder, 1 mathematician, and 1 "other" student.
        // So we need k "other" students.
        // We must have k <= (c - k) + (m - k) + x.
        // This simplifies to k <= c + m + x - 2k, or 3k <= c + m + x.
        // This is exactly the third condition.
        // Therefore, the maximum k is indeed min(c, m, (c + m + x) / 3).
        long long ans = std::min({c, m, (c + m + x) / 3});
        std::cout << ans << "\n";
    }
    return 0;
}

