#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i] < a[i-1]
    // This marks the end of the non-decreasing suffix
    int i = n - 1;
    while (i > 0 && a[i-1] <= a[i]) {
        i--;
    }
    // Now, a[i...n-1] is non-decreasing.
    // If i is 0, the whole array is non-decreasing.

    // Find the rightmost index `j` such that a[j] > a[j+1]
    // This marks the end of the non-increasing suffix (from right to left)
    // We start from `i` because elements to the right of `i` are already non-decreasing.
    // We are looking for the point where the sequence stops being non-increasing from right.
    // Example: [4,3,3,8,4,5,2]
    // i = 6 (a[6]=2)
    // a[5]=5, a[6]=2. a[5] > a[6]. So i becomes 5.
    // a[4]=4, a[5]=5. a[4] <= a[5]. Stop. i is 4.
    // So a[4...6] = [4,5,2] is the non-decreasing suffix.
    // Now we need to find the point where the prefix before this suffix stops being non-increasing from right.
    // We are looking for the first element from the right that breaks the non-increasing pattern.
    // The elements from a[i] to a[n-1] are already non-decreasing.
    // We need to find the first index `j` from the right such that `a[j] < a[j-1]`
    // and `j` is to the left of `i`.
    // The loop below finds the first index `j` from the right such that `a[j] > a[j+1]`.
    // This `j` will be the rightmost element of the "peak" or the start of the non-increasing part.
    // The elements from `j+1` to `n-1` are non-decreasing.
    // The elements from `k` to `j` are non-increasing (from right to left).
    // We want to find the smallest `k` such that `a[k...n-1]` is good.
    // The `i` we found above is the start of the non-decreasing suffix.
    // So `a[i...n-1]` is non-decreasing.
    // Now we need to find the start of the non-increasing part that precedes `a[i]`.
    // This means we are looking for the first `j` from `i-1` down to `0` such that `a[j] < a[j+1]`.
    // If we find such `j`, then `a[j+1...i-1]` is non-increasing.
    // The elements `a[j+1...n-1]` form the candidate suffix.
    // The prefix to remove would be `j+1`.

    int j = i; // Start from the beginning of the non-decreasing suffix
    while (j > 0 && a[j-1] >= a[j]) { // While elements are non-increasing from right to left
        j--;
    }
    // Now, a[j...i-1] is non-increasing (from right to left).
    // And a[i...n-1] is non-decreasing.
    // The suffix a[j...n-1] is the shortest possible good array.
    // The length of the prefix to erase is `j`.

    std::cout << j << std::endl;
}

