            // If (a+b) is odd, and (b+c) == 0, then all toys are in A or D.
            // If A > 0 or D > 0, then magnitude will always be >= 1.
            // So, if (a+b) is odd, and (b+c) == 0, then ans2 = "Tidak".
            // So, ans2 = "Ya" if (a+b) % 2 == 1 AND (b+c > 0 OR (a==0 AND d==0)).
            // This simplifies to: if (a+b) % 2 == 1 AND (b+c > 0 OR (a==0 AND d==0)).
            // Let's test this.
            // A=1, B=2, C=0, D=1. (a+b)=3 (odd). (b+c)=2 (>0). -> ans2="Ya". (Example case 1)
            // A=0, B=1, C=0, D=0. (a+b)=1 (odd). (b+c)=1 (>0). -> ans2="Ya". (Example case 2)
            // A=1, B=0, C=0, D=0. (a+b)=1 (odd). (b+c)=0. (a=1, d=0). -> ans2="Tidak". Correct, it's Box 1.
            // A=0, B=0, C=0, D=1. (a+b)=0 (even). -> ans2="Tidak". Correct, it's Box 4.
            // A=0, B=0, C=1, D=0. (a+b)=0 (even). -> ans2="Tidak". Correct, it's Box 3.
            // A=0, B=1, C=0, D=0. (a+b)=1 (odd). (b+c)=1 (>0). -> ans2="Ya". Correct, it's Box 2.
            // This logic seems correct.
            if (b + c > 0 || (a == 0 && d == 0)) {
                ans2 = "Ya";
            }
        }

        // Can Box 3 be the special box?
        // Final product must be positive and magnitude < 1.
        // Need even number of negative toys.
        // Need to be able to make magnitude < 1.
        // If (a+b) is even, we can make the final product positive.
        // To make magnitude < 1:
        // If A=0 and D=0, then all toys are in B or C. Product will always be in (-1, 1). So ans3 = "Ya".
        // If A > 0 or D > 0:
        // We need to be able to make the product of all toys have magnitude < 1.
        // This is possible if we have at least one toy in B or C.
        // So, if (a+b) is even AND (b+c) > 0, then ans3 = "Ya".
        // What if (b+c) == 0? Then all toys are in A or D.
        // If (a+b) is even, and (b+c) == 0, then all toys are in A or D.
        // If A > 0 or D > 0, then magnitude will always be >= 1.
        // So, if (a+b) is even, and (b+c) == 0, then ans3 = "Tidak".
        // So, ans3 = "Ya" if (a+b) % 2 == 0 AND (b+c > 0 OR (a==0 AND d==0)).
        if ((a + b) % 2 == 0) { // Even number of negative toys
            if (b + c > 0 || (a == 0 && d == 0)) {
                ans3 = "Ya";
            }
        }

        // Can Box 4 be the special box?
        // Final product must be positive and magnitude >= 1.
        // Need even number of negative toys.
        // Need to be able to make magnitude >= 1.
        // If (a+b) is even, we can make the final product positive.
        // To make magnitude >= 1:
        // This is possible if A > 0 or D > 0.
        // If A=0 and D=0, then all toys are in B or C. Product will always be in (-1, 1). So ans4 = "Tidak".
        // So, if (a+b) is even AND (a > 0 OR d > 0), then ans4 = "Ya".
        if ((a + b) % 2 == 0) { // Even number of negative toys
            if (a > 0 || d > 0) {
                ans4 = "Ya";
            }
        }
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
}

