#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_can_be_increasing
    // prefix_can_be_increasing[i] is true if a[0...i] can form 0, 1, ..., i
    std::vector<bool> prefix_can_be_increasing(n);
    prefix_can_be_increasing[0] = (a[0] >= 0); // a[0] must be >= 0
    for (int i = 1; i < n; ++i) {
        prefix_can_be_increasing[i] = prefix_can_be_increasing[i-1] && (a[i] >= i);
    }

    // Calculate suffix_can_be_decreasing
    // suffix_can_be_decreasing[i] is true if a[i...n-1] can form ..., 1, 0
    std::vector<bool> suffix_can_be_decreasing(n);
    suffix_can_be_decreasing[n-1] = (a[n-1] >= 0); // a[n-1] must be >= 0
    for (int i = n - 2; i >= 0; --i) {
        suffix_can_be_decreasing[i] = suffix_can_be_decreasing[i+1] && (a[i] >= (n - 1 - i));
    }

    // Check if there exists a k (0-indexed) such that
    // a[0...k] can be 0, 1, ..., k
    // AND a[k...n-1] can be k, k-1, ..., 0 (relative to k)
    // This means a[k] must be >= k AND a[k] must be >= (n-1-k)
    // So a[k] must be >= max(k, n-1-k)
    // The conditions for prefix_can_be_increasing[k] and suffix_can_be_decreasing[k]
    // already implicitly check a[k] >= k and a[k] >= (n-1-k) respectively.
    // Specifically, prefix_can_be_increasing[k] checks a[k] >= k.
    // And suffix_can_be_decreasing[k] checks a[k] >= (n-1-k).
    // So we just need to find a k where both are true.

    bool possible = false;
    for (int k = 0; k < n; ++k) {
        if (prefix_can_be_increasing[k] && suffix_can_be_decreasing[k]) {
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

