int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2; // For 0-indexed array, (n-1)/2 is the middle index

    // First, make the median element equal to s
    operations += std::abs(a[median_idx] - s);
    a[median_idx] = s; // Conceptually change it to s for subsequent checks

    // Ensure elements to the left of median are <= s
    // These are elements a[0]...a[median_idx-1]
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
            // a[i] = s; // No need to actually change, just count operations
        }
    }

    // Ensure elements to the right of median are >= s
    // These are elements a[median_idx+1]...a[n-1]
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
            // a[i] = s; // No need to actually change, just count operations
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

