int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int j = 0; // Pointer for elements to be placed (the 'b' array)
    for (int i = 0; i < n; ++i) { // Pointer for original positions (the 'a' array)
        // We are trying to find an element a[j] from the sorted array
        // to place at position i such that a[j] > a[i].
        // Since both a[i] and a[j] are from the sorted array,
        // we want to find the smallest a[j] that is greater than a[i].
        // We can advance j as long as a[j] is not greater than a[i].
        // Once a[j] > a[i], we found a match, increment count, and move to the next element for both.
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        if (j < n) { // If we found an element a[j] such that a[j] > a[i]
            count++;
            j++; // Move to the next element in the 'b' array for the next potential match
        } else {
            // If j reached the end, it means no more elements can be found
            // that are greater than the current a[i] or any subsequent a[k] (k > i).
            // So we can break.
            break;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

