#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<int> prefix_counts(n + 1, 0);
    int current_max_prefix = 0;
    int distinct_count_prefix = 0;

    for (int i = 0; i < n; ++i) {
        if (prefix_counts[a[i]] == 0) {
            distinct_count_prefix++;
        }
        prefix_counts[a[i]]++;
        current_max_prefix = std::max(current_max_prefix, a[i]);

        if (distinct_count_prefix == i + 1 && current_max_prefix == i + 1) {
            is_prefix_perm[i + 1] = true;
        }
    }

    std::vector<bool> is_suffix_perm(n + 1, false);
    std::vector<int> suffix_counts(n + 1, 0);
    int current_max_suffix = 0;
    int distinct_count_suffix = 0;

    for (int i = n - 1; i >= 0; --i) {
        int len = n - i; // length of suffix a[i...n-1]
        if (suffix_counts[a[i]] == 0) {
            distinct_count_suffix++;
        }
        suffix_counts[a[i]]++;
        current_max_suffix = std::max(current_max_suffix, a[i]);

        if (distinct_count_suffix == len && current_max_suffix == len) {
            is_suffix_perm[len] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

