        std::cin >> s;
        int n = s.length();

        std::map<char, int> counts;
        for (char c : s) {
            counts[c]++;
        }

        char most_frequent_char = ' ';
        int max_count = -1;

        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_char = 'R';
        }
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_char = 'S';
        }
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_char = 'P';
        }

        // If counts are equal, any choice is fine.
        // The problem statement implies that any optimal answer is fine.
        // The order R, S, P in the if-conditions above implicitly handles ties
        // by picking the one that appears first in that order.
        // For example, if R and S both have max_count, R will be chosen.
        // This is fine as we just need *a* most frequent character.

        char our_optimal_move = get_winning_move(most_frequent_char);

        for (int i = 0; i < n; ++i) {
            std::cout << our_optimal_move;
