void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // If s[i] is '0', then both w[i-x] and w[i+x] must be '0'.
    // We use this to set corresponding w characters to '0'.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Now, verify if this candidate w can produce the given s.
    // Construct s_prime from w and x.
    std::string s_prime(n, '0');
    for (int i = 0; i < n; ++i) {
        // Check w[i-x]
        if (i - x >= 0 && w[i - x] == '1') {
            s_prime[i] = '1';
        }
        // Check w[i+x]
        if (i + x < n && w[i + x] == '1') {
            s_prime[i] = '1';
        }
    }

    // Compare s_prime with the original s.
    if (s_prime == s) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // `i` represents the number of items taken from the left (0 to n)
    for (int i = 0; i <= n; ++i) {
        int j = n - i; // Number of items taken from the right

        long long current_energy = 0;

        // Energy for items taken from the left
        if (i > 0) {
            current_energy += prefix_sum[i] * l;
        }

        // Energy for items taken from the right
        if (j > 0) {
            current_energy += (prefix_sum[n] - prefix_sum[n - j]) * r;
        }

        // Add penalty for unbalanced counts
        if (i > j) { // More items from left
            if (i - j > 1) { // If difference is more than 1, there are (i-j-1) extra left moves
                current_energy += (i - j - 1) * Ql;
            }
        } else if (j > i) { // More items from right
            if (j - i > 1) { // If difference is more than 1, there are (j-i-1) extra right moves
                current_energy += (j - i - 1) * Qr;
            }
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

