#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_score = 0;

    // Case 1: N is odd
    // Chanek must take 1 coin. N becomes even.
    // Then the game proceeds with N-1 coins, and it's opponent's turn.
    if (n % 2 != 0) {
        chanek_score += 1;
        n -= 1;
    }

    // Now N is even.
    // Chanek's turn.
    // Option A: Take 1 coin. N becomes odd. Opponent's turn.
    // Option B: Take N/2 coins. N becomes N/2. Opponent's turn.

    // If N is a power of 2, say 2^k.
    // Chanek takes N/2. N becomes N/2 (which is 2^(k-1)).
    // Opponent takes N/4. N becomes N/4 (which is 2^(k-2)).
    // This continues until N=1.
    // Chanek gets N/2 + N/8 + N/32 + ...
    // Opponent gets N/4 + N/16 + N/64 + ...
    // If N is 2^k, Chanek gets N/2 + N/8 + ... + (if k is odd) 1/2 + (if k is even) 1.
    // This is (N/2) * (1 + 1/4 + 1/16 + ...) = (N/2) * (1 / (1 - 1/4)) = (N/2) * (4/3) = 2N/3.
    // But this is not quite right because the turns alternate.
    // If N = 2^k:
    // C takes 2^(k-1). N = 2^(k-1).
    // O takes 2^(k-2). N = 2^(k-2).
    // C takes 2^(k-3). N = 2^(k-3).
    // ...
    // The last coin is taken by C if k is odd, by O if k is even.
    // Chanek's total: 2^(k-1) + 2^(k-3) + ...
    // Opponent's total: 2^(k-2) + 2^(k-4) + ...
    // Sum of geometric series:
    // Chanek: 2^(k-1) * (1 + 1/4 + 1/16 + ...) = 2^(k-1) * (4/3) = 2^(k+1)/3.
    // Opponent: 2^(k-2) * (1 + 1/4 + 1/16 + ...) = 2^(k-2) * (4/3) = 2^k/3.
    // Total: 2^(k+1)/3 + 2^k/3 = (2*2^k + 2^k)/3 = 3*2^k/3 = 2^k = N. This is correct.
    // So if N is a power of 2, Chanek gets 2N/3 and Opponent gets N/3.
    // This strategy is optimal for Chanek because taking 1 coin would leave N-1 (odd),
    // then opponent takes 1, N-2 (even). This seems worse.

    // If N is even but not a power of 2.
    // N = 2^k * M, where M is odd and M > 1.
    // Chanek's turn. N is even.
    // Option A: Take 1. N becomes N-1 (odd). Opponent takes 1. N becomes N-2 (even).
    // Option B: Take N/2. N becomes N/2.
    // If Chanek takes N/2, the new N is 2^(k-1) * M.
    // If M > 1, then N/2 is still even and not a power of 2 (unless k-1=0 and M is power of 2, but M is odd).
    // The game continues with N/2.
    // This suggests a greedy strategy: always take N/2 if N is even.
    // If N is odd, take 1.

    // Let's simulate this greedy strategy.
    // Chanek's turn:
    // If N is odd: Chanek takes 1. N becomes N-1.
    // If N is even: Chanek takes N/2. N becomes N/2.
    // Opponent's turn:
    // If N is odd: Opponent takes 1. N becomes N-1.
    // If N is even: Opponent takes N/2. N becomes N/2.

    // This is equivalent to:
    // While N > 0:
    //   If current player is Chanek:
    //     If N is odd: Chanek takes 1. N--.
    //     Else (N is even):
    //       If N is a power of 2: Chanek takes N/2. N = N/2.
    //       Else (N is even, not power of 2): Chanek takes N/2. N = N/2.
    //   Else (current player is Opponent):
    //     If N is odd: Opponent takes 1. N--.
    //     Else (N is even):
    //       If N is a power of 2: Opponent takes N/2. N = N/2.
    //       Else (N is even, not power of 2): Opponent takes N/2. N = N/2.

    // The only time a player might deviate from taking N/2 when N is even is if N is a power of 2.
    // If N = 2^k:
    // Chanek takes N/2. N becomes 2^(k-1).
    // Opponent takes N/4. N becomes 2^(k-2).
    // ...
    // This leads to Chanek getting 2N/3 and Opponent getting N/3.
    // What if Chanek takes 1 when N=2^k?
    // N becomes 2^k-1 (odd). Opponent takes 1. N becomes 2^k-2 (even).
    // This seems worse for Chanek.
    // Example N=4 (2^2):
    // C takes 4/2=2. N=2. O takes 2/2=1. N=1. C takes 1. N=0.
    // C: 2+1=3. O: 1.
    // Using 2N/3 formula: 2*4/3 = 8/3 (not integer).
    // The formula 2N/3 and N/3 is for the total sum of coins taken by each player if they always take half.
    // For N=4: C takes 2. N=2. O takes 1. N=1. C takes 1. N=0.
    // C: 2+1=3. O: 1.
    // For N=2: C takes 1. N=1. O takes 1. N=0.
    // C: 1. O: 1.
    // For N=6:
    // C takes 6/2=3. N=3. O takes 1. N=2. C takes 2/2=1. N=1. O takes 1. N=0.
    // C: 3+1=4. O: 1+1=2.
    // This matches example.

    // The strategy is:
    // If N is odd, take 1.
    // If N is even:
    //   If N is a power of 2, take N/2.
    //   If N is even but not a power of 2, take N/2.

    // This means the optimal strategy is always:
    // If N is odd, take 1.
    // If N is even, take N/2.

    // Let's re-evaluate the power of 2 case.
    // N = 2^k.
    // Chanek's turn.
    // Option 1: Take 1. N becomes 2^k-1 (odd). Opponent's turn.
    //   Opponent takes 1. N becomes 2^k-2 (even). Chanek's turn.
    //   This path seems to give Chanek less.
    // Option 2: Take N/2. N becomes 2^(k-1). Opponent's turn.
    //   This path leads to Chanek getting 2N/3 and Opponent N/3 (approximately).
    //   More precisely, Chanek gets 2^(k-1) + 2^(k-3) + ...
    //   Opponent gets 2^(k-2) + 2^(k-4) + ...
    //   If k is odd, Chanek gets 2^(k-1) + ... + 2^0. Sum = (2^k - 1)/ (2-1) = 2^k - 1.
    //   If k is even, Chanek gets 2^(k-1) + ... + 2^1. Sum = (2^k - 2)/ (2-1) = 2^k - 2.
    //   This is wrong. The sum is 2^(k-1) + 2^(k-3) + ... + 2^x.
    //   This is a geometric series with ratio 1/4.
    //   Number of terms: floor((k-1)/2) + 1.
    //   Sum = 2^(k-1) * (1 - (1/4)^num_terms) / (1 - 1/4).
    //   This is getting complicated.

    // Let's use the observation from the problem statement:
    // For N=5: C takes 1. N=4. O takes 2. N=2. C takes 1. N=1. O takes 1. N=0.
    // C: 1+1=2. O: 2+1=3.
    // My greedy: C takes 1. N=4. O takes 4/2=2. N=2. C takes 2/2=1. N=1. O takes 1. N=0.
    // C: 1+1=2. O: 2+1=3. Matches.

    // For N=6: C takes 3. N=3. O takes 1. N=2. C takes 1. N=1. O takes 1. N=0.
    // C: 3+1=4. O: 1+1=2.
    // My greedy: C takes 6/2=3. N=3. O takes 1. N=2. C takes 2/2=1. N=1. O takes 1. N=0.
    // C: 3+1=4. O: 1+1=2. Matches.

    // It seems the greedy strategy (take N/2 if even, take 1 if odd) is optimal for both players.
    // Let's trace this strategy for Chanek.
    // Initial N.
    // If N is odd, Chanek takes 1. N becomes N-1. Chanek's score += 1.
    // Now N is even.
    // While N > 0:
    //   Chanek's turn:
    //     If N is even: Chanek takes N/2. Chanek's score += N/2. N = N/2.
    //     Else (N is odd): Chanek takes 1. Chanek's score += 1. N = N-1.
    //   Opponent's turn:
    //     If N is even: Opponent takes N/2. N = N/2.
    //     Else (N is odd): Opponent takes 1. N = N-1.

    // This is the simulation of the greedy strategy.
    // The only special case is when N is a power of 2.
    // If N = 2^k, and it's Chanek's turn.
    // Chanek takes N/2. N becomes 2^(k-1).
    // Opponent takes N/4. N becomes 2^(k-2).
    // Chanek takes N/8. N becomes 2^(k-3).
    // ...
    // This continues until N=1.
    // The last coin (1) is taken by Chanek if k is odd.
    // The last coin (1) is taken by Opponent if k is even.

    // Let's check if N is a power of 2.
    // A number N is a power of 2 if N > 0 and (N & (N - 1)) == 0.
    // If N is a power of 2, say N = 2^k.
    // Chanek's score will be N - (N/3) (approx).
    // More precisely, if N = 2^k:
    // Chanek gets 2^(k-1) + 2^(k-3) + ...
    // Opponent gets 2^(k-2) + 2^(k-4) + ...
    // If k is odd: Chanek gets 2^(k-1) + ... + 2^0. This is (2^k - 1) / (2-1) = 2^k - 1.
    // If k is even: Chanek gets 2^(k-1) + ... + 2^1. This is (2^k - 2) / (2-1) = 2^k - 2.
    // This is wrong. The sum is 2^(k-1) + 2^(k-3) + ...
    // Example N=4 (k=2, even): C takes 2. N=2. O takes 1. N=1. C takes 1. N=0. C: 3. O: 1.
    // My formula: 2^2 - 2 = 2. Incorrect.
    // The sum is 2^(k-1) + 2^(k-3) + ... + 2^x.
    // For N=4 (k=2): C gets 2^(2-1) + 2^(2-3) (no, stop at 2^0 or 2^1).
    // C gets 2^(k-1) + 2^(k-3) + ... + (2^1 if k is even, 2^0 if k is odd).
    // If k is even, say k=2. C gets 2^1 = 2. O gets 2^0 = 1. Total 3. Remaining 1. C gets 1. Total C: 3. O: 1.
    // If k is odd, say k=3. N=8. C gets 4. N=4. O gets 2. N=2. C gets 1. N=1. O gets 1. N=0.
    // C: 4+1=5. O: 2+1=3.
    // My formula: 2^3 - 1 = 7. Incorrect.

    // Let's re-evaluate the power of 2 case carefully.
    // N = 2^k.
    // Chanek takes 2^(k-1). Remaining: 2^(k-1). Chanek's score: 2^(k-1).
    // Opponent takes 2^(k-2). Remaining: 2^(k-2). Opponent's score: 2^(k-2).
    // Chanek takes 2^(k-3). Remaining: 2^(k-3). Chanek's score: 2^(k-1) + 2^(k-3).
    // ...
    // This continues until 1 coin remains.
    // If k is odd: The last coin (1 = 2^0) is taken by Chanek.
    //   Chanek's score: 2^(k-1) + 2^(k-3) + ... + 2^0.
    //   This is a geometric series: a = 2^0 = 1, r = 4, num_terms = (k-1)/2 + 1 = (k+1)/2.
    //   Sum = 1 * (4^((k+1)/2) - 1) / (4 - 1) = (2^(k+1) - 1) / 3.
    // If k is even: The last coin (1 = 2^0) is taken by Opponent.
    //   Chanek's score: 2^(k-1) + 2^(k-3) + ... + 2^1.
    //   This is a geometric series: a = 2^1 = 2, r = 4, num_terms = (k-2)/2 + 1 = k/2.
    //   Sum = 2 * (4^(k/2) - 1) / (4 - 1) = 2 * (2^k - 1) / 3 = (2^(k+1) - 2) / 3.

    // So, if N is a power of 2:
    // If N = 2^k, and k is odd: Chanek gets (2N - 1) / 3.
    // If N = 2^k, and k is even: Chanek gets (2N - 2) / 3.

    // Let's test these formulas:
    // N=1 (k=0, even): Chanek gets (2*1 - 2) / 3 = 0. Incorrect. Chanek gets 1.
    // N=2 (k=1, odd): Chanek gets (2*2 - 1) / 3 = 1. Correct.
    // N=4 (k=2, even): Chanek gets (2*4 - 2) / 3 = 2. Incorrect. Chanek gets 3.
    // N=8 (k=3, odd): Chanek gets (2*8 - 1) / 3 = 5. Correct.

    // The issue is that the formulas are for the sum of coins taken *during* the "take half" phase.
    // When N=1, Chanek takes 1.
    // When N=4: C takes 2. N=2. O takes 1. N=1. C takes 1. N=0.
    // C: 2+1=3. O: 1.
    // The formulas are for the sum of coins taken by Chanek *if the game ends when N=0*.
    // The problem is that the last coin is always taken by the player whose turn it is when N=1.
    // If N=1, current player takes 1.
    // If N=2, current player takes 1. Next player takes 1.
    // If N=4, current player takes 2. N=2. Next player takes 1. N=1. Current player takes 1.
    // So, for N=4, C takes 2. N=2. O takes 1. N=1. C takes 1.
    // C: 2+1=3. O: 1.

    // The strategy is:
    // If N is odd: Chanek takes 1. N becomes N-1. Chanek's score += 1.
    // If N is even:
    //   If N is a power of 2:
    //     Chanek takes N/2. N becomes N/2. Chanek's score += N/2.
    //     Now N is 2^(k-1). It's Opponent's turn.
    //     Opponent will take N/2. N becomes N/4.
    //     Chanek will take N/8. N becomes N/8.
    //     ...
    //     This continues until N=1.
    //     The total coins taken by Chanek in this "take half" sequence (starting from N/2) is:
    //     (N/2) + (N/8) + (N/32) + ...
    //     The total coins taken by Opponent in this "take half" sequence is:
    //     (N/4) + (N/16) + (N/64) + ...
    //     The last coin (1) is taken by Chanek if k-1 is even (i.e., k is odd).
    //     The last coin (1) is taken by Opponent if k-1 is odd (i.e., k is even).
    //     So, if k is odd, Chanek gets (N/2) + (N/8) + ... + 1. This is (N - 1) / 3.
    //     If k is even, Chanek gets (N/2) + (N/8) + ... + 2. This is (N - 2) / 3.
    //     So, if N is a power of 2 (N=2^k):
    //     If k is odd: Chanek gets N/2 + (N/2 - 1)/3 = (3N/2 + N/2 - 1)/3 = (2N - 1)/3.
    //     If k is even: Chanek gets N/2 + (N/2 - 2)/3 = (3N/2 + N/2 - 2)/3 = (2N - 2)/3.
    //     Let's test this:
    //     N=1 (k=0, even): Chanek gets (2*1 - 2)/3 = 0. Incorrect. Chanek gets 1.
    //     N=2 (k=1, odd): Chanek gets (2*2 - 1)/3 = 1. Correct.
    //     N=4 (k=2, even): Chanek gets (2*4 - 2)/3 = 2. Incorrect. Chanek gets 3.
    //     N=8 (k=3, odd): Chanek gets (2*8 - 1)/3 = 5. Correct.

    // The formulas are still off for N=1 and N=4.
    // The issue is that the "take half" strategy is only optimal if N is not 1.
    // If N=1, the player takes 1.
    // If N=2, player takes 1. Opponent takes 1.
    // If N=4, player takes 2. N=2. Opponent takes 1. N=1. Player takes 1.
    // So, for N=4, Chanek gets 2+1=3. Opponent gets 1.
    // For N=1, Chanek gets 1.
    // For N=2, Chanek gets 1.

    // Let's use a direct simulation of the greedy strategy.
    // Chanek's turn:
    // If N is odd, take 1.
    // If N is even, take N/2.
    // Opponent's turn:
    // If N is odd, take 1.
    // If N is even, take N/2.

    // This is the strategy that both players will follow.
    // Let's simulate this.
    bool chanek_turn = true;
    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_score += 1;
                n -= 1;
            } else { // N is even
                // Check if N is a power of 2.
                // If N is a power of 2, say 2^k, and k is even (e.g., N=4, 16, 64, ...).
                // Chanek takes N/2. N becomes N/2.
                // Opponent takes N/4. N becomes N/4.
                // Chanek takes N/8. N becomes N/8.
                // ...
