// Function to get prime factors of a number
std::map<long long, int> get_prime_factors(long long n) {
    std::map<long long, int> factors;
    for (long long i = 2; i * i <= n; ++i) {
        while (n % i == 0) {
            factors[i]++;
            n /= i;
        }
    }
    if (n > 1) {
        factors[n]++;
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x | p and x % q != 0.
        // This means x must be p / (some factor of q that makes p/factor not divisible by q)
        // Or more generally, x = p / k where k is a divisor of p, and (p/k) % q != 0.
        // We want to maximize p/k, which means minimizing k.
        // The smallest k is 1, but p/1 = p, and p % q == 0.
        // So we need to find a k such that p/k is not divisible by q.

        // Let q = f1^a1 * f2^a2 * ... * fk^ak
        // If p is divisible by q, then p must have at least as many factors of fi as q for each fi.
        // To make x = p / (some factor) not divisible by q, we need to remove enough factors of some fi
        // from p such that x no longer has enough factors of fi to be divisible by q.
        // Specifically, for some prime factor f of q, we need x to have fewer factors of f than q has.

        std::map<long long, int> q_factors = get_prime_factors(q);
        long long max_x = 1;

        for (auto const& [factor, count] : q_factors) {
            // For each prime factor 'factor' of q, we want to find the largest x
            // such that x is a divisor of p, and x has fewer 'factor's than q.
            // To do this, we take p, and divide it by 'factor' repeatedly until it's no longer divisible by q.
            // Let current_p = p.
            // While current_p is divisible by q:
            //   current_p /= factor
            // The resulting current_p is a candidate for x.
            // We want to maximize x, so we take the maximum over all such candidates.

            long long current_p = p;
            while (current_p % q == 0) {
                current_p /= factor;
            }
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

