long long sum_arithmetic_series(long long n) {
    if (n <= 0) return 0;
    long long MOD = 1000000007;
    long long n_mod = n % MOD;
    long long n_plus_1_mod = (n + 1) % MOD;
    long long term1 = (n_mod * n_plus_1_mod) % MOD;
    long long inv2 = 500000004; // Modular inverse of 2 modulo 10^9 + 7
    return (term1 * inv2) % MOD;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_{k=1}^{a} k
    long long sum_k = sum_arithmetic_series(a);

    // Calculate sum_{r=1}^{b-1} r
    long long sum_r = sum_arithmetic_series(b - 1);

    // Calculate sum_{k=1}^{a} sum_{r=1}^{b-1} (r * k * b + r)
    // This is sum_{k=1}^{a} (k * b * sum_{r=1}^{b-1} r + sum_{r=1}^{b-1} r)
    // Which is sum_{k=1}^{a} ((k * b + 1) * sum_{r=1}^{b-1} r)
    // Which is (sum_{r=1}^{b-1} r) * sum_{k=1}^{a} (k * b + 1)
    // Which is (sum_{r=1}^{b-1} r) * (b * sum_{k=1}^{a} k + sum_{k=1}^{a} 1)
    // Which is (sum_{r=1}^{b-1} r) * (b * sum_{k=1}^{a} k + a)

    long long term_b_sum_k = (b % MOD * sum_k) % MOD;
    long long term_a = a % MOD;
    long long sum_k_b_plus_1 = (term_b_sum_k + term_a) % MOD;

    long long total_sum = (sum_r * sum_k_b_plus_1) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

