#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <algorithm>

long long binToDec(const std::string& s, int start, int end) {
    long long val = 0;
    long long power = 1;
    for (int i = end; i >= start; --i) {
        if (s[i] == '1') {
            val += power;
        }
        if (i > start && power > 2000000000000000000LL / 2) { // Prevent overflow for power
            return 2000000000000000000LL; // Return a value larger than any possible length
        }
        power *= 2;
    }
    return val;
}

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    // Precompute positions of '1's
    std::vector<int> ones_pos;
    for (int i = 0; i < n; ++i) {
        if (s[i] == '1') {
            ones_pos.push_back(i);
        }
    }

    // Iterate through all possible starting positions l
    for (int l = 0; l < n; ++l) {
        // Case 1: Substrings starting with '0'
        // These substrings must have s[l] = '0'.
        // The value f(s_l...s_r) is determined by the first '1' after l.
        // If there is no '1' after l, f(s_l...s_r) = 0.
        // If s[l] is '0', we need to find the first '1' at or after l.
        // If s[l] is '1', this loop is skipped.
        if (s[l] == '0') {
            // Find the first '1' at or after l
            auto it = std::lower_bound(ones_pos.begin(), ones_pos.end(), l);
            if (it == ones_pos.end()) { // No '1' found at or after l
                // All substrings s[l...r] will be all '0's.
                // f(s[l...r]) = 0.
                // Condition: r - l + 1 = 0. This is impossible as length >= 1.
                // So, no good substrings if all are '0's.
            } else {
                int first_one_idx = *it;
                // For any r such that l <= r < first_one_idx, s[l...r] consists only of '0's.
                // f(s[l...r]) = 0. Length r - l + 1.
                // Condition: r - l + 1 = 0. Impossible.

                // For substrings s[l...r] where r >= first_one_idx:
                // The value f(s[l...r]) will be positive.
                // The leading '0's (from l to first_one_idx - 1) don't affect the value.
                // The value is f(s[first_one_idx...r]).
                // The length is r - l + 1.
                // Condition: r - l + 1 = f(s[first_one_idx...r]).
                // Let k = first_one_idx.
                // We need r - l + 1 = f(s[k...r]).
                // The maximum possible value for f(s[k...r]) is 2^(r-k+1) - 1.
                // The minimum possible value for f(s[k...r]) is 2^(r-k).
                // So, r - l + 1 must be roughly in the range [2^(r-k), 2^(r-k+1)-1].
                // This implies r - k + 1 (the length of the effective binary part)
                // cannot be too large compared to r - l + 1.
                // Specifically, r - k + 1 <= 20 (approx) because 2^20 is ~10^6,
                // and r - l + 1 <= n = 2*10^5.
                // So, r - k + 1 must be small.
                // This means r must be close to k.

                // Iterate r from first_one_idx up to min(n-1, first_one_idx + MAX_LEN_FOR_VAL - 1)
                // MAX_LEN_FOR_VAL is chosen such that 2^MAX_LEN_FOR_VAL is around n.
                // 2^18 = 262144, 2^17 = 131072. So, MAX_LEN_FOR_VAL can be around 18-20.
                // Let's use 20 for safety.
                for (int r = first_one_idx; r < n && r - first_one_idx + 1 <= 20; ++r) {
                    long long current_val = 0;
                    for (int i = first_one_idx; i <= r; ++i) {
                        current_val = current_val * 2 + (s[i] - '0');
                    }
                    if (current_val == (long long)(r - l + 1)) {
                        good_substrings_count++;
                    }
                }
            }
        }

        // Case 2: Substrings starting with '1'
        // These substrings must have s[l] = '1'.
        // The value f(s_l...s_r) is at least 2^(r-l).
        // The length is r - l + 1.
        // Condition: r - l + 1 = f(s_l...s_r).
        // Since f(s_l...s_r) >= 2^(r-l), we must have r - l + 1 >= 2^(r-l).
        // This inequality holds only for small values of (r-l).
        // For r-l = 0, 1 >= 2^0 = 1. (s[l...l])
        // For r-l = 1, 2 >= 2^1 = 2. (s[l...l+1])
        // For r-l = 2, 3 >= 2^2 = 4. (False)
        // So, r-l can be at most 1 for this condition to potentially hold.
        // This means the length r-l+1 can be at most 2.
        // So, we only need to check substrings of length 1 and 2 starting with '1'.

        if (s[l] == '1') {
            // Substring s[l...l] (length 1)
            // f(s[l...l]) = 1.
            // Condition: 1 = 1. Always true if s[l] = '1'.
            good_substrings_count++;

            // Substring s[l...l+1] (length 2)
            // Only if l+1 < n.
            if (l + 1 < n) {
                // f(s[l...l+1]) can be 10_2 = 2 or 11_2 = 3.
                // Condition: 2 = f(s[l...l+1]).
                // This is true if s[l...l+1] is "10".
                if (s[l+1] == '0') { // s[l...l+1] is "10"
                    good_substrings_count++;
                }
            }
        }
    }

    std::cout << good_substrings_count << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_diff = 0;
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_diff++;
        } else {
            initial_diff--;
        }
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // diff_L[i] = (count of 1s - count of 2s) in jars [1, i]
    // We are interested in jars [i, n] being eaten, so we need prefix sums from right to left for the left part.
    // Let's define diff_L[k] as the balance of jars [n-k+1, n]
    // This means k jars are eaten from the left.
    // diff_L[0] = 0 (no jars eaten from left)
    // diff_L[1] = balance of jar n
    // diff_L[k] = balance of jars n, n-1, ..., n-k+1
    // This is equivalent to (balance of jars [1, n] - balance of jars [1, n-k])
    // Or, more simply, let's compute balance of jars [1, i] for i from 1 to n.
    // And balance of jars [i, n] for i from 1 to n.
    // Let's use a map to store the balance of the remaining jars on the left side.
    // `left_balances[k]` stores the balance (S-B) if `k` jars are eaten from the left.
    // `k` jars eaten from left means jars `n, n-1, ..., n-k+1` are eaten.
    // The remaining jars on the left are `1, ..., n-k`.
    // `left_balances[k]` will store the balance of jars `1, ..., n-k`.
    // `left_balances[0]` stores the balance of jars `1, ..., n`.
    // `left_balances[n]` stores the balance of 0 jars, which is 0.

    std::map<int, int> left_balances; // balance -> k (number of jars eaten from left)
    int current_balance_left = 0;
    // Calculate balance for jars [1, n]
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            current_balance_left++;
        } else {
            current_balance_left--;
        }
    }
    // left_balances[0] stores the balance of jars [1, n]
    left_balances[current_balance_left] = 0;

    // Now, simulate eating jars from the left, from n down to 1.
    // When we eat jar `n-k+1`, the balance of remaining jars `1, ..., n-k` changes.
    // The balance of jars `1, ..., n-k` is `current_balance_left - (balance of jar n-k+1)`.
    // We iterate `k` from 1 to `n`.
    // `k` is the number of jars eaten from the left.
    // The jar being eaten is `a[n-k]`.
    for (int k = 1; k <= n; ++k) {
        int jar_idx_eaten = n - k; // 0-indexed
        if (a[jar_idx_eaten] == 1) {
            current_balance_left--;
        } else {
            current_balance_left++;
        }
        // Store the minimum k for this balance
        if (left_balances.find(current_balance_left) == left_balances.end()) {
            left_balances[current_balance_left] = k;
        }
    }

    // Calculate prefix sums for the right side (jars n+1 to 2n)
    // `right_balances[k]` stores the balance (S-B) if `k` jars are eaten from the right.
    // `k` jars eaten from right means jars `n+1, n+2, ..., n+k` are eaten.
    // The remaining jars on the right are `n+k+1, ..., 2n`.
    // `right_balances[0]` stores the balance of jars `n+1, ..., 2n`.
    // `right_balances[n]` stores the balance of 0 jars, which is 0.

    std::map<int, int> right_balances; // balance -> k (number of jars eaten from right)
    int current_balance_right = 0;
    // Calculate balance for jars [n+1, 2n]
    for (int i = n; i < 2 * n; ++i) {
        if (a[i] == 1) {
            current_balance_right++;
        } else {
            current_balance_right--;
        }
    }
    // right_balances[0] stores the balance of jars [n+1, 2n]
    right_balances[current_balance_right] = 0;

    // Now, simulate eating jars from the right, from n+1 up to 2n.
    // When we eat jar `n+k`, the balance of remaining jars `n+k+1, ..., 2n` changes.
    // The balance of jars `n+k+1, ..., 2n` is `current_balance_right - (balance of jar n+k)`.
    // We iterate `k` from 1 to `n`.
    // `k` is the number of jars eaten from the right.
    // The jar being eaten is `a[n+k-1]`.
    for (int k = 1; k <= n; ++k) {
        int jar_idx_eaten = n + k - 1; // 0-indexed
        if (a[jar_idx_eaten] == 1) {
            current_balance_right--;
        } else {
            current_balance_right++;
        }
        // Store the minimum k for this balance
        if (right_balances.find(current_balance_right) == right_balances.end()) {
            right_balances[current_balance_right] = k;
        }
    }

    int min_eaten = 2 * n; // Max possible jars to eat

    // Iterate through all possible balances for the left side
    // For each `(balance_L, k_L)` pair, we need to find a `(balance_R, k_R)` pair
    // such that `balance_L + balance_R = initial_diff`.
    // This means `balance_R = initial_diff - balance_L`.
    for (auto const& [balance_L, k_L] : left_balances) {
        int target_balance_R = initial_diff - balance_L;
        if (right_balances.count(target_balance_R)) {
            int k_R = right_balances[target_balance_R];
            min_eaten = std::min(min_eaten, k_L + k_R);
        }
    }

    std::cout << min_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

bool check(long long x, int n, int m, const std::vector<int>& a) {
    long long prev_val = 0; // The target value for a[0] must be at least 0.
                            // For a[i], its target value must be at least prev_val.

    for (int i = 0; i < n; ++i) {
        long long current_a = a[i];

        // Case 1: a[i] is already >= prev_val.
        // We need to ensure that a[i] (after operations) is >= prev_val.
        // If a[i] >= prev_val, we can potentially keep its value as a[i]
        // or increment it to (a[i] + k) mod m where k <= x.
        // The smallest possible value for a[i] (after operations) that is >= prev_val
        // is a[i] itself, if a[i] >= prev_val.
        // If a[i] < prev_val, we must increment it.

        if (current_a >= prev_val) {
            // If current_a is already >= prev_val, we have two options:
            // 1. Keep current_a as is. This requires 0 increments for a[i].
            //    This is possible if 0 <= x.
            // 2. Increment current_a to (current_a + k) mod m.
            //    If (current_a + k) mod m < prev_val, this means we "wrapped around".
            //    This happens if current_a + k >= m.
            //    The value (current_a + k) mod m must be >= prev_val.
            //    This is only possible if current_a + k >= m + prev_val.
            //    The number of increments needed for this is k.
            //    The minimum k for this is m - current_a + prev_val.
            //    If this k is <= x, then we can achieve prev_val by wrapping around.
            //    However, if current_a >= prev_val, we don't need to wrap around.
            //    We can just keep current_a as is, which requires 0 increments.
            //    So, if current_a >= prev_val, we don't need to do anything special
            //    unless we are forced to wrap around to satisfy prev_val.
            //    The only way we are forced to wrap around is if prev_val is very large,
            //    but prev_val is always <= m-1.
            //    So, if current_a >= prev_val, we can just use current_a as the new prev_val.
            //    This requires 0 increments for a[i].
            //    The only exception is if current_a + x < m + prev_val.
            //    This means even with x increments, we cannot reach prev_val by wrapping around.
            //    But we don't need to wrap around if current_a >= prev_val.
            //    So, if current_a >= prev_val, we can always satisfy the condition
            //    by not incrementing a[i] (0 operations), and setting prev_val = current_a.
            //    The only case where we *must* increment is if current_a + x < m + prev_val.
            //    This means that even if we increment a[i] by x, it's still less than prev_val
            //    if we consider the "wrapped around" value.
            //    Example: m=7, a[i]=6, prev_val=0, x=0. current_a >= prev_val. OK. prev_val=6.
            //    Example: m=7, a[i]=0, prev_val=6, x=0. current_a < prev_val. NOT OK.
            //    Example: m=7, a[i]=0, prev_val=6, x=1.
            //      current_a < prev_val.
            //      Need to increment.
            //      Target value must be >= prev_val.
            //      (current_a + k) mod m >= prev_val.
            //      Smallest k is m - current_a + prev_val.
            //      k = 7 - 0 + 6 = 13. This is too large.
            //      This means we need to reach prev_val by wrapping around.
            //      The value (current_a + k) mod m must be >= prev_val.
            //      This means current_a + k must be >= m + prev_val.
            //      So k >= m + prev_val - current_a.
            //      If current_a = 0, prev_val = 6, m = 7. k >= 7 + 6 - 0 = 13.
            //      This is not right.
            //      The value (a[i] + k) mod m must be >= prev_val.
            //      If a[i] < prev_val, we must increment it.
            //      The smallest value we can achieve is a[i] + 0.
            //      The largest value we can achieve is (a[i] + x) mod m.
            //      If a[i] + x < m, then the range of values is [a[i], a[i]+x].
            //      If a[i] + x >= m, then the range of values is [0, (a[i]+x) mod m] U [a[i], m-1].
            //      This is equivalent to saying we can achieve any value v such that
            //      v = (a[i] + k) mod m for some 0 <= k <= x.

            // Let's simplify. We need to find a k (0 <= k <= x) such that (a[i] + k) mod m >= prev_val.
            // If a[i] >= prev_val:
            //   We can choose k=0. Then (a[i]+0) mod m = a[i] >= prev_val. This is valid.
            //   So we can set prev_val = a[i].
            //   However, we also have the option to increment a[i] by some k.
            //   If we increment a[i] by k, and it wraps around, i.e., a[i]+k >= m,
            //   then (a[i]+k) mod m could be smaller than prev_val.
            //   Example: m=7, a[i]=6, prev_val=0, x=1.
            //   If we choose k=0, new prev_val=6. OK.
            //   If we choose k=1, (6+1) mod 7 = 0. This is also >= prev_val (0).
            //   So we can choose 0 as the new prev_val.
            //   We want to pick the smallest possible value for a[i] (after operations)
            //   that is >= prev_val.
            //   If a[i] >= prev_val, we can always pick a[i] itself (by using 0 operations).
            //   This is the smallest possible value >= prev_val.
            //   The only time we *cannot* pick a[i] is if a[i] is too large, and we are forced
            //   to wrap around to satisfy the condition.
            //   This happens if a[i] + x < m + prev_val.
            //   No, this is not right.
            //   If a[i] >= prev_val, we can always choose to not increment a[i] (k=0).
