#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;

        std::vector<long long> costs;
        long long current_n = 1;
        long long current_cost = 1;

        while (current_cost <= x) {
            costs.push_back(current_cost);
            current_n = current_n * 2 + 1;
            current_cost = current_n * (current_n + 1) / 2;
        }

        int count = 0;
        for (int i = costs.size() - 1; i >= 0; --i) {
            if (x >= costs[i]) {
                x -= costs[i];
                count++;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

