// Using long long for y and intermediate sums to prevent overflow
// as a_i can be up to 10^9 and y can accumulate multiple such values.
// n can be up to 2*10^5.

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // a_1 is determined by the loop variable i.
    // a_2 to a_n are given.
    // We use a 0-indexed vector for convenience, so a_idx corresponds to a[idx-1].
    // a_val[0] will be unused, a_val[1] corresponds to a_2, ..., a_val[n-1] corresponds to a_n.
    std::vector<long long> a_val(n); 
    for (int k = 1; k < n; ++k) {
        std::cin >> a_val[k];
    }

    // dp[k] stores the final y value if the program starts with x=k, y=0
    // and the first operation is x = x + a_k, y = y + a_k.
    // This is effectively the state after the first "step 2" operation.
    // dp[k] will store the total y accumulated from this point until termination.
    // We initialize with -2 to indicate not computed yet, -1 for infinite loop.
    std::vector<long long> dp(n + 1, -2);

    // Iterate backwards from n to 2.
    // This allows us to compute dp[k] using values dp[k + a_k] or dp[k - a_k]
    // which would have already been computed if they are larger than k.
    for (int k = n; k >= 2; --k) {
        long long current_a_k = a_val[k-1]; // a_val is 0-indexed, a_k is a_val[k-1]

        long long next_x = k + current_a_k;
        long long current_y_contribution = current_a_k;

        if (next_x <= 0 || next_x > n) {
            // Terminates after first step 2.
            // y = a_k (from step 2) + a_k (from step 3)
            dp[k] = current_y_contribution + current_a_k;
        } else {
            // Continues to step 3, then next iteration.
            // The x value for the next iteration is next_x - a_next_x.
            // The y value accumulated from this point is current_y_contribution + a_next_x + dp[next_x].
            // However, dp[next_x] is defined as the total y accumulated starting from x=next_x
            // after the first step 2 operation (x = next_x + a_next_x, y = y + a_next_x).
            // So, if we are at x=k, and we transition to x=next_x, the y accumulated is:
            // a_k (from step 2) + a_next_x (from step 3) + dp[next_x]
            // This is incorrect. Let's re-evaluate the state definition.

            // Let dp[k] be the total y accumulated if the program starts at x=k, y=0
            // and the first operation is x = x + a_k, y = y + a_k.
            // This means dp[k] is the total y from the point where x is k, and we are about to execute step 2.

            // If we are at x=k, y=0:
            // 1. x = k + a_k, y = a_k. Let this be (x_prime, y_prime).
            //    If x_prime <= 0 or x_prime > n, program terminates. Total y = a_k.
            //    This is not correct. The problem states:
            //    "The program increases both x and y by a value equal to a_x simultaneously." (Step 2)
            //    "The program now increases y by a_x while decreasing x by a_x." (Step 3)
            //    "The program executes steps 2 and 3 (first step 2, then step 3) repeatedly until it terminates."

            // Let's redefine dp[k] as the total y accumulated if the program starts at x=k, y=0
            // and we are about to execute Step 2.
            // So, for a given k:
            // Current x = k, current y = 0.
            // Step 2: x_new = k + a_k, y_new = a_k.
            // If x_new <= 0 or x_new > n, program terminates. Total y = a_k.
            // Step 3: x_final = x_new - a_new_x (where a_new_x is a_val[x_new-1]), y_final = y_new + a_new_x.
            // If x_final <= 0 or x_final > n, program terminates. Total y = a_k + a_new_x.
            // Otherwise, the program continues from (x_final, y_final) as the new (x, y) for the next iteration.
            // The total y from this point onwards would be y_final + dp[x_final].

            // Let's use a slightly different DP state:
            // dp[k] = total y accumulated starting from x=k, y=0, assuming a_k is the value at current x.
            // This is exactly what we need for the initial calls.

            // For a given k:
            // Let current_a_k = a_val[k-1].
            // x_after_step2 = k + current_a_k
            // y_after_step2 = current_a_k

            // If x_after_step2 <= 0 or x_after_step2 > n:
            //    dp[k] = y_after_step2 (program terminates here)
            // Else:
            //    x_after_step3 = x_after_step2 - a_val[x_after_step2 - 1]
            //    y_after_step3 = y_after_step2 + a_val[x_after_step2 - 1]
            //    If x_after_step3 <= 0 or x_after_step3 > n:
            //        dp[k] = y_after_step3 (program terminates here)
            //    Else:
            //        If dp[x_after_step3] == -1 (infinite loop):
            //            dp[k] = -1
            //        Else if dp[x_after_step3] == -2 (not computed yet, implies cycle):
            //            dp[k] = -1 (infinite loop)
            //        Else:
            //            dp[k] = y_after_step3 + dp[x_after_step3]

            // This DP definition is correct.
            // The loop `for (int k = n; k >= 2; --k)` ensures that `dp[x_after_step3]` is already computed
            // if `x_after_step3 > k`. If `x_after_step3 < k`, it's a cycle.

            long long val_at_k = a_val[k-1];
            long long x_after_step2 = k + val_at_k;
            long long y_accumulated = val_at_k;

            if (x_after_step2 <= 0 || x_after_step2 > n) {
                dp[k] = y_accumulated;
            } else {
                long long val_at_x_after_step2 = a_val[x_after_step2 - 1];
                long long x_after_step3 = x_after_step2 - val_at_x_after_step2;
                y_accumulated += val_at_x_after_step2;

                if (x_after_step3 <= 0 || x_after_step3 > n) {
                    dp[k] = y_accumulated;
                } else {
                    if (dp[x_after_step3] == -2) { // Not computed yet, implies a cycle
                        dp[k] = -1; // Infinite loop
                    } else if (dp[x_after_step3] == -1) { // Already known to be infinite loop
                        dp[k] = -1;
                    } else {
                        dp[k] = y_accumulated + dp[x_after_step3];
                    }
                }
            }
        }
    }

    // Now, for each i from 1 to n-1, we need to run the program.
    // a_1 is i.
    for (int i = 1; i < n; ++i) {
        long long val_at_1 = i; // This is a_1 for this run
        long long x_after_step2 = 1 + val_at_1;
        long long y_accumulated = val_at_1;

        if (x_after_step2 <= 0 || x_after_step2 > n) {
            std::cout << y_accumulated << "\n";
        } else {
            long long val_at_x_after_step2 = a_val[x_after_step2 - 1];
            long long x_after_step3 = x_after_step2 - val_at_x_after_step2;
            y_accumulated += val_at_x_after_step2;

            if (x_after_step3 <= 0 || x_after_step3 > n) {
                std::cout << y_accumulated << "\n";
            } else {
                // We need to check for cycles involving x_after_step3.
                // If x_after_step3 is 1, it's a cycle back to the start.
                // If x_after_step3 is > 1, we can use the precomputed dp values.
                if (x_after_step3 == 1) { // Cycle back to x=1
                    std::cout << -1 << "\n";
                } else if (dp[x_after_step3] == -1) { // Known infinite loop
                    std::cout << -1 << "\n";
                } else {
                    std::cout << y_accumulated + dp[x_after_step3] << "\n";
                }
            }
        }
    }

    return 0;
}

