    std::string a, b;
    std::cin >> a >> b;

    int ones_a = count_ones(a);
    int ones_b = count_ones(b);

    // If initial 'a' has an odd number of ones, its parity is 1.
    // If initial 'a' has an even number of ones, its parity is 0.
    // After appending parity, the number of ones might change.
    // If parity is 1, ones_a becomes ones_a + 1.
    // If parity is 0, ones_a remains ones_a.
    // So, the maximum number of ones we can achieve in 'a' (before removing prefix)
    // is ones_a + 1 if ones_a is odd, or ones_a if ones_a is even.
    // This is equivalent to (ones_a + (ones_a % 2 == 1 ? 1 : 0)).
    // Or simply, ones_a + (ones_a % 2).
    // This is the maximum number of ones we can have in 'a' if we append its parity once.
    // If we append parity multiple times, the number of ones can only increase or stay the same.
    // For example, 101 (2 ones, even parity 0) -> 1010 (2 ones, even parity 0) -> 10100 (2 ones, even parity 0)
    // For example, 10 (1 one, odd parity 1) -> 101 (2 ones, even parity 0) -> 1010 (2 ones, even parity 0)
    // So, if the initial 'a' has an odd number of ones, we can always make it have an even number of ones
    // by appending '1'. After that, it will always have an even number of ones and append '0'.
    // If the initial 'a' has an even number of ones, it will always append '0' and maintain an even number of ones.
    // Therefore, if 'a' initially has an odd number of ones, we can effectively consider it as having
    // (ones_a + 1) ones by appending its parity '1'.
    // If 'a' initially has an even number of ones, it will always have 'ones_a' ones.
    // So, the effective maximum number of ones we can achieve in 'a' (before removing prefix)
    // is ones_a if ones_a is even, and ones_a + 1 if ones_a is odd.
    // This can be written as ones_a + (ones_a % 2).

    int effective_ones_a = ones_a + (ones_a % 2);

    // Condition 1: The number of ones in 'b' must be less than or equal to
    // the maximum possible number of ones we can achieve in 'a' (after appending parity).
    if (ones_b > effective_ones_a) {
        std::cout << "NO\n";
        return 0;
    }

    // Condition 2: The length of 'b' must be less than or equal to the length of 'a'
    // after 'a' has been extended enough to potentially contain 'b' as a suffix.
    // We can always extend 'a' to be as long as we want using the parity operation.
    // So, if |b| <= |a|, we just need to check if 'b' can be formed by removing prefix from 'a'.
    // If |b| > |a|, we need to extend 'a' by at least |b| - |a| operations.
    // The 'remove first character' operation means 'b' must be a suffix of some
    // string 'a_prime' that can be generated from 'a'.
    // Since we can always append parity, we can always make 'a' long enough.
    // The only constraint is the number of ones.

    std::cout << "YES\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // delta_sum[i] stores the sum of all 'd' values from type 1 operations
    // that affect index i.
    std::vector<long long> delta_sum(n, 0);

    // For each type 2 operation (2 l r m), we know that for any j in [l, r],
    // a_0[j] + delta_sum_at_op_time[j] <= m.
    // This implies a_0[j] <= m - delta_sum_at_op_time[j].
    // We want to maximize a_0[j] to satisfy constraints, so we take the minimum
    // of these upper bounds.
    // Initialize a_0[j] to a very large value (effectively infinity)
    // and then take min with (m - delta_sum_at_op_time[j]).
    std::vector<long long> a0_upper_bound(n, 2000000000000000000LL); // A sufficiently large number

    // Iterate through operations in reverse to calculate delta_sum_at_op_time
    // and update a0_upper_bound.
    // When processing an operation at index `k` (0-indexed), `delta_sum`
    // should reflect the sum of `d` values from operations `k+1` to `m-1`.
    // This is because `a_0[j] + (sum of d's up to op k) <= m_k`.
    // Let `S_k[j]` be the sum of `d` values from operations `0` to `k-1` that affect `j`.
    // Then `a_0[j] + S_k[j] <= m_k`.
    // So `a_0[j] <= m_k - S_k[j]`.
    // We need `S_k[j]`.
    // Let's rephrase: `a_final[j] = a_0[j] + total_delta[j]`.
    // `a_current[j] = a_0[j] + delta_applied_so_far[j]`.
    // For a type 2 op `k`: `max_{p=l_k}^{r_k} (a_0[p] + delta_applied_so_far_at_k[p]) = m_k`.
    // This means `a_0[p] + delta_applied_so_far_at_k[p] <= m_k` for all `p` in `[l_k, r_k]`.
    // So `a_0[p] <= m_k - delta_applied_so_far_at_k[p]`.

    // Let's calculate `delta_applied_so_far_at_k[p]` for each `k` and `p`.
    // This can be done by iterating forward.
    // `current_delta[j]` will store `delta_applied_so_far_at_k[j]` for the current `k`.
    std::vector<long long> current_delta(n, 0);
    std::vector<std::vector<long long>> delta_at_op(m, std::vector<long long>(n));

    for (int i = 0; i < m; ++i) {
        delta_at_op[i] = current_delta; // Store delta state before applying op i
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        }
    }

    // Now, use the stored delta states to update a0_upper_bound
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 2) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                a0_upper_bound[j] = std::min(a0_upper_bound[j], ops[i].val - delta_at_op[i][j]);
            }
        }
    }

    // Initialize a_0 with the calculated upper bounds.
    // If an element has no upper bound from type 2 ops, it can be 0.
    // The problem states |a_i| <= 10^9.
    // The upper bound could be very large if no type 2 op constrained it.
    // Let's cap it at 10^9 if it's still very large.
    std::vector<long long> a0(n);
    for (int i = 0; i < n; ++i) {
        if (a0_upper_bound[i] > 1000000000LL) { // If no constraint or very loose, set to 10^9
            a0[i] = 1000000000LL;
        } else if (a0_upper_bound[i] < -1000000000LL) { // If upper bound is too low, set to -10^9
            a0[i] = -1000000000LL;
        } else {
            a0[i] = a0_upper_bound[i];
        }
    }

    // Verify the solution
    std::vector<long long> current_a(n);
    for (int i = 0; i < n; ++i) {
        current_a[i] = a0[i];
    }

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_a[j] += ops[i].val;
            }
        } else { // Type 2 operation
            long long max_val = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, current_a[j]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a0[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    int id;
    long long v, d, p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_ids.push_back(children[i].id);
        children[i].in_line = false; // This child is now cured

        long long current_v_cry = children[i].v;
        long long total_d_cry_from_leaving = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply confidence reduction from the current child's v_cry
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry = std::max(0LL, current_v_cry - 1);
            }

            // Apply confidence reduction from children who left earlier
            children[j].p -= total_d_cry_from_leaving;

            // Check if child j leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_cry_from_leaving += children[j].d;
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <set>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    for (char c = 'a'; c <= 'z'; ++c) {
        adj[c] = std::set<char>();
    }

    bool possible = true;
    for (size_t i = 0; i < s.length() - 1; ++i) {
        char u = s[i];
        char v = s[i+1];
        adj[u].insert(v);
        adj[v].insert(u);
    }

    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj[c].size() > 2) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    std::string layout_str = "";
    std::vector<bool> visited(26, false); // 'a' -> 0, 'b' -> 1, etc.

    // Find a starting point (a character with only one neighbor in the password graph)
    char start_char = '\0';
    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj[c].size() == 1) {
            start_char = c;
            break;
        }
    }

    // If all characters in the password graph have 2 neighbors (cycle) or 0 neighbors (isolated)
    // and there are no 1-neighbor nodes, pick any character from the password that has neighbors.
    if (start_char == '\0') {
        for (char c = 'a'; c <= 'z'; ++c) {
            if (!adj[c].empty()) { // If it's part of the password graph
                start_char = c;
                break;
            }
        }
    }

    // If start_char is still '\0', it means the password was empty or all characters are isolated.
    // In this case, any layout is fine. We'll handle this by just appending all unvisited chars later.

    if (start_char != '\0') {
        char current_char = start_char;
        char prev_char = '\0'; // Sentinel for the first step

        while (current_char != '\0' && !visited[current_char - 'a']) {
            layout_str += current_char;
            visited[current_char - 'a'] = true;

            char next_char = '\0';
            for (char neighbor : adj[current_char]) {
                if (neighbor != prev_char) {
                    next_char = neighbor;
                    break;
                }
            }
            prev_char = current_char;
            current_char = next_char;
        }
    }

    // Append any remaining unvisited characters (those not in the password or isolated)
    for (char c = 'a'; c <= 'z'; ++c) {
        if (!visited[c - 'a']) {
            layout_str += c;
        }
    }

    if (layout_str.length() != 26) {
        // This should ideally not happen if the logic is correct,
        // but as a safeguard, if the constructed string isn't 26 chars, it's an error.
        // Or, more likely, it means the graph was disconnected and we only traversed one component.
        // The current logic for appending unvisited characters should cover this.
        // The only way layout_str.length() != 26 is if there was a cycle in the password graph
        // and we started from a node in that cycle, but then couldn't add all nodes.
        // Let's re-check the cycle condition.
        // If a component is a cycle, all nodes have degree 2.
        // If we start from any node in a cycle, we will traverse the whole cycle.
        // If there are multiple components, we will traverse one.
        // The current logic for `start_char` picks a degree-1 node if available.
        // If not, it picks any node with neighbors.
        // If it picks a node in a cycle, it will traverse the cycle.
        // Then the remaining characters are added.
        // The only way it could be impossible is if there are multiple components that are paths/cycles
        // and they need to be merged, but they can't be.
        // E.g., 'ab' and 'cd'. This would mean 'a'-'b' and 'c'-'d' are separate components.
        // The current algorithm would pick 'a', traverse 'a'-'b', then add 'c', 'd', etc.
        // This is fine.
        // The only true impossibility is if a character has >2 neighbors.
        // So, if we reach here and layout_str.length() != 26, it implies a bug or a missed impossibility case.
        // However, the problem statement implies that if degree > 2 is the only impossibility.
        // Let's assume the current logic for `possible` is sufficient.
        // The only way `layout_str.length() != 26` could happen is if `start_char` was never found,
        // meaning all `adj[c]` were empty, and then `layout_str` would be empty before the loop.
        // But then all 26 chars would be added in the final loop.
        // So, `layout_str.length()` will always be 26.
    }

    std::cout << "YES\n";
    std::cout << layout_str << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    if (n < 3) {
        std::cout << 0 << std::endl;
        return 0;
    }

    std::vector<int> min_r_for_l(n + 1, n + 1); // min_r_for_l[i] stores the minimum r such that s[i..r-1] contains a bad triplet.
                                                // If no such r exists, it's n+1.
                                                // Using 1-based indexing for l, r for consistency with problem statement.
                                                // s[i] corresponds to s_i+1 in problem.

    // Iterate through all possible starting positions x (0-indexed)
    for (int x = 0; x < n; ++x) {
        // Check for k=1
        if (x + 2 < n) {
            if (s[x] == s[x+1] && s[x+1] == s[x+2]) {
                // Found a bad triplet (x, k=1). It covers s[x..x+2].
                // The minimum r for any l <= x is x+2.
                // So, for l from 0 to x, min_r_for_l[l+1] can be updated to x+2+1.
                // We need to find the smallest r for a given l.
                // The current triplet (x, k=1) implies that for any l' <= x, the substring s[l'..x+2] contains this triplet.
                // So, for l' from 0 to x, the minimum r is x+2.
                // We update min_r_for_l[l'+1] = min(min_r_for_l[l'+1], x+2+1).
                // Since we iterate x from left to right, x+2 is increasing.
                // This means for a fixed l', the first x that satisfies l' <= x will give the smallest x+2.
                // So, min_r_for_l[l'+1] = x+2+1 for l' from 0 to x.
                // This is equivalent to setting min_r_for_l[l'+1] = x+3 for l' from 0 to x.
                // The loop below will handle this.
                min_r_for_l[x + 1] = std::min(min_r_for_l[x + 1], x + 3);
            }
        }
        // Check for k=2
        if (x + 4 < n) {
            if (s[x] == s[x+2] && s[x+2] == s[x+4]) {
                // Found a bad triplet (x, k=2). It covers s[x..x+4].
                min_r_for_l[x + 1] = std::min(min_r_for_l[x + 1], x + 5);
            }
        }
        // Check for k=3
        if (x + 6 < n) {
            if (s[x] == s[x+3] && s[x+3] == s[x+6]) {
                // Found a bad triplet (x, k=3). It covers s[x..x+6].
                min_r_for_l[x + 1] = std::min(min_r_for_l[x + 1], x + 7);
            }
        }
    }

    // Propagate minimum r values: if s[l..r] contains a bad triplet, then s[l-1..r] also contains it.
    // So, min_r_for_l[l] <= min_r_for_l[l+1].
    // We want to find the smallest r for each l.
    // Iterate l from n-1 down to 1 (1-indexed).
    // min_r_for_l[l] should be min(min_r_for_l[l], min_r_for_l[l+1]).
    for (int l = n - 1; l >= 1; --l) {
        min_r_for_l[l] = std::min(min_r_for_l[l], min_r_for_l[l + 1]);
    }

    long long total_good_pairs = 0;
    for (int l = 1; l <= n; ++l) {
        if (min_r_for_l[l] <= n) { // If there is at least one r for this l
            total_good_pairs += (n - min_r_for_l[l] + 1);
        }
    }

    std::cout << total_good_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Check for k=1
    // Cut s into s1 and s2. s = s1 + s2.
    // New string s' = s2 + s1.
    // We need s' to be a palindrome and s' != s.
    // Iterate through all possible cut points (n-1 possibilities).
    for (int i = 1; i < n; ++i) {
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string s_prime = s2 + s1;
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // If k=1 didn't work, check for k=2.
    // The problem statement guarantees s is a palindrome.
    // If all characters in s are the same (e.g., "qqqq"),
    // then any rearrangement of its substrings will result in the same string.
    // For example, "qq|qq" -> "qqqq", "q|q|qq" -> "qqqq".
    // In this case, it's impossible to form a new string.
    bool all_same_chars = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_chars = false;
            break;
        }
    }
    if (all_same_chars) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work,
    // then k=2 is always possible.
    // Consider cutting s into s[0...i-1], s[i], s[i+1...n-1].
    // For example, take s[0] as one piece, s[1...n-2] as another, and s[n-1] as the third.
    // Since s is a palindrome, s[0] == s[n-1].
    // Let s = c_0 c_1 ... c_{n-2} c_{n-1}.
    // We can cut it into c_0 | c_1 ... c_{n-2} | c_{n-1}.
    // Rearrange to c_1 ... c_{n-2} | c_0 | c_{n-1}.
    // This forms c_1 ... c_{n-2} c_0 c_{n-1}.
    // Since c_0 = c_{n-1}, this is c_1 ... c_{n-2} c_0 c_0.
    // This is not necessarily a palindrome.

    // A simpler argument for k=2:
    // Since s is a palindrome and not all characters are the same,
    // there must be at least two distinct characters.
    // Consider the string s' formed by taking s[0...n-2] and s[n-1].
    // s = s[0...n-1].
    // s' = s[n-1] + s[0...n-2].
    // This is a cyclic shift.
    // We know s' is not equal to s (otherwise k=1 would have found it).
    // We need to show that we can make s' a palindrome with 2 cuts.
    //
    // The problem states "minimum number of cuts k".
    // If k=1 is not possible, and "Impossible" is not the answer, then k=2 must be the answer.
    // The only case where it's "Impossible" is if all characters are the same.
    // We've already handled that.
    // So if we reach this point, k=1 failed, and it's not "Impossible".
    // Therefore, the answer must be 2.
    //
    // Example: "nolon" (n=5)
    // k=1:
    // "n" + "olon" -> "olonn" (not pal)
    // "no" + "lon" -> "lonno" (not pal)
    // "nol" + "on" -> "onnol" (not pal)
    // "nolo" + "n" -> "nnolo" (not pal)
    // All k=1 attempts fail.
    // Not all chars are same. So output 2.
    //
    // Example: "abacaba" (n=7)
    // k=1:
    // "a" + "bacaba" -> "bacabaa" (not pal)
    // "ab" + "acaba" -> "acabaab" (not pal)
    // "aba" + "caba" -> "cabaaba" (pal!) != "abacaba". So k=1.
    //
    // The logic is:
    // 1. Try k=1. If successful, print 1 and exit.
    // 2. If k=1 fails, check if all characters in s are the same.
    //    If yes, print "Impossible" and exit.
    // 3. Otherwise (k=1 failed, and not all characters are the same),
    //    print 2. This is because it's always possible to make a new palindrome with 2 cuts
    //    if the string is not monochromatic.
    //    For example, take s = A B C B A.
    //    Cut into A | B C B | A. Rearrange to B C B | A | A.
    //    This is B C B A A. Not necessarily a palindrome.
    //    However, the problem states "unite those pieces together to get a new string".
    //    It doesn't say the pieces must be symmetric.
    //    The crucial part is that if s is a palindrome and not all characters are the same,
    //    then s has at least two distinct characters.
    //    Consider s = s_0 s_1 ... s_{n-1}.
    //    Since s is a palindrome, s_i = s_{n-1-i}.
    //    Since not all characters are the same, there exists some i such that s_i != s_0.
    //    Consider the string s' formed by taking s[0...n-2] and s[n-1].
    //    s' = s[n-1] + s[0...n-2].
    //    This is a cyclic shift.
    //    If s' is a palindrome and s' != s, then k=1.
    //    If s' is not a palindrome, or s' == s, then k=1 fails.
    //    The problem is asking for *any* new palindrome, not necessarily a cyclic shift.
    //
    //    The argument for k=2 being always possible (if not all chars are same) is subtle.
    //    Consider s = s_0 s_1 ... s_{n-1}.
    //    Since s is a palindrome, s_0 = s_{n-1}, s_1 = s_{n-2}, etc.
    //    Since not all characters are the same, there must be some s_i != s_j.
    //    Consider the string s_sub = s.substr(0, n/2).
    //    If s_sub is not monochromatic, then we can cut s into s_sub | s_mid | s_sub_rev.
    //    Example: "abacaba". s_sub = "aba". s_mid = "c". s_sub_rev = "aba".
    //    Cut into "a" | "bacab" | "a".
    //    Rearrange to "bacab" | "a" | "a" -> "bacabaa". Not a palindrome.
    //
    //    The problem is simpler: if k=1 doesn't work, and it's not "Impossible", then it must be 2.
    //    The "Impossible" case is only when all characters are the same.
    //    If not all characters are the same, then there exists at least one character `c` such that `s[0] != c`.
    //    Since `s` is a palindrome, `s[0] == s[n-1]`.
    //    Consider the string `s_prefix = s.substr(0, n-1)`.
    //    And `s_suffix = s.substr(1, n-1)`.
    //    Since `s` is a palindrome, `s_prefix` is `s_0 s_1 ... s_{n-2}`.
    //    And `s_suffix` is `s_1 s_2 ... s_{n-1}`.
    //    Since `s_0 = s_{n-1}`, `s_1 = s_{n-2}`, etc.
    //    `s_prefix` is the reverse of `s_suffix`.
    //    `s_prefix = s_0 s_1 ... s_{n-2}`
    //    `s_suffix = s_1 s_2 ... s_0` (reversed)
    //    If `s` is not monochromatic, then `s_prefix` is not equal to `s_suffix`.
    //    Consider cutting `s` into `s[0]` | `s[1...n-1]`.
    //    This is `s_0` | `s_suffix`.
    //    Rearrange to `s_suffix` | `s_0`. This is `s_1 s_2 ... s_{n-1} s_0`.
    //    Since `s_{n-1} = s_0`, this is `s_1 s_2 ... s_0 s_0`.
    //    This is a palindrome if `s_1 s_2 ... s_0` is a palindrome.
    //    This is the same as checking `s_suffix + s_0`.
    //    This is exactly what the k=1 check does for `i=1`.
    //    If `s_suffix + s_0` is a palindrome and `!= s`, then k=1.
    //
    //    The problem statement implies that if k=1 doesn't work and it's not "Impossible", then k=2 is the answer.
    //    This is a common pattern in competitive programming problems where small k values are checked,
    //    and if they fail, a slightly larger k is always possible unless a specific "Impossible" condition is met.
    //    The "Impossible" condition here is indeed when all characters are the same.
    //    If not all characters are the same, then there's at least one character `c` such that `s[0] != c`.
    //    Since `s` is a palindrome, `s[0] == s[n-1]`.
    //    Consider the string `s_mid = s.substr(1, n-2)`.
    //    `s = s[0] + s_mid + s[n-1]`.
    //    Since `s` is a palindrome, `s_mid` is also a palindrome.
    //    If `s_mid` is not monochromatic, we can apply the k=1 logic to `s_mid`.
    //    If `s_mid` is monochromatic, but `s` is not, then `s` must be like `a bbb a`.
    //    Example: "ababa". `s_mid = "bab"`.
    //    Cut "ababa" into "a" | "b" | "aba". Rearrange to "aba" | "b" | "a" -> "ababa". (original)
    //    Cut "ababa" into "a" | "ba" | "ba". Rearrange to "ba" | "a" | "ba" -> "baaba". (palindrome, != original)
    //    This uses 2 cuts.
    //    So, if k=1 fails and not all characters are the same, k=2 is always possible.

    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int head_idx = 0;
    int p_idx = 0;

    while (p_idx < m && head_idx < n) {
        long long current_head_pos = h[head_idx];
        long long current_p_target = p[p_idx];

        // If the current head can't reach the current target p_idx even by moving left T steps,
        // then this head is too far right for this target. We need to use a head further left.
        // But heads are sorted, so this head is the leftmost available.
        // This means this head must cover p_idx.
        // If current_head_pos - T > current_p_target, it means this head cannot reach p_idx.
        // This case should not happen if we are trying to cover p_idx with head_idx.
        // The logic should be: if head_idx can cover p_idx, it should.
        // If it can't, then no head to its right can cover p_idx either.
        // So, if h[head_idx] + T < p[p_idx], then this head cannot cover p[p_idx].
        // We must advance p_idx, but we can't. This means it's impossible.
        // However, the problem is about covering ALL p_j.
        // We should try to cover p_idx with head_idx.
        // The head at h[head_idx] can cover the range [h[head_idx] - T, h[head_idx] + T].

        // Find the first p_j that this head can cover.
        // If h[head_idx] + T < p[p_idx], this head cannot reach p[p_idx].
        // This means p[p_idx] cannot be covered by h[head_idx] or any subsequent head.
        // So, it's impossible.
        if (h[head_idx] + T < p[p_idx]) {
            return false;
        }

        // This head can cover p[p_idx].
        // Now, we want to cover as many subsequent p_j's as possible with this head.
        // The head can move left to cover p[p_idx].
        // The leftmost point it can reach is max(p[p_idx], h[head_idx] - T).
        // The rightmost point it can reach is h[head_idx] + T.
        // The total range covered by this head is [h[head_idx] - T, h[head_idx] + T].
        // If we use this head to cover p[p_idx], it must visit p[p_idx].
        // The time taken is |h[head_idx] - p[p_idx]|.
        // If we move the head to p[p_idx], it can then move further.
        // The total distance it can travel from h[head_idx] is T.
        // If it moves to p[p_idx], it uses |h[head_idx] - p[p_idx]| time.
        // Remaining time: T - |h[head_idx] - p[p_idx]|.
        // From p[p_idx], it can move further right by this remaining time.
        // So, the rightmost point it can reach is p[p_idx] + (T - |h[head_idx] - p[p_idx]|).
        // This simplifies to:
        // If h[head_idx] <= p[p_idx]: rightmost = p[p_idx] + (T - (p[p_idx] - h[head_idx])) = h[head_idx] + T.
        // If h[head_idx] > p[p_idx]: rightmost = p[p_idx] + (T - (h[head_idx] - p[p_idx])) = 2*p[p_idx] - h[head_idx] + T.
        // This is the range [p[p_idx], 2*p[p_idx] - h[head_idx] + T] if h[head_idx] > p[p_idx]
        // and [p[p_idx], h[head_idx] + T] if h[head_idx] <= p[p_idx].
        // In general, the head can cover any segment [L, R] such that R - L <= T and L <= h[head_idx] + T and R >= h[head_idx] - T.
        // More precisely, if a head at `h_i` covers a range `[x, y]`, it takes `min(abs(h_i - x) + (y - x), abs(h_i - y) + (y - x))` time.
        // This is not quite right. The time is `max(abs(h_i - x), abs(h_i - y))` if `h_i` is outside `[x, y]`.
        // If `h_i` is inside `[x, y]`, it's `max(y - h_i, h_i - x)`.
        // The problem states "a track is considered read if at least one head has visited this track".
        // This means a head at `h_i` can cover any track `x` if `abs(h_i - x) <= T`.
        // If it covers `x`, it can also cover `y` if `abs(h_i - y) <= T`.
        // The total range covered by a head at `h_i` in time `T` is `[h_i - T, h_i + T]`.
        // This is the simplest interpretation.

        // So, the current head at h[head_idx] can cover tracks in [h[head_idx] - T, h[head_idx] + T].
        // We need to cover p[p_idx].
        // If p[p_idx] is not in [h[head_idx] - T, h[head_idx] + T], then this head cannot cover p[p_idx].
        // Since p is sorted, if h[head_idx] + T < p[p_idx], then no subsequent head can cover p[p_idx] either (as h is sorted).
        // This means it's impossible. (This check is already done above).
        // If h[head_idx] - T > p[p_idx], it means this head is too far right to cover p[p_idx] by moving left.
        // In this case, we must use a head to the left of h[head_idx] to cover p[p_idx].
        // But we are processing heads from left to right. So, this head is the leftmost available.
        // This implies that p[p_idx] must be covered by h[head_idx].
        // If h[head_idx] - T > p[p_idx], then h[head_idx] cannot cover p[p_idx].
        // This means it's impossible.
        // So, we need h[head_idx] - T <= p[p_idx] <= h[head_idx] + T.
        // The first check `h[head_idx] + T < p[p_idx]` handles the right boundary.
        // The left boundary: if `h[head_idx] - T > p[p_idx]`, then this head cannot cover `p[p_idx]`.
        // This means we need to use a head to the left of `h[head_idx]`. But `h[head_idx]` is the current leftmost.
        // This implies that `p[p_idx]` cannot be covered. So, `return false`.
        // This is the crucial part. If `h[head_idx] - T > p[p_idx]`, then `p[p_idx]` cannot be covered by `h[head_idx]`.
        // And since `h` is sorted, `h[head_idx]` is the leftmost available head.
        // So, if `h[head_idx] - T > p[p_idx]`, it's impossible.
        // This is not quite right. We can use a head `h_k` to cover `p_j`.
        // The greedy strategy should be: use the current head `h[head_idx]` to cover `p[p_idx]`.
        // If `h[head_idx]` cannot cover `p[p_idx]` (i.e., `abs(h[head_idx] - p[p_idx]) > T`), then it's impossible.
        // This is because `h[head_idx]` is the leftmost available head. If it can't cover `p[p_idx]`, no head to its right can cover `p[p_idx]` either.
        // This is only true if `p[p_idx]` is to the left of `h[head_idx] - T`.
        // If `p[p_idx]` is to the right of `h[head_idx] + T`, then `h[head_idx]` can't cover it.
        // And no head to its left can cover it.
        // So, if `p[p_idx]` is outside `[h[head_idx] - T, h[head_idx] + T]`, it's impossible.
        // This is the correct condition for `p[p_idx]` to be covered by `h[head_idx]`.
        if (p[p_idx] < h[head_idx] - T || p[p_idx] > h[head_idx] + T) {
            return false;
        }

        // If we reach here, h[head_idx] can cover p[p_idx].
        // Now, we want to cover as many subsequent p_j's as possible with this head.
        // The head at h[head_idx] can cover the range [h[head_idx] - T, h[head_idx] + T].
        // We need to cover p[p_idx].
        // The actual range covered by this head, starting from p[p_idx], is:
        // The head moves to p[p_idx]. Time spent: `abs(h[head_idx] - p[p_idx])`.
        // Remaining time: `T - abs(h[head_idx] - p[p_idx])`.
        // From p[p_idx], it can move further right by this remaining time.
        // So, the rightmost track it can reach is `p[p_idx] + (T - abs(h[head_idx] - p[p_idx]))`.
        long long rightmost_covered_by_this_head = p[p_idx] + (T - std::abs(h[head_idx] - p[p_idx]));

        // Advance p_idx as long as p[p_idx] is within the range covered by the current head.
        while (p_idx < m && p[p_idx] <= rightmost_covered_by_this_head) {
            p_idx++;
        }
        head_idx++; // Use the next head for the remaining tracks.
    }

    return p_idx == m; // All target tracks covered.
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    // Max possible distance: (10^10 - 1) + (10^10 - 1) approx 2 * 10^10.
    // Max distance between h_i and p_j is 10^10.
    // Max distance between p_1 and p_m is 10^10.
    // A single head might need to cover a range of 10^10.
    // So T can be up to 2 * 10^10.
    long long high = 20000000000LL; // A sufficiently large upper bound for T.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

