            // So, X must be <= x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }
            // f4 = 0 means cannot move down (y-1). So, target Y must be >= current y.
            // If robot is at y, and cannot move down, it cannot reach any Y < y.
            // So, Y must be >= y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
            // f2 = 0 means cannot move up (y+1). So, target Y must be <= current y.
            // If robot is at y, and cannot move up, it cannot reach any Y > y.
            // So, Y must be <= y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            // A valid point exists. We can pick any point within the valid range.
            // The problem guarantees that if a solution exists, one with coordinates
