#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        long long diff = std::abs(a - b);

        long long ans = 0;

        // Use 5s
        ans += diff / 5;
        diff %= 5;

        // Now diff is 0, 1, 2, 3, or 4
        if (diff == 0) {
            // No more presses needed
        } else if (diff == 1) {
            ans += 1; // Use +1 or -1
        } else if (diff == 2) {
            ans += 1; // Use +2 or -2
        } else if (diff == 3) {
            // Can use +1, +1, +1 (3 presses)
            // Or +5, then -2 (2 presses)
            ans += 2;
        } else if (diff == 4) {
            // Can use +2, +2 (2 presses)
            // Or +5, then -1 (2 presses)
            ans += 2;
        }

        std::cout << ans << "\n";
    }
    return 0;
}

