int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
        }

        // The reversed permutation will always have the same fingerprint.
        // We just need to ensure it's different from the original.
        // The problem statement guarantees a solution exists, and for n >= 2,
        // a permutation p is equal to its reverse p_rev if and only if
        // p is a palindrome.
        // For n >= 2, a permutation cannot be a palindrome unless n=1 (which is not allowed)
        // or n=2 and p=[1,2] or p=[2,1].
        // If p=[1,2], p_rev=[2,1], which is different.
        // If p=[2,1], p_rev=[1,2], which is different.
        // For n > 2, a permutation cannot be a palindrome.
        // For example, if p is a palindrome, p_1 = p_n, but elements must be distinct.
        // This means p_1 cannot be equal to p_n unless n=1.
        // So, p_rev is always different from p for n >= 2.

        std::reverse(p.begin(), p.end());

        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, d;
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        long long current_a1 = a[0];
        long long remaining_days = d;

        for (int i = 1; i < n; ++i) {
            // Cost to move one haybale from pile i+1 (0-indexed i) to pile 1 (0-indexed 0)
            // is i days.
            long long cost_per_haybale = i; 

            if (remaining_days >= cost_per_haybale) {
                // Calculate how many haybales we can move from this pile
                // based on available haybales and remaining days.
                long long haybales_to_move = std::min((long long)a[i], remaining_days / cost_per_haybale);

                current_a1 += haybales_to_move;
                remaining_days -= haybales_to_move * cost_per_haybale;
            } else {
                // Not enough days to move even one haybale from this pile.
                // Since piles are processed in increasing order of distance,
                // we won't be able to move haybales from any further piles either.
                break; 
            }
        }
        std::cout << current_a1 << std::endl;
    }
    return 0;
}

