#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    std::vector<int> p(n);

    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) { // Exclude a[i][i] which is 0
                max_val_in_row = std::max(max_val_in_row, a[i][j]);
            }
        }
        // If max_val_in_row is n-1, it means p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        // This logic works because if p[i] = n, then min(p[i], p[j]) = p[j] for all j!=i.
        // So max_{j!=i} (min(p[i], p[j])) = max_{j!=i} (p[j]) = n-1.
        // If p[i] < n, then there must be some p[k] > p[i].
        // For such k, min(p[i], p[k]) = p[i].
        // For any j where p[j] < p[i], min(p[i], p[j]) = p[j].
        // So max_{j!=i} (min(p[i], p[j])) will be p[i].
        // The only exception is if p[i] is n, in which case the max is n-1.
        // So, if max_val_in_row == n-1, then p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

int main() {
    // Optimize C++ standard streams for competitive programming.
    // This unties cin/cout from C standard streams and disables synchronization
    // with C standard streams, and unties cin from cout.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t; // Read the number of test cases

    while (t--) { // Loop through each test case
        int n;
        std::cin >> n; // Read the number of days for the current test case

        std::vector<int> a(n); // Declare a vector to store prices
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i]; // Read prices into the vector
        }

        if (n == 0) { // Handle edge case for n=0, though constraints say n >= 1
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0;
        // Initialize min_suffix_price with the price on the last day.
        // Any price before the last day can potentially be bad if it's greater than a[n-1].
        // The last day's price itself can never be bad because there are no days after it.
        int min_suffix_price = a[n - 1]; 

        // Iterate from the second to last day down to the first day.
        // The loop goes from n-2 down to 0 (inclusive).
        for (int i = n - 2; i >= 0; --i) {
            // If the current day's price is greater than the minimum price
            // found so far in the suffix (days i+1 to n-1), then it's a bad price.
            if (a[i] > min_suffix_price) {
                bad_prices_count++;
            } else {
                // If the current day's price is not greater than min_suffix_price,
                // it means a[i] is either less than or equal to min_suffix_price.
                // In this case, a[i] becomes the new minimum for the suffix
                // starting from day i.
                min_suffix_price = a[i];
            }
        }
        std::cout << bad_prices_count << "\n"; // Print the result for the current test case
    }

    return 0; // Indicate successful execution
}

