int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_gap = 0;
        int last_R_pos = -1; // Represents cell 0

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // Current cell is i+1 (1-indexed)
                // Distance from last 'R' or cell 0 to current 'R'
                // The gap is (i+1) - (last_R_pos + 1)
                // Or, more simply, current_pos - previous_R_pos
                // current_pos is i+1
                // previous_R_pos is last_R_pos+1 (if last_R_pos is 0-indexed string index)
                // If last_R_pos is -1 (cell 0), then previous_R_pos is 0.
                // So, gap is (i+1) - (last_R_pos + 1)
                max_gap = std::max(max_gap, (i + 1) - (last_R_pos + 1));
                last_R_pos = i;
            }
        }

        // After iterating through the string, consider the gap from the last 'R'
        // to cell n+1.
        // The last 'R' was at index last_R_pos (0-indexed string index).
        // Its cell number is last_R_pos + 1.
        // The target cell is n+1.
        // The gap is (n+1) - (last_R_pos + 1).
        max_gap = std::max(max_gap, (n + 1) - (last_R_pos + 1));

        std::cout << max_gap << "\n";
    }
    return 0;
}

