int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    // The area of the whole carrot is A = (1/2) * base * height = (1/2) * 1 * h = h/2.
    // Each of the n pieces must have an area of A_piece = A / n = (h/2) / n = h / (2n).

    // Consider a smaller triangle formed by a cut at distance x from the apex.
    // By similar triangles, if the height is x, the base is x/h.
    // The area of this smaller triangle is A_x = (1/2) * (x/h) * x = x^2 / (2h).

    // We want to find x_k such that the area of the triangle from the apex to x_k
    // is equal to k * A_piece.
    // So, x_k^2 / (2h) = k * (h / (2n))
    // x_k^2 = k * h^2 / n
    // x_k = sqrt(k * h^2 / n)
    // x_k = h * sqrt(k / n)

    // We need to find n-1 cut positions x_1, x_2, ..., x_{n-1}.
    // These correspond to k = 1, 2, ..., n-1.

    std::cout << std::fixed << std::setprecision(12);

    for (int k = 1; k < n; ++k) {
        double x_k = h * std::sqrt(static_cast<double>(k) / n);
        std::cout << x_k << (k == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

