        if (count == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // The last digits of k*m repeat with a cycle of length 10.
        // For example, if m=3, last digits are:
        // 3*1=3, 3*2=6, 3*3=9, 3*4=12->2, 3*5=15->5, 3*6=18->8, 3*7=21->1, 3*8=24->4, 3*9=27->7, 3*10=30->0
        // Then 3*11=33->3, and the cycle repeats.

        std::vector<long long> cycle_digits(10);
        long long sum_of_cycle_digits = 0;
        for (int i = 1; i <= 10; ++i) {
            cycle_digits[i - 1] = (static_cast<long long>(i) * m) % 10;
            sum_of_cycle_digits += cycle_digits[i - 1];
        }

        long long num_full_cycles = count / 10;
        long long remaining_elements = count % 10;

        long long total_sum = num_full_cycles * sum_of_cycle_digits;

        for (int i = 0; i < remaining_elements; ++i) {
            total_sum += cycle_digits[i];
        }

        std::cout << total_sum << "\n";
    }
