#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Check prefix for increasing sequence
    // We need a_i >= i for 0-indexed array to form 0, 1, 2, ...
    // Or more generally, a_i >= a_{i-1} + 1.
    // The minimum possible value for a[i] to be part of a strictly increasing sequence
    // starting from 0 at index 0 is i.
    // So, we check if a[i] >= i for all i from 0 to n-1.
    // If at any point a[i] < i, then we cannot form a strictly increasing sequence
    // 0, 1, ..., i.
    // Let's find the first index `i` where `a[i] < i`.
    // All elements before this index `i` (i.e., `a[0]` to `a[i-1]`) satisfy `a[j] >= j`.
    // This means we can potentially form `0, 1, ..., i-1` using `a[0], ..., a[i-1]`.
    // The peak `k` must be at or before this index `i-1`.
    // If `a[i] < i`, then `i` cannot be part of the increasing sequence `0, 1, ..., i`.
    // So, the peak `k` must be at an index `j < i`.
    // The maximum possible index for the peak `k` (0-indexed) is `i-1`.
    // If `a[i] >= i` for all `i`, then the peak can be `n-1`.

    int prefix_limit = n; // The first index `i` such that `a[i] < i`.
                          // If no such `i` exists, `prefix_limit` remains `n`.
    for (int i = 0; i < n; ++i) {
        if (a[i] < i) {
            prefix_limit = i;
            break;
        }
    }

    // Check suffix for decreasing sequence
    // We need a_i >= (n-1-i) for 0-indexed array to form ..., 2, 1, 0
    // The minimum possible value for a[i] to be part of a strictly decreasing sequence
    // ending with 0 at index n-1 is (n-1-i).
    // So, we check if a[i] >= (n-1-i) for all i from n-1 down to 0.
    // If at any point a[i] < (n-1-i), then we cannot form a strictly decreasing sequence
    // i, ..., n-1 with a[n-1]=0, a[n-2]=1, etc.
    // Let's find the first index `i` (from right) where `a[i] < (n-1-i)`.
    // All elements after this index `i` (i.e., `a[i+1]` to `a[n-1]`) satisfy `a[j] >= (n-1-j)`.
    // This means we can potentially form `..., 1, 0` using `a[i+1], ..., a[n-1]`.
    // The peak `k` must be at or after this index `i+1`.
    // If `a[i] < (n-1-i)`, then `i` cannot be part of the decreasing sequence `i, ..., n-1`
    // with `a[n-1]=0, a[n-2]=1, ...`.
    // So, the peak `k` must be at an index `j > i`.
    // The minimum possible index for the peak `k` (0-indexed) is `i+1`.
    // If `a[i] >= (n-1-i)` for all `i`, then the peak can be `0`.

    int suffix_limit = -1; // The first index `i` (from right) such that `a[i] < (n-1-i)`.
                           // If no such `i` exists, `suffix_limit` remains `-1`.
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] < (n - 1 - i)) {
            suffix_limit = i;
            break;
        }
    }

    // A sharpened array requires a peak `k` (0-indexed) such that:
    // 1. `a[0] < ... < a[k]` (can be achieved if `a[j] >= j` for `j <= k`)
    // 2. `a[k] > ... > a[n-1]` (can be achieved if `a[j] >= (n-1-j)` for `j >= k`)

    // From prefix_limit: any peak `k` must satisfy `k < prefix_limit`.
    // From suffix_limit: any peak `k` must satisfy `k > suffix_limit`.

    // So, we need to find if there exists an index `k` such that `suffix_limit < k < prefix_limit`.
    // This is equivalent to checking if `suffix_limit + 1 < prefix_limit`.
    // If `suffix_limit + 1 < prefix_limit`, then there is at least one valid `k`.
    // For example, if `suffix_limit = 0` and `prefix_limit = 2`, then `k=1` is valid.
    // If `suffix_limit = -1` (all prefix conditions met) and `prefix_limit = n` (all suffix conditions met),
    // then `-1 + 1 < n` (i.e., `0 < n`) is true for `n >= 1`.
    // This means any `k` from `0` to `n-1` could be a peak.
    // The condition `suffix_limit + 1 < prefix_limit` correctly identifies if there's an overlap.

    if (suffix_limit + 1 < prefix_limit) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

