// Function to check if a prefix of length `len` is a permutation
bool is_prefix_permutation(int len, const std::vector<int>& a, const std::vector<int>& max_prefix_val, const std::vector<int>& distinct_prefix_count) {
    if (len == 0) return false; // Permutation length must be non-zero
    return max_prefix_val[len - 1] == len && distinct_prefix_count[len - 1] == len;
}

// Function to check if a suffix of length `len` is a permutation
bool is_suffix_permutation(int len, int n, const std::vector<int>& a, const std::vector<int>& max_suffix_val, const std::vector<int>& distinct_suffix_count) {
    if (len == 0) return false; // Permutation length must be non-zero
    return max_suffix_val[n - len] == len && distinct_suffix_count[n - len] == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute for prefixes
    std::vector<int> max_prefix_val(n);
    std::vector<int> distinct_prefix_count(n);
    std::vector<bool> seen_prefix(n + 1, false); // Max value can be n, so size n+1
    int current_max_prefix = 0;
    int current_distinct_prefix = 0;

    for (int i = 0; i < n; ++i) {
        current_max_prefix = std::max(current_max_prefix, a[i]);
        if (!seen_prefix[a[i]]) {
            seen_prefix[a[i]] = true;
            current_distinct_prefix++;
        }
        max_prefix_val[i] = current_max_prefix;
        distinct_prefix_count[i] = current_distinct_prefix;
    }

    // Precompute for suffixes
    std::vector<int> max_suffix_val(n);
    std::vector<int> distinct_suffix_count(n);
    std::fill(seen_prefix.begin(), seen_prefix.end(), false); // Reuse seen_prefix for suffixes
    int current_max_suffix = 0;
    int current_distinct_suffix = 0;

    for (int i = n - 1; i >= 0; --i) {
        current_max_suffix = std::max(current_max_suffix, a[i]);
        if (!seen_prefix[a[i]]) {
            seen_prefix[a[i]] = true;
            current_distinct_suffix++;
        }
        max_suffix_val[i] = current_max_suffix;
        distinct_suffix_count[i] = current_distinct_suffix;
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 can range from 1 to n-1
        int l2 = n - l1;
        if (is_prefix_permutation(l1, a, max_prefix_val, distinct_prefix_count) &&
            is_suffix_permutation(l2, n, a, max_suffix_val, distinct_suffix_count)) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

