#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        long long current_sum = 0;
        long long current_xor_sum = 0;
        for (int i = 0; i < n; ++i) {
            long long a;
            std::cin >> a;
            current_sum += a;
            current_xor_sum ^= a;
        }

        // We need S' = 2 * X'
        // Let S_orig be current_sum and X_orig be current_xor_sum.
        // We want to find b1, b2, b3 such that
        // (S_orig + b1 + b2 + b3) = 2 * (X_orig ^ b1 ^ b2 ^ b3)

        // The strategy is to append at most 3 elements.
        // It's always possible to achieve this with 2 or 3 elements.
        // Let's try to append two elements: X_orig and S_orig.
        // New sum: S_orig + X_orig + S_orig = 2 * S_orig + X_orig
        // New XOR sum: X_orig ^ X_orig ^ S_orig = S_orig
        // We need: 2 * S_orig + X_orig = 2 * S_orig
        // This implies X_orig = 0. This is not generally true.

        // Let's try to append two elements: X_orig and S_orig + X_orig.
        // This is not quite right.
        // The standard trick is to append X_orig and then something else.
        // Let's append X_orig.
        // New sum: S_orig + X_orig
        // New XOR sum: X_orig ^ X_orig = 0
        // We need: S_orig + X_orig = 2 * 0 = 0.
        // This is only true if S_orig = 0 and X_orig = 0, which is not general.

        // Consider the property: A + B = (A XOR B) + 2 * (A AND B).
        // Sum of all elements = XOR sum of all elements + 2 * (sum of all pairwise ANDs).
        // This means Sum - XOR_sum must be an even number.
        // S' - X' = 2 * (sum of all pairwise ANDs).
        // If S' = 2 * X', then 2 * X' - X' = X' must be an even number.
        // So, X' must be even.

        // Let's append two elements: X_orig and S_orig.
        // New sum: S_orig + X_orig + S_orig = 2 * S_orig + X_orig
        // New XOR sum: X_orig ^ X_orig ^ S_orig = S_orig
        // We need: 2 * S_orig + X_orig = 2 * S_orig
        // This implies X_orig = 0. This is not generally true.

        // The common strategy for this type of problem is to make the XOR sum 0,
        // and then adjust the sum.
        // If we append X_orig, the new XOR sum becomes X_orig ^ X_orig = 0.
        // The new sum becomes S_orig + X_orig.
        // Now we have an array with sum S_orig + X_orig and XOR sum 0.
        // We need (S_orig + X_orig) = 2 * 0 = 0.
        // This is only true if S_orig + X_orig = 0.

        // What if we append X_orig and then another element `y`?
        // New XOR sum: X_orig ^ X_orig ^ y = y.
        // New sum: S_orig + X_orig + y.
        // We need: S_orig + X_orig + y = 2 * y.
        // This simplifies to S_orig + X_orig = y.
        // So, if we append X_orig and (S_orig + X_orig), the condition should hold.

        // Let's verify this strategy:
        // Elements to append: b1 = X_orig, b2 = S_orig + X_orig.
        // New sum S' = S_orig + b1 + b2 = S_orig + X_orig + (S_orig + X_orig) = 2 * S_orig + 2 * X_orig.
        // New XOR sum X' = X_orig ^ b1 ^ b2 = X_orig ^ X_orig ^ (S_orig + X_orig) = S_orig + X_orig.
        // We need S' = 2 * X'.
        // Is (2 * S_orig + 2 * X_orig) = 2 * (S_orig + X_orig)?
        // Yes, it is. This strategy always works with 2 appended elements.

        // The problem states "at most 3 elements".
        // If the array is already good, we append 0 elements.
        if (current_sum == 2 * current_xor_sum) {
            std::cout << 0 << "\n\n";
        } else {
            // Append X_orig and (S_orig + X_orig)
            // The problem states elements can be up to 10^18.
            // S_orig can be up to 10^5 * 10^9 = 10^14.
            // X_orig can be up to 2^30 (approx 10^9).
            // S_orig + X_orig can be up to 10^14 + 10^9, which fits in long long.
            std::cout << 2 << "\n";
            std::cout << current_xor_sum << " " << (current_sum + current_xor_sum) << "\n";
        }
    }
    return 0;
}

