void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // If s_i is '0', then w[i-x] (if exists) must be '0'
    // and w[i+x] (if exists) must be '0'.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Now, verify if this w can produce the given s.
    // Construct a candidate s_prime from w.
    std::string s_prime(n, '0');
    for (int i = 0; i < n; ++i) {
        bool is_one = false;
        if (i - x >= 0 && w[i - x] == '1') {
            is_one = true;
        }
        if (i + x < n && w[i + x] == '1') {
            is_one = true;
        }
        if (is_one) {
            s_prime[i] = '1';
        }
    }

    // Compare s_prime with the original s.
    if (s_prime == s) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

