int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Precompute prefix sums for 'x', 'y', 'z'
    // count[0][i] stores count of 'x' in s[0...i-1]
    // count[1][i] stores count of 'y' in s[0...i-1]
    // count[2][i] stores count of 'z' in s[0...i-1]
    std::vector<std::vector<int>> count(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        count[0][i + 1] = count[0][i];
        count[1][i + 1] = count[1][i];
        count[2][i + 1] = count[2][i];
        if (s[i] == 'x') {
            count[0][i + 1]++;
        } else if (s[i] == 'y') {
            count[1][i + 1]++;
        } else { // s[i] == 'z'
            count[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r; // 1-indexed

        int len = r - l + 1;

        if (len < 3) {
            std::cout << "YES\n";
            continue;
        }

        // Get counts of 'x', 'y', 'z' in the substring s[l-1...r-1]
        int count_x = count[0][r] - count[0][l - 1];
        int count_y = count[1][r] - count[1][l - 1];
        int count_z = count[2][r] - count[2][l - 1];

        // Check if the counts are "balanced" enough
        // The difference between max and min count must be at most 1
        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

