// Function to find prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x | p and x % q != 0.
        // Let p = k * q.
        // We need to remove prime factors from p such that it's no longer divisible by q.
        // The strategy is to iterate through prime factors of q.
        // For each prime factor f of q, we try to divide p by f until p is no longer divisible by q.
        // The largest such resulting number will be our candidate x.
        // We take the maximum of these candidates.

        std::vector<long long> q_prime_factors = get_prime_factors(q);
        long long max_x = 1;

        for (long long f : q_prime_factors) {
            long long current_p = p;
            // Divide current_p by f until it's no longer divisible by q
            // or until it's no longer divisible by f.
            while (current_p % q == 0) {
                current_p /= f;
            }
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    long long turn = 0; // 0 for Chanek, 1 for Opponent

    while (n > 0) {
        if (turn == 0) { // Chanek's turn
            if (n % 2 == 1) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                // Option 1: Take 1 coin
                // If Chanek takes 1, N becomes N-1 (odd).
                // Next, opponent faces N-1.
                // If N-1 is 1, opponent takes 1.
                // If N-1 is >1, opponent takes 1 or (N-1)/2.
                // This path is generally worse for Chanek if N is large and even.

                // Option 2: Take N/2 coins
                // This is generally the greedy choice for the current player.
                // However, we need to consider the opponent's optimal play.

                // Special case: N is a power of 2.
                // If N is a power of 2 (e.g., 2, 4, 8, 16, ...), and Chanek takes N/2,
                // the opponent faces N/2, which is also a power of 2.
                // This continues until N becomes 1.
                // Example: N=8. Chanek takes 4. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 4+1=5. Opponent: 2+1=3.
                // If N=8, Chanek takes 1. N=7. Opponent takes 1. N=6. Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 1+3+1=5. Opponent: 1+1+1=3.
                // It seems taking N/2 is better or equal for powers of 2.

                // The critical observation is when N is even.
                // If N is even, Chanek can take N/2.
                // If N/2 is odd, then the opponent faces an odd number.
                // The opponent will take 1, leaving N/2 - 1 (even).
                // Chanek then faces N/2 - 1.
                // This strategy seems to give Chanek a good share.

                // What if N/2 is even? This means N is a multiple of 4.
                // If N is a multiple of 4, Chanek takes N/2. Opponent faces N/2 (even).
                // Opponent can also take (N/2)/2 = N/4.
                // This continues until N becomes an odd number or 2.

                // Let's consider the strategy:
                // If N is odd, take 1.
                // If N is even:
                //   If N is 2, take 1. (Chanek gets 1, Opponent gets 1)
                //   If N is a power of 2 (N = 2^k, k > 1):
                //     Chanek takes N/2. Opponent faces N/2 (power of 2).
                //     This continues until N becomes 2.
                //     Example N=8: C takes 4 (N=4), O takes 2 (N=2), C takes 1 (N=1), O takes 1 (N=0). C: 4+1=5, O: 2+1=3.
                //     If C takes 1 (N=7): O takes 1 (N=6), C takes 3 (N=3), O takes 1 (N=2), C takes 1 (N=1), O takes 1 (N=0). C: 1+3+1=5, O: 1+1+1=3.
                //     It seems for powers of 2, taking N/2 is optimal.
                //   If N is even but not a power of 2 (N = 2^k * M, where M is odd and M > 1):
                //     Chanek takes N/2. Opponent faces N/2 = 2^(k-1) * M.
                //     If k=1 (N = 2 * M, M odd > 1), Chanek takes M. Opponent faces M (odd).
                //     Opponent takes 1. Chanek faces M-1 (even).
                //     This seems like a good strategy for Chanek.
                //     Example N=6: C takes 3 (N=3). O takes 1 (N=2). C takes 1 (N=1). O takes 1 (N=0). C: 3+1=4, O: 1+1=2.
                //     If C takes 1 (N=5): O takes 1 (N=4). C takes 2 (N=2). O takes 1 (N=1). C takes 1 (N=0). C: 1+2+1=4, O: 1+1=2.
                //     Both strategies yield 4 for Chanek.

                // The general greedy strategy for the current player is:
                // If N is odd, take 1.
                // If N is even:
                //   If N is 2, take 1. (This is the only option for N=2 if we want to maximize our own score, as taking N/2 also gives 1)
                //   If N > 2 and N is even:
                //     If taking N/2 leads to a state where the opponent gets significantly less, take N/2.
                //     Otherwise, taking 1 might be better.

                // Let's re-evaluate the "take 1" vs "take N/2" for even N.
                // If N is even, Chanek can take N/2. This is a large amount.
                // The remaining N/2 coins are then for the opponent.
                // If Chanek takes 1, the remaining N-1 coins are for the opponent.
                // The opponent will try to maximize their coins from N/2 or N-1.

                // Consider the total coins taken by Chanek.
                // If N is even:
                //   Option A: Take 1. Remaining N-1. Opponent plays on N-1.
