int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1 = 0 means cannot move left (x-1). So, target X must be >= current x.
            // If robot is at x and cannot move left, it can only reach points >= x.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }
            // f3 = 0 means cannot move right (x+1). So, target X must be <= current x.
            // If robot is at x and cannot move right, it can only reach points <= x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }
            // f4 = 0 means cannot move down (y-1). So, target Y must be >= current y.
            // If robot is at y and cannot move down, it can only reach points >= y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
            // f2 = 0 means cannot move up (y+1). So, target Y must be <= current y.
            // If robot is at y and cannot move up, it can only reach points <= y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            // A valid point exists. The problem guarantees that if a point exists,
            // one exists within [-10^5, 10^5].
            // We can pick any point in the valid range, e.g., (min_x, min_y).
            // The coordinates can be up to 10^5, so min_x and min_y could be 10^5.
            // The problem statement says "not exceeding 10^5 by absolute value".
            // Our calculated min_x and min_y could be outside this range if the initial
            // robot positions are outside, but the problem guarantees that if a solution
            // exists, one exists within the [-10^5, 10^5] range.
            // So, we can just output min_x and min_y directly.
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s, t;
    std::cin >> s >> t;

    // Create frequency maps for characters in s and t
    // A std::vector<bool> of size 26 is not suitable for frequency counts.
    // A std::vector<int> or std::array<int, 26> is better.
    // However, we only need to know if a character *exists*, not its count.
    // So, a boolean array is fine for existence.
    std::vector<bool> s_chars(26, false);
    std::vector<bool> t_chars(26, false);

    for (char c : s) {
        s_chars[c - 'a'] = true;
    }
    for (char c : t) {
        t_chars[c - 'a'] = true;
    }

    bool common_char_found = false;
    for (int i = 0; i < 26; ++i) {
        if (s_chars[i] && t_chars[i]) {
            common_char_found = true;
            break;
        }
    }

    if (common_char_found) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

