#include <algorithm>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    bool possible = true;

    for (size_t i = 0; i < s.length() - 1; ++i) {
        char c1 = s[i];
        char c2 = s[i+1];
        adj[c1].insert(c2);
        adj[c2].insert(c1);
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    std::string layout = "";
    std::set<char> visited_in_layout;

    // Find a starting point for the layout: a character with only one required neighbor.
    char start_char = '\0';
    for (const auto& pair : adj) {
        if (pair.second.size() == 1) {
            start_char = pair.first;
            break;
        }
    }

    // If no char has 1 neighbor, it means all chars in adj have 2 neighbors (a cycle)
    // or there's only one char in adj (which has 0 neighbors).
    // If it's a cycle, it's impossible to form a linear layout unless it's a single path.
    // If it's a single path, the first and last elements will have 1 neighbor.
    // If all characters in adj have 2 neighbors, it means they form one or more cycles.
    // A single cycle of length 26 would be valid, but we need to check if it's a single path.
    // If all characters in adj have 2 neighbors, and there are more than 2 characters in adj,
    // it means it's a cycle. A cycle cannot be represented as a linear keyboard layout
    // unless it's a path where the ends are connected, which is not what "adjacent" means here.
    // A linear layout must have two endpoints with degree 1 (or 0 if only one char).
    // If all characters in adj have 2 neighbors, it means they form a cycle.
    // A cycle cannot be flattened into a linear layout without breaking adjacency for some pair.
    // Example: A-B-C-D-A. If we lay it out as A-B-C-D, then A and D are not adjacent.
    // The only exception is if the "cycle" is just two characters, e.g., A-B-A.
    // But the problem guarantees no adjacent equal characters, so A-B-A means A-B and B-A.
    // A and B are neighbors. This is fine.
    // If all characters in adj have 2 neighbors, and the number of characters in adj is > 2,
    // then it's a cycle of length > 2, which is impossible.
    // If all characters in adj have 2 neighbors, and the number of characters in adj is 2,
    // e.g., 'a' and 'b', then adj['a']={b}, adj['b']={a}. This is fine.
    // The start_char logic handles this: if adj.size() == 2, say 'a' and 'b',
    // then adj['a'] has size 1 (containing 'b'), and adj['b'] has size 1 (containing 'a').
    // So start_char will be found.
    // The only case where start_char is not found is if adj is empty (s.length() == 1)
    // or if all characters in adj have 2 neighbors AND adj.size() > 2.
    // If adj is empty, s has length 1. We can pick any char as start.
    // If adj is not empty and start_char is still '\0', it means all chars in adj have 2 neighbors.
    // This implies a cycle of length > 2.
    if (start_char == '\0' && !adj.empty()) {
        // This means all characters in adj have degree 2.
        // This forms one or more cycles. If there's more than one character in adj,
        // and all have degree 2, it's impossible to form a linear layout.
        // Example: abca. a-b, b-c, c-a. All have degree 2.
        // This is only possible if adj.size() == 0 (s.length() == 1)
        // or if adj.size() == 1 (e.g., s="ab", adj={'a':{'b'}, 'b':{'a'}}).
        // The start_char logic should find a start if adj.size() == 1.
        // So if start_char is '\0' and adj is not empty, it means adj.size() > 2 and all degrees are 2.
        // This is a cycle of length > 2.
        std::cout << "NO\n";
        return;
    }

    if (start_char == '\0' && adj.empty()) { // s has length 1
        start_char = s[0];
    } else if (start_char == '\0' && !adj.empty()) { // All chars in adj have degree 2, and adj is not empty.
        // This means it's a cycle of length > 2.
        // Example: s = "abcda". adj: a:{b,d}, b:{a,c}, c:{b,d}, d:{a,c}.
        // This is not a simple cycle. This is a graph where all nodes have degree 2.
        // This implies a cycle. If the number of nodes in this cycle is > 2, it's impossible.
        // The only case where it's possible is if the graph is a single path.
        // A single path will always have two endpoints with degree 1.
        // If all nodes have degree 2, it's a cycle.
        // A cycle cannot be laid out linearly.
        // So, if start_char is still '\0' and adj is not empty, it's impossible.
        std::cout << "NO\n";
        return;
    }


    char current = start_char;
    char prev = '\0'; // To keep track of the previous character in the layout path

    while (current != '\0') {
        layout += current;
        visited_in_layout.insert(current);

        char next_char = '\0';
        for (char neighbor : adj[current]) {
            if (neighbor != prev) {
                next_char = neighbor;
                break;
            }
        }
        prev = current;
        current = next_char;
    }

    // Add remaining characters not in the password to the layout
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

