    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

long long sum_arithmetic_series(long long n) {
    if (n <= 0) {
        return 0;
    }
    long long MOD = 1000000007;
    long long n_mod = n % MOD;
    long long n_plus_1_mod = (n + 1) % MOD;
    long long inv2 = 500000004; // Modular inverse of 2 modulo 10^9 + 7

    long long term1 = (n_mod * n_plus_1_mod) % MOD;
    long long result = (term1 * inv2) % MOD;
    return result;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of r from 1 to b-1
    // This is (b-1) * b / 2
    long long sum_r_val = sum_arithmetic_series(b - 1);

    // Sum of (k * b + 1) for k from 1 to a
    // This is sum_{k=1 to a} (k*b + 1)
    // = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // = b * (a * (a+1) / 2) + a
    long long sum_k_b_plus_1_val;

    long long sum_k_val = sum_arithmetic_series(a); // a * (a+1) / 2

    long long term_b_sum_k = (b % MOD * sum_k_val) % MOD;
    long long term_a = a % MOD;

    sum_k_b_plus_1_val = (term_b_sum_k + term_a) % MOD;

    // Total sum = (sum_r_val * sum_k_b_plus_1_val) % MOD
    long long total_sum = (sum_r_val * sum_k_b_plus_1_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <numeric>
