    if (final_and_const != 1023) {
        result_ops.push_back({'&', final_and_const});
    }
    // If `final_or_const` is not all 0s (0), we need an OR operation.
    if (final_or_const != 0) {
        result_ops.push_back({'|', final_or_const});
    }
    // If `final_xor_const` is not all 0s (0), we need an XOR operation.
    if (final_xor_const != 0) {
        result_ops.push_back({'^', final_xor_const});
    }

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> L(n, 0), R(n, 0);

    // Calculate L[i]: length of consecutive identical elements ending at i
    L[0] = 1;
    for (int i = 1; i < n; ++i) {
        if (a[i] == a[i - 1]) {
            L[i] = L[i - 1] + 1;
        } else {
            L[i] = 1;
        }
    }

    // Calculate R[i]: length of consecutive identical elements starting at i
    R[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == a[i + 1]) {
            R[i] = R[i + 1] + 1;
        } else {
            R[i] = 1;
        }
    }

    int max_steps = 0;
    std::vector<int> final_a = a;

    for (int i = 1; i < n - 1; ++i) {
        if (a[i] != a[i - 1] && a[i] != a[i + 1]) { // Pattern X Y X
            int len_left = L[i - 1];
            int len_right = R[i + 1];

            int steps_needed = (std::min(len_left, len_right) + 1) / 2;
            max_steps = std::max(max_steps, steps_needed);

            // Determine the final state of the block
            // If len_left == len_right, the middle part becomes 0s if a[i-1]=0, 1s if a[i-1]=1
            // If len_left < len_right, the middle part becomes a[i-1]
            // If len_left > len_right, the middle part becomes a[i+1]

            // The elements that change are from index i - len_left + 1 to i + len_right - 1
            // The elements that become stable are from index i - len_left + steps_needed to i + len_right - steps_needed

            // The elements from i - steps_needed + 1 to i + steps_needed - 1 will flip
            // The elements from i - steps_needed + 1 to i will become a[i-1]
            // The elements from i + 1 to i + steps_needed - 1 will become a[i+1]

            // The final state of the segment [i - len_left + 1, i + len_right - 1]
            // The first `len_left` elements will be `a[i-1]`
            // The last `len_right` elements will be `a[i+1]`
            // The middle part will be determined by the shorter block

            // The elements from index `i - len_left + 1` to `i - len_left + steps_needed` will become `a[i-1]`
            // The elements from index `i + len_right - steps_needed` to `i + len_right - 1` will become `a[i+1]`

            // The elements in the middle, from `i - len_left + steps_needed + 1` to `i + len_right - steps_needed - 1`
            // will become `a[i-1]` if `len_left <= len_right`
            // will become `a[i+1]` if `len_left > len_right`

            // More simply, the elements from `i - len_left + 1` to `i + len_right - 1`
            // will become `a[i-1]` for `k` from `i - len_left + 1` to `i - len_left + steps_needed`
            // will become `a[i+1]` for `k` from `i + len_right - steps_needed` to `i + len_right - 1`

            // The elements from `i - len_left + steps_needed` to `i + len_right - steps_needed`
            // will become `a[i-1]` if `len_left <= len_right`
            // will become `a[i+1]` if `len_left > len_right`

            // Let's simplify:
            // The segment from `i - len_left + 1` to `i + len_right - 1`
            // The first `len_left - steps_needed` elements remain `a[i-1]`
            // The last `len_right - steps_needed` elements remain `a[i+1]`
            // The middle `len_left + len_right - 1 - 2 * steps_needed` elements
            // will become `a[i-1]` if `len_left <= len_right`
            // will become `a[i+1]` if `len_left > len_right`

            // The elements from `i - len_left + steps_needed` to `i + len_right - steps_needed`
            // will all become `a[i-1]` if `len_left <= len_right`
            // will all become `a[i+1]` if `len_left > len_right`

            int start_idx = i - len_left + 1;
            int end_idx = i + len_right - 1;

            int stable_val;
            if (len_left <= len_right) {
                stable_val = a[i - 1];
            } else {
                stable_val = a[i + 1];
            }

            for (int k = start_idx + steps_needed -1; k <= end_idx - steps_needed; ++k) {
                final_a[k] = stable_val;
            }
        }
    }

    std::cout << max_steps << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << final_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize initial_a[j] to a very large value (effectively infinity)
    // This represents the upper bound for A_0[j]
    std::vector<long long> initial_a(n, 2000000000LL); // Max possible value for A_0[j] is 10^9,
                                                      // but it can be reduced by operations.
                                                      // A value like 2*10^9 is safe as an initial upper bound.

    // Process operations in reverse to find initial_a bounds
    // For type 2 operations: max(A_0[j] + current_delta[j]) = m
    // This implies A_0[j] + current_delta[j] <= m for all j in [l, r]
    // So, A_0[j] <= m - current_delta[j]
    // We want to find the tightest upper bound for A_0[j], so we take the minimum of all such m - current_delta[j]
    // encountered for A_0[j].

    // current_delta_prefix_sum[j] stores the sum of d values applied to a[j]
    // from operations *after* the current one being processed in reverse.
    // This is equivalent to the total delta applied to a[j] *before* the current operation
    // when processing operations in forward order.
    std::vector<long long> current_delta_prefix_sum(n + 1, 0);

    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // This is a type 1 operation: a[j] += d for j in [l, r]
            // When processing in reverse, this means that for elements a[j] in this range,
            // the delta applied *before* this operation (in forward time) was d less than
            // the delta applied *after* this operation.
            // So, we subtract d from the prefix sum for this range.
            current_delta_prefix_sum[ops[i].l] -= ops[i].val;
            current_delta_prefix_sum[ops[i].r + 1] += ops[i].val;
        } else {
            // This is a type 2 operation: max(a[l...r]) = m
            // For all j in [l, r], A_0[j] + current_delta[j] <= m
            // current_delta[j] is the sum of d's applied to a[j] *before* this operation.
            // This is exactly what current_delta_prefix_sum represents when processed in reverse.
            // We need to calculate the actual delta for each j in [l, r]
            // and update initial_a[j] = min(initial_a[j], m - actual_delta_for_j).

            long long current_delta_val = 0;
            for (int j = 0; j < n; ++j) {
                current_delta_val += current_delta_prefix_sum[j];
                if (j >= ops[i].l && j <= ops[i].r) {
                    initial_a[j] = std::min(initial_a[j], ops[i].val - current_delta_val);
                }
            }
        }
    }

    // Check if any initial_a[j] is too small (less than -10^9)
    // If initial_a[j] is still 2*10^9, it means no upper bound was imposed by type 2 ops.
    // In this case, we can set it to 10^9 to satisfy the |a_i| <= 10^9 constraint.
    for (int j = 0; j < n; ++j) {
        if (initial_a[j] > 1000000000LL) {
            initial_a[j] = 1000000000LL;
        }
        if (initial_a[j] < -1000000000LL) {
            // This means even with the smallest possible initial value, it would exceed the max_val constraint.
            // This case should ideally be caught by the verification step, but good to have a sanity check.
            // For this problem, it's more about the verification step.
        }
    }

    // Verify the constructed initial_a
    std::vector<long long> a = initial_a;
    std::vector<long long> current_delta_for_verification(n + 1, 0); // For calculating actual a[j] values

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            // Apply delta for type 1 operations
            current_delta_for_verification[ops[i].l] += ops[i].val;
            current_delta_for_verification[ops[i].r + 1] -= ops[i].val;
        } else {
            // Verify type 2 operations
            long long max_val_in_range = LLONG_MIN;
            long long current_delta_val = 0;
            for (int j = 0; j < n; ++j) {
                current_delta_val += current_delta_for_verification[j];
                if (j >= ops[i].l && j <= ops[i].r) {
                    max_val_in_range = std::max(max_val_in_range, a[j] + current_delta_val);
                }
            }
            if (max_val_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for x and y to prevent overflow, as a_i can be up to 10^9
// and y can accumulate many such values. x can also become large.
// N is up to 2*10^5.
// Max y could be roughly N * 2 * max(a_i) = 2*10^5 * 2 * 10^9 = 4*10^14, fits in long long.
// Max x could be roughly N * max(a_i) = 2*10^5 * 10^9 = 2*10^14, fits in long long.

// Memoization table for results of (x, y) states.
// dp[x_val] stores a pair {final_x, final_y} if starting from (x_val, 0)
// and applying the operations, it terminates.
// If it enters a cycle, it stores {0, -1} (or some other indicator for cycle).
// If it goes out of bounds, it stores {final_x, final_y}.
// We need to store the *change* in y, not the absolute y, because the initial y varies.
// dp[x_val] = {delta_x, delta_y}
// delta_x is the change in x from x_val to the next x_val after one full step (step 2 then step 3).
// delta_y is the change in y from 0 to the y accumulated in one full step.
// This is not quite right. The problem is that the value a_x depends on x.
// The state is (current_x, current_y).
// We need to find the final y for each starting a_1.
// The sequence a_2, ..., a_n is fixed.
// For each i from 1 to n-1, we set a_1 = i.

// Let's define a function `solve(current_x)` that returns the pair {final_x, final_y_increment}
// if starting from `current_x` (and initial y=0 for this subproblem), it terminates.
// `final_y_increment` is the total y accumulated from `current_x` until termination.
// If it loops, it returns {0, -1} (or some other indicator).

// The actual values of a_i are stored in a vector `A`.
// A[0] is unused. A[1] corresponds to a_2, A[2] to a_3, ..., A[n-1] to a_n.
// So, a_k is A[k-1].
// When we set a_1 = i, we use `i` for a_1.
// The array `a` in the problem is 1-indexed.
// Let's use `a_vals` vector where `a_vals[k]` stores `a_{k+1}`.
// So `a_vals[0]` stores `a_2`, `a_vals[1]` stores `a_3`, ..., `a_vals[n-2]` stores `a_n`.
// When `x` is `k`, `a_x` is `a_vals[k-1]` if `k > 1`.
// If `x = 1`, `a_x` is the current `i` we are testing.

std::vector<long long> a_vals_fixed; // Stores a_2, a_3, ..., a_n
std::vector<long long> memo_y; // memo_y[x] stores the total y accumulated if starting from x and terminating.
                               // -1 indicates a cycle or not yet computed.
std::vector<long long> memo_x_final; // memo_x_final[x] stores the final x if starting from x and terminating.
                                     // 0 indicates a cycle or not yet computed.
std::vector<bool> visited; // visited[x] is true if we are currently exploring path from x.
int N_global;

// This function calculates the final y and final x if starting from `current_x`
// and `a_1_val` is used for `a_1`.
// It returns {final_x, total_y_increment}.
// If it detects a cycle, it returns {0, -1}.
std::pair<long long, long long> calculate_path(long long current_x, long long a_1_val) {
    // Check termination condition
    if (current_x <= 0 || current_x > N_global) {
        return {current_x, 0}; // Terminated, no further y increment
    }

    // Check memoization table
    // Note: memo_y and memo_x_final are for a fixed a_1_val.
    // Since a_1_val changes for each query, we need to clear/recompute for each query.
    // This means the DP approach needs to be specific to the current a_1_val.
    // However, the problem structure is that a_x is fixed for x > 1.
    // Only a_1 changes.
    // This suggests that if we land on x > 1, the path from there is always the same.
    // So, we can memoize results for x > 1.
    // For x = 1, we always start fresh.

    if (current_x > 1) {
        if (memo_y[current_x] != -1) { // Already computed for this x > 1
            return {memo_x_final[current_x], memo_y[current_x]};
        }
        if (visited[current_x]) { // Cycle detected
            return {0, -1};
        }
    }

    // Mark as visited to detect cycles
    if (current_x > 1) {
        visited[current_x] = true;
    }

    long long val_ax;
    if (current_x == 1) {
        val_ax = a_1_val;
    } else {
        val_ax = a_vals_fixed[current_x - 2]; // a_vals_fixed[0] is a_2, so a_vals_fixed[k-2] is a_k
    }

    // Step 2: x = x + a_x, y = y + a_x
    long long next_x_after_step2 = current_x + val_ax;
    long long y_increment_step2 = val_ax;

    // Step 3: x = x - a_x, y = y + a_x
    long long next_x_after_step3 = next_x_after_step2 - val_ax; // This is current_x
    long long y_increment_step3 = val_ax;

    // Total y increment for one full cycle (step 2 then step 3) is 2 * val_ax.
    // The x value after one full cycle is current_x.
    // This is incorrect based on the problem description.
    // "The program increases both x and y by a value equal to a_x simultaneously."
    // "The program now increases y by a_x while decreasing x by a_x."
    // This means the *new* x from step 2 is used for step 3.

    // Let's re-trace the operations:
    // Current state: (x_curr, y_curr)
    // 1. Check termination: if x_curr <= 0 or x_curr > N, terminate.
    // 2. Let `val = a_x_curr`.
    //    x_temp = x_curr + val
    //    y_temp = y_curr + val
    // 3. Let `val_prime = a_x_temp`. (This is the crucial part, a_x changes)
    //    x_next = x_temp - val_prime
    //    y_next = y_temp + val_prime
    // The problem states "The program now increases y by a_x while decreasing x by a_x."
    // This "a_x" refers to the *original* a_x from the start of the cycle, not a_x_temp.
    // This is a common ambiguity in competitive programming problems.
    // Let's re-read carefully: "The program increases both x and y by a value equal to a_x simultaneously."
    // "The program now increases y by a_x while decreasing x by a_x."
    // The phrasing "a_x" in the second sentence, without specifying "new a_x" or "a_x_temp",
    // usually implies it refers to the same `a_x` from the beginning of the current iteration.
    // If it meant `a_{x_temp}`, it would typically say `a_{x}` where `x` is the *current* value of `x`.
    // Let's assume `a_x` refers to the value `a_x_curr` throughout one (step 2, step 3) block.

    // So, if `val = a_x_curr`:
    // After step 2: x becomes `x_curr + val`, y becomes `y_curr + val`.
    // After step 3: x becomes `(x_curr + val) - val = x_curr`, y becomes `(y_curr + val) + val = y_curr + 2*val`.
    // This means x always returns to its original value, and y increases by 2*a_x_curr.
    // This would lead to an infinite loop if x never goes out of bounds.
    // This interpretation is what the sample explanation contradicts.

    // Sample 1: i = 1, a_1 = 1, a_2 = 2, a_3 = 4, a_4 = 1.
    // Start: x=1, y=0. a_x = a_1 = 1.
    // Step 2: x = 1+1=2, y = 0+1=1.
    // Step 3: x = 2-a_2 = 2-2=0, y = 1+a_2 = 1+2=3.
    // Terminate because x=0. Final y=3.
    // This implies that in step 3, `a_x` refers to `a_{x_temp}` (where `x_temp` is the value of x after step 2).
    // This is the standard interpretation for such problems.

    // Let's re-trace with the standard interpretation:
    // Current state: (x_curr, y_curr)
    // 1. Check termination: if x_curr <= 0 or x_curr > N, terminate.
    // 2. Let `val1 = a_x_curr`.
    //    x_after_step2 = x_curr + val1
    //    y_after_step2 = y_curr + val1
    // 3. Check termination: if x_after_step2 <= 0 or x_after_step2 > N, terminate.
    //    Let `val2 = a_x_after_step2`.
    //    x_next = x_after_step2 - val2
    //    y_next = y_after_step2 + val2
    // Then repeat with (x_next, y_next).

    // Calculate val1 = a_x_curr
    long long val1;
    if (current_x == 1) {
        val1 = a_1_val;
    } else {
        val1 = a_vals_fixed[current_x - 2];
    }

    // Simulate Step 2
    long long x_after_step2 = current_x + val1;
    long long y_increment_from_current_x = val1;

    // Check termination after Step 2
    if (x_after_step2 <= 0 || x_after_step2 > N_global) {
        if (current_x > 1) {
            visited[current_x] = false; // Backtrack visited status
            memo_x_final[current_x] = x_after_step2;
            memo_y[current_x] = y_increment_from_current_x;
        }
        return {x_after_step2, y_increment_from_current_x};
    }

    // Calculate val2 = a_x_after_step2
    long long val2;
    if (x_after_step2 == 1) {
        val2 = a_1_val;
    } else {
        val2 = a_vals_fixed[x_after_step2 - 2];
    }

    // Simulate Step 3
    long long next_x = x_after_step2 - val2;
    y_increment_from_current_x += val2;

    // Recursively call for the next state
    std::pair<long long, long long> result = calculate_path(next_x, a_1_val);

    // If a cycle was detected in the recursive call
    if (result.second == -1) {
        if (current_x > 1) {
            visited[current_x] = false; // Backtrack visited status
            memo_x_final[current_x] = 0; // Mark as cycle
            memo_y[current_x] = -1;
        }
        return {0, -1};
    }

    // If it terminated, add current y increment to the total
    long long final_y_increment = y_increment_from_current_x + result.second;
    long long final_x = result.first;

    // Memoize result for current_x if current_x > 1
    if (current_x > 1) {
        visited[current_x] = false; // Backtrack visited status
        memo_x_final[current_x] = final_x;
        memo_y[current_x] = final_y_increment;
    }

    return {final_x, final_y_increment};
}


int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;
    N_global = n;

    a_vals_fixed.resize(n - 1); // a_vals_fixed[0] is a_2, ..., a_vals_fixed[n-2] is a_n
    for (int k = 0; k < n - 1; ++k) {
        std::cin >> a_vals_fixed[k];
    }

    // Initialize memoization tables for x > 1.
    // Size N_global + 1 to use 1-based indexing for x.
    // memo_y[0] and memo_x_final[0] are unused.
    // memo_y[1] and memo_x_final[1] are unused because a_1 changes.
    // We only memoize for x from 2 to N_global.
    memo_y.assign(N_global + 1, -1); // -1 indicates not computed or cycle
    memo_x_final.assign(N_global + 1, 0); // 0 indicates not computed or cycle
    visited.assign(N_global + 1, false);

    // For each i from 1 to n-1, run the program with a_1 = i
    for (long long i = 1; i <= n - 1; ++i) {
        // Clear visited status for each new query.
        // This is only needed if we were to memoize for x=1, but we don't.
        // For x > 1, the memoization is valid across queries.
        // The `visited` array is only used to detect cycles *within* a single `calculate_path` call.
        // So it needs to be cleared for each top-level call to `calculate_path` if it starts from x > 1.
        // But here, the top-level call is always `calculate_path(1, i)`.
        // The `visited` array is correctly managed by setting/unsetting within the recursive calls.
        // No need to clear `memo_y` or `memo_x_final` for x > 1.

        std::pair<long long, long long> result = calculate_path(1, i);
        std::cout << result.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> treated_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        treated_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false;

        long long current_v_cry = children[i].v;
        long long total_d_cry_effect = 0; // Accumulates d_j cries from children leaving due to current_v_cry or previous d_j_cries

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated d_cry_effect from previous children leaving
            if (total_d_cry_effect > 0) {
                children[j].p -= total_d_cry_effect;
            }

            // Apply current_v_cry effect
            if (current_v_cry > 0) {
