    // Right part: a[n]...a[2n-1]
    // We are interested in sums of remaining jars: a[n+k_R]...a[2n-1]
    // This is equivalent to suffix sums of a[n]...a[2n-1].
    // Let diff_R[i] be the sum of a[i]...a[2n-1] (using 1/-1 values).
    // It's easier to compute prefix sums from right to left.
    // Let diff_R_prefix[i] be the sum of a[2n-1]...a[2n-1-i] (using 1/-1 values).
    // diff_R_prefix[0] = 0 (empty suffix)
    // diff_R_prefix[i] = sum of first i jars from the right (a[2n-1]...a[2n-i])
    std::map<int, int> right_diff_to_len; // Stores {diff_value: length_of_suffix}
    right_diff_to_len[0] = 0; // Empty suffix has diff 0, length 0
    int current_diff_R = 0;
    for (int i = 0; i < n; ++i) {
        current_diff_R += (a[2 * n - 1 - i] == 1 ? 1 : -1);
        if (right_diff_to_len.find(current_diff_R) == right_diff_to_len.end()) {
            right_diff_to_len[current_diff_R] = i + 1;
        }
    }

    // The total difference of all 2n jars
    int total_diff = 0;
    for (int x : a) {
        total_diff += (x == 1 ? 1 : -1);
    }

    // We want the remaining jars to have a total difference of 0.
    // Let the remaining left jars have diff L_rem and remaining right jars have diff R_rem.
    // We need L_rem + R_rem = 0, or L_rem = -R_rem.
    // The jars removed from the left are a[n-1]...a[n-k_L].
    // The jars removed from the right are a[n]...a[n+k_R-1].
    // The remaining jars are a[0]...a[n-1-k_L] and a[n+k_R]...a[2n-1].
    // The diff of a[0]...a[n-1-k_L] is current_diff_L for length (n-k_L).
    // The diff of a[n+k_R]...a[2n-1] is current_diff_R for length (n-k_R).
    // The total diff of remaining jars is (diff of a[0]...a[n-1-k_L]) + (diff of a[n+k_R]...a[2n-1]).
    // This is equivalent to:
    // (total_diff of all 2n jars) - (diff of removed jars).
    // Let diff_removed_L be the sum of a[n-1]...a[n-k_L].
    // Let diff_removed_R be the sum of a[n]...a[n+k_R-1].
    // We need total_diff - (diff_removed_L + diff_removed_R) = 0.
    // So, diff_removed_L + diff_removed_R = total_diff.

    // Let's re-evaluate.
    // The problem asks for minimum jars removed.
    // Let k_L jars be removed from the left (a[n-1], ..., a[n-k_L]).
    // Let k_R jars be removed from the right (a[n], ..., a[n+k_R-1]).
    // The remaining jars are a[0]...a[n-1-k_L] and a[n+k_R]...a[2n-1].
    // Let S_L_rem be the sum of a[0]...a[n-1-k_L]. This is `current_diff_L` for length `n-k_L`.
    // Let S_R_rem be the sum of a[n+k_R]...a[2n-1]. This is `current_diff_R` for length `n-k_R`.
    // We need S_L_rem + S_R_rem = 0.
    // This means S_L_rem = -S_R_rem.

    // Iterate through all possible numbers of jars removed from the left (k_L from 0 to n).
    // For each k_L, the remaining left jars are a[0]...a[n-1-k_L].
    // The sum of these remaining jars is `current_diff_L` for length `n-k_L`.
    // Let `target_diff_L` be this sum.
    // We need to find `target_diff_R` such that `target_diff_L + target_diff_R = 0`.
    // So, `target_diff_R = -target_diff_L`.
    // We look up `-target_diff_L` in `right_diff_to_len`.
    // If found, we have a valid configuration.
    // The number of jars remaining on the left is `n-k_L`.
    // The number of jars remaining on the right is `n-k_R`.
    // The total number of jars removed is `k_L + k_R`.
    // `k_L` is `n - (length of remaining left part)`.
    // `k_R` is `n - (length of remaining right part)`.

    // Let's use the maps directly.
    // `left_diff_to_len[d]` gives the length of the prefix `a[0]...a[len-1]` that sums to `d`.
    // `right_diff_to_len[d]` gives the length of the suffix `a[n]...a[n+len-1]` that sums to `d`.
    // No, `right_diff_to_len[d]` gives the length of the suffix `a[2n-len]...a[2n-1]` that sums to `d`.

    // Let's re-index for clarity.
    // Left jars: L_0, L_1, ..., L_{n-1} (original a[0]...a[n-1])
    // Right jars: R_0, R_1, ..., R_{n-1} (original a[n]...a[2n-1])
    // Karlsson is between L_{n-1} and R_0.

    // `left_diff_to_len[d]` stores the minimum `k_L_rem` such that `sum(L_0...L_{k_L_rem-1}) == d`.
    // `right_diff_to_len[d]` stores the minimum `k_R_rem` such that `sum(R_{n-k_R_rem}...R_{n-1}) == d`.

    // We need `sum(L_0...L_{k_L_rem-1}) + sum(R_{n-k_R_rem}...R_{n-1}) == 0`.
    // So, `d_L + d_R == 0`, or `d_R == -d_L`.
    // For each `d_L` in `left_diff_to_len`:
    //   Let `k_L_rem = left_diff_to_len[d_L]`.
    //   If `-d_L` is in `right_diff_to_len`:
    //     Let `k_R_rem = right_diff_to_len[-d_L]`.
    //     Number of jars removed = `(n - k_L_rem) + (n - k_R_rem)`.
    //     We want to minimize this.

    int min_removed = 2 * n; // Max possible jars removed

    // Case 1: No jars removed from the left.
    // The remaining left part has diff `current_diff_L` (which is `left_diff_to_len[current_diff_L]` for length `n`).
    // No, this is wrong. `current_diff_L` is the sum of all `n` left jars.
    // `left_diff_to_len` stores prefix sums.
    // `left_diff_to_len[d]` stores the length of the prefix `a[0]...a[len-1]` that sums to `d`.
    // `right_diff_to_len[d]` stores the length of the suffix `a[2n-len]...a[2n-1]` that sums to `d`.

    // Iterate through all possible `diff_L` values from `left_diff_to_len`.
    for (auto const& [diff_L, len_L] : left_diff_to_len) {
        int target_diff_R = -diff_L;
        if (right_diff_to_len.count(target_diff_R)) {
            int len_R = right_diff_to_len[target_diff_R];
            // len_L is the number of jars remaining on the left side (from a[0] to a[len_L-1])
            // len_R is the number of jars remaining on the right side (from a[2n-len_R] to a[2n-1])
            // Jars removed from left: n - len_L
            // Jars removed from right: n - len_R
            min_removed = std::min(min_removed, (n - len_L) + (n - len_R));
        }
    }

    std::cout << min_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

long long solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long count = 0;

    // Precompute positions of '1's
    std::vector<int> ones_pos;
    for (int i = 0; i < n; ++i) {
        if (s[i] == '1') {
            ones_pos.push_back(i);
        }
    }

    // Iterate through each '1' as a potential starting point for a good substring
    for (int i = 0; i < ones_pos.size(); ++i) {
        int l_idx = ones_pos[i]; // Current '1' is at index l_idx
        long long current_val = 0;

        // Iterate through possible ending points for substrings starting at l_idx
        // The maximum length of a substring is N.
        // The maximum value of a binary string of length L is 2^L - 1.
        // If value == length, then length <= N.
        // Max N is 2e5. 2^18 is 262144. So, max length of a good substring is around 18-19.
        // We can iterate up to a small constant number of characters after the '1'.
        // Let's say we iterate up to 20 characters after the '1'.
        // This covers all possible values up to 2^20 - 1, which is > 2e5.
        // So, if a substring is good, its length must be <= N.
        // If its length is L, its value is also L.
        // The maximum L is N.
        // The maximum value of a binary string of length L is 2^L - 1.
        // So, L <= 2^L - 1. This is true for L >= 1.
        // However, if L is large, say L=20, then 2^20 - 1 is much larger than 20.
        // The actual constraint is that the value must be equal to the length.
        // If the value is V, and length is L, then V=L.
        // The maximum possible value for L is N.
        // So, V <= N.
        // If the substring starts with '1', its value is at least 2^(L-1).
        // So, L = V >= 2^(L-1).
        // This inequality L >= 2^(L-1) holds only for small L.
        // For L=1, 1 >= 2^0 = 1 (True)
        // For L=2, 2 >= 2^1 = 2 (True)
        // For L=3, 3 >= 2^2 = 4 (False)
        // So, if a good substring starts with '1', its length can be at most 2.
        // This is incorrect. The value is $f(s_l \dots s_r)$, not $f(s_l \dots s_r)$ where $s_l$ is the MSB.
        // $f(011) = 3$, length 3. $3=3$. This is a good substring.
        // $f(00101) = 5$, length 5. $5=5$. This is a good substring.
        // The leading zeros are part of the length.
        // The value $f(s_l \dots s_r)$ is the decimal value of the binary string $s_l \dots s_r$.
        // The maximum length of $s$ is $2 \cdot 10^5$.
        // If $len = f(s_l \dots s_r)$, then $len \le 2 \cdot 10^5$.
        // The maximum value a binary string of length $k$ can represent is $2^k - 1$.
        // If $len = f(s_l \dots s_r)$, then $len$ must be representable by $s_l \dots s_r$.
        // The maximum length of a substring is $N$.
        // If $len = f(s_l \dots s_r)$, then $len \le N$.
        // The maximum value $f(s_l \dots s_r)$ can take is $2^{len}-1$.
        // So $len \le 2^{len}-1$. This is true for $len \ge 1$.
        // The actual constraint is that $f(s_l \dots s_r)$ must be equal to $len$.
        // The maximum value $f(s_l \dots s_r)$ can be is $N$.
        // What is the maximum $k$ such that $2^k-1 \le N$?
        // For $N=2 \cdot 10^5$, $2^{17} = 131072$, $2^{18} = 262144$.
        // So, if $f(s_l \dots s_r) = len$, then $len$ can be at most $N$.
        // If $len > 18$, then $f(s_l \dots s_r)$ would be at least $2^{len-1}$ (if $s_l \dots s_r$ has a '1' somewhere).
        // If $len > 18$, then $2^{len-1}$ is much larger than $len$.
        // For example, if $len=19$, $f(s_l \dots s_r)$ could be $19$.
        // But $f(s_l \dots s_r)$ is a binary number of length 19.
        // The smallest positive value for a binary string of length 19 is $f(0 \dots 01) = 1$.
        // The largest value is $f(1 \dots 1) = 2^{19}-1$.
        // The condition is $len = f(s_l \dots s_r)$.
        // If $len$ is large, say $len > 20$, then $f(s_l \dots s_r)$ would typically be much larger than $len$.
        // For example, if $len=20$, $f(s_l \dots s_r)$ could be $20$.
        // The smallest value for a binary string of length 20 that is not all zeros is 1.
        // The largest value is $2^{20}-1$.
        // The maximum value of $len$ is $N = 2 \cdot 10^5$.
        // The maximum $k$ such that $2^k-1 \le N$ is $k=17$.
        // So, if $f(s_l \dots s_r) = len$, then $len$ must be representable by a binary string.
        // If $len$ is large, say $len > 18$, then $f(s_l \dots s_r)$ would be at least $2^{len-1}$ if it starts with '1'.
        // If $len$ is large, say $len > 18$, then $f(s_l \dots s_r)$ would be at least $1$ if it contains a '1'.
        // The maximum value of $len$ is $N$.
        // The maximum value of $f(s_l \dots s_r)$ is $N$.
        // The maximum length of a binary string whose value is at most $N$ is about 18.
        // $2^{17} = 131072$, $2^{18} = 262144$.
        // So, if $f(s_l \dots s_r) = len$, then $len$ must be at most $N$.
        // And $len$ must be representable by a binary string of length $len$.
        // This means $len$ must be at most $2^{len}-1$.
        // This is always true for $len \ge 1$.
        // The key observation is that if $len$ is large, say $len > 18$, then $f(s_l \dots s_r)$ will be much larger than $len$ unless it consists of many leading zeros.
        // For example, if $len=20$, and $f(s_l \dots s_r)=20$. The binary representation of 20 is $10100$.
        // To have length 20, it must be $00000000000000010100$.
        // The number of leading zeros is $20 - \text{bit_length}(20) = 20 - 5 = 15$.
        // So, $s_l \dots s_r$ must be $0 \dots 010100$.
        // The number of leading zeros is $l_z = len - \text{bit_length}(len)$.
        // The actual starting index of the '1' that contributes to the value is $l_idx$.
        // The substring is $s[l \dots r]$. Its length is $len = r - l + 1$.
        // The value is $f(s[l \dots r])$.
        // We are iterating $l_idx$ as the position of the first '1' in the substring $s[l \dots r]$ that contributes to its value.
        // This means $s[l \dots l_idx-1]$ are all '0's.
        // The number of leading zeros is $l_idx - l$.
        // The value $f(s[l \dots r])$ is $f(s[l_idx \dots r])$.
        // So, we need $r - l + 1 = f(s[l_idx \dots r])$.
        // Let $k = r - l_idx + 1$ be the length of $s[l_idx \dots r]$.
        // Let $val = f(s[l_idx \dots r])$.
        // Then $r - l + 1 = (l_idx - l) + (r - l_idx + 1) = (l_idx - l) + k$.
        // So we need $(l_idx - l) + k = val$.
        // This means $l_idx - l = val - k$.
        // Since $l_idx - l \ge 0$, we must have $val - k \ge 0$.
        // Also, $l_idx - l$ is the number of leading zeros.
        // The maximum value of $val$ is $N$.
        // The maximum length $k$ is $N$.
        // The maximum $val$ is $N = 2 \cdot 10^5$.
        // The maximum $k$ for which $val$ can be $N$ is $18$ (since $2^{18} > N$).
        // So, $k$ can be at most $18$.
        // This means we only need to check substrings $s[l_idx \dots r]$ where $r - l_idx + 1 \le 18$.
        // This is a small constant. Let's use 20 for safety.
        for (int r_idx = l_idx; r_idx < std::min(n, l_idx + 20); ++r_idx) {
            current_val = current_val * 2 + (s[r_idx] - '0');
            int k = r_idx - l_idx + 1; // Length of s[l_idx ... r_idx]

            // If current_val exceeds N, it cannot be a good substring length.
            // Also, if current_val is 0, it cannot be a good substring length (length must be >= 1).
            if (current_val == 0) continue;
            if (current_val > n) break; // Optimization: further values will also be too large

            // We need to find 'l' such that s[l...l_idx-1] are all '0's
            // and (l_idx - l) + k = current_val
            // This means l_idx - l = current_val - k
            // Let num_leading_zeros = current_val - k
            long long num_leading_zeros = current_val - k;

            if (num_leading_zeros < 0) continue; // Not enough leading zeros possible

            // Calculate the required starting index 'l'
            int l = l_idx - num_leading_zeros;

            // Check if 'l' is a valid index and if s[l...l_idx-1] are all '0's
            if (l >= 0 && l <= l_idx) { // l <= l_idx is always true if num_leading_zeros >= 0
                // All characters from s[l] to s[l_idx-1] must be '0'.
                // This is implicitly handled by the 'ones_pos' array.
                // The number of zeros before l_idx is l_idx - (previous '1' position + 1).
                int prev_one_pos = (i == 0) ? -1 : ones_pos[i-1];
                if (l > prev_one_pos) { // This means s[l...l_idx-1] are all '0's
                    count++;
                }
            }
        }
    }

    // Handle substrings consisting only of '0's.
    // For these, f(0...0) = 0.
    // The length must be 0. But length must be >= 1.
    // So, no substring of all '0's can be good.
    // Example: f(000) = 0. Length is 3. 3 != 0.
    // Example: f(0) = 0. Length is 1. 1 != 0.
    // So, we don't need to handle all-zero substrings separately.
    // The current logic correctly handles this because current_val will be 0, and we skip it.

    return count;
}

