#include <iostream>
#include <string>
#include <numeric>
#include <algorithm>

int count_ones(const std::string& s) {
    int count = 0;
    for (char c : s) {
        if (c == '1') {
            count++;
        }
    }
    return count;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string a, b;
    std::cin >> a >> b;

    int ones_in_a = count_ones(a);
    int ones_in_b = count_ones(b);

    // If ones_in_a is odd, we can add a '1' to a.
    // If ones_in_a is even, we can add a '0' to a.
    // This means we can always increase the number of ones by 1 if it's odd,
    // or keep it the same if it's even.
    // Effectively, we can always reach a state with `ones_in_a + 1` ones if `ones_in_a` is odd.
    // If `ones_in_a` is even, we can reach a state with `ones_in_a` ones.
    // So, the maximum number of ones we can achieve in a string of length L is:
    // if initial ones_in_a is even: ones_in_a + (L - |a|) / 2
    // if initial ones_in_a is odd: ones_in_a + 1 + (L - |a| - 1) / 2 (if L - |a| >= 1)
    // A simpler way: if ones_in_a is odd, we can always make it even by adding a '1'.
    // If ones_in_a is even, we can always make it odd by adding a '1' (if we add '1' to an odd string).
    // The key is that we can always increase the number of ones by 1 if the current count is odd,
    // or keep it the same if it's even.
    // This means if we have `k` ones, we can make it `k` or `k+1` (if we append '1').
    // The maximum number of ones we can achieve in a string of length `|b|` or more,
    // starting from `a`, is `ones_in_a` if `ones_in_a` is even, or `ones_in_a + 1` if `ones_in_a` is odd.
    // This is because if `ones_in_a` is odd, we can append a '1', making the count `ones_in_a + 1` (even).
    // If `ones_in_a` is even, we can append a '0', keeping the count `ones_in_a` (even).
    // After this, the parity of the string will be 0.
    // Any subsequent appends will be '0's until the count of '1's becomes odd again.
    // So, the maximum number of '1's we can have in a string of length `|b|` or more,
    // that is derived from `a`, is `ones_in_a` if `ones_in_a` is even, or `ones_in_a + 1` if `ones_in_a` is odd.
    // Let's call this `max_possible_ones_in_a_prefix`.

    int max_ones_a_can_have = ones_in_a;
    if (ones_in_a % 2 != 0) { // If initial '1's count is odd
        max_ones_a_can_have++; // We can append a '1', making it even
    }
    // Now, max_ones_a_can_have is the maximum number of '1's we can have in a string
    // that is at least as long as 'a' and has an even number of '1's.
    // Any further appends will be '0's until the count of '1's becomes odd again.
    // But we only care if we can match 'b's '1's count.
    // The length of 'a' can be extended to `|a| + k`.
    // The number of ones in `a` can be at most `max_ones_a_can_have`.
    // If `ones_in_b` is greater than `max_ones_a_can_have`, it's impossible.
    // Otherwise, it's possible if `max_ones_a_can_have >= ones_in_b`.

    if (max_ones_a_can_have >= ones_in_b) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}
